def alert_quality_minutes_out_of_sync(left: float | None, right: float | None) -> bool:
    if left is None or right is None:
        return False
    return abs(float(left) - float(right)) >= DEFAULT_ALERT_QUALITY_SYNC_MINUTE_TOLERANCE


