def validate_dual_chart_crosshair_probe_report(
    path: str | Path,
    *,
    max_age_minutes: float = 1440.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    target = Path(path)
    payload, load_state = read_json_object_report(target)
    if not load_state.get("exists"):
        return check(
            "dual_chart_crosshair_probe",
            "INFO",
            "Sonda del cursor dual aun no ejecutada.",
            path=str(target),
            probe_status="NO_DATA",
        )
    if load_state.get("malformed"):
        return check(
            "dual_chart_crosshair_probe",
            "WARN",
            f"Sonda del cursor dual invalida: {load_state.get('detail')}",
            path=str(target),
            probe_status="ERROR",
        )
    current = now or utc_now()
    generated = parse_utc_datetime(payload.get("generated_at"))
    age_minutes = ((current - generated).total_seconds() / 60.0) if generated else None
    probe_status = str(payload.get("status") or "NO_DATA").upper()
    if age_minutes is None or age_minutes > max_age_minutes:
        return check(
            "dual_chart_crosshair_probe",
            "INFO",
            f"Sonda del cursor dual sin evidencia vigente ({age_minutes:.1f}m)." if age_minutes is not None else "Sonda del cursor dual sin fecha valida.",
            path=str(target),
            probe_status="STALE",
            age_minutes=age_minutes,
            max_age_minutes=max_age_minutes,
        )
    status = "OK" if probe_status == "OK" and bool(payload.get("ok")) else "FAIL"
    return check(
        "dual_chart_crosshair_probe",
        status,
        str(payload.get("detail") or "Sonda del cursor dual sin detalle."),
        path=str(target),
        probe_status=probe_status,
        age_minutes=age_minutes,
        max_age_minutes=max_age_minutes,
        states=payload.get("states") if isinstance(payload.get("states"), list) else [],
        console_error_count=len(payload.get("console_errors") or []),
    )


def heartbeat_artifact_path(heartbeat: dict[str, Any], key: str) -> Path | None:
    value = heartbeat.get(key)
    if not value:
        return None
    path = Path(str(value))
    return path if path.exists() else None


def check(name: str, status: str, detail: str, **extra: Any) -> dict[str, Any]:
    return {"name": name, "status": status, "detail": detail, **extra}


def overall_status(checks: list[dict[str, Any]]) -> str:
    statuses = set()
    historical_fail = False
    for item in checks:
        status = str(item.get("status") or "").upper()
        if str(item.get("name") or "") == "health_stability_slo" and status == "FAIL":
            historical_fail = True
            continue
        statuses.add(status)
    if "FAIL" in statuses:
        return "FAIL"
    if "WARN" in statuses or historical_fail:
        return "WARN"
    return "OK"


def pid_is_running(pid: Any) -> bool:
    try:
        pid_int = int(pid)
    except (TypeError, ValueError):
        return False
    if pid_int <= 0:
        return False
    try:
        os.kill(pid_int, 0)
    except OSError:
        return False
    return True


def live_backend_command_role(command: str) -> str | None:
    normalized = " ".join(str(command or "").split())
    if not normalized:
        return None
    try:
        executable = Path(shlex.split(normalized)[0]).name
    except ValueError:
        executable = normalized.split()[0]
    if executable in {"rg", "grep", "egrep", "fgrep"}:
        return None
    for role, markers in LIVE_BACKEND_PROCESS_ROLES.items():
        if any(marker in normalized for marker in markers):
            return role
    return None


def parse_ps_process_line(raw_line: str) -> dict[str, Any] | None:
    line = str(raw_line or "").strip()
    if not line:
        return None
    match = re.match(r"^(?P<pid>\d+)\s+(?P<rest>.+)$", line)
    if not match:
        return None
    rest = match.group("rest").strip()
    ppid: int | None = None
    command = rest
    ppid_match = re.match(r"^(?P<ppid>\d+)\s+(?P<command>.+)$", rest)
    if ppid_match:
        ppid = int(ppid_match.group("ppid"))
        command = ppid_match.group("command")
    return {"pid": int(match.group("pid")), "ppid": ppid, "command": command}


def live_backend_processes_from_ps_lines(lines: list[str]) -> dict[str, Any]:
    counts = {role: 0 for role in LIVE_BACKEND_PROCESS_ROLES}
    processes: list[dict[str, Any]] = []
    raw_processes: list[dict[str, Any]] = []
    for raw_line in lines:
        parsed = parse_ps_process_line(raw_line)
        if parsed:
            raw_processes.append(parsed)
    process_by_pid = {int(item["pid"]): item for item in raw_processes}
    supervised_processes: list[dict[str, Any]] = []
    for parsed in raw_processes:
        command = parsed["command"]
        role = live_backend_command_role(command)
        if role is None:
            continue
        pid = int(parsed["pid"])
        ppid = parsed.get("ppid")
        parent = process_by_pid.get(int(ppid)) if ppid is not None else None
        parent_command = str((parent or {}).get("command") or "")
        if role == "ma_scan" and any(
            marker in parent_command for marker in LIVE_BACKEND_SUPERVISED_SCAN_PARENT_MARKERS
        ):
            supervised_processes.append({"pid": pid, "ppid": ppid, "role": role, "command": command})
            continue
        counts[role] += 1
        process = {"pid": pid, "role": role, "command": command}
        if ppid is not None:
            process["ppid"] = ppid
        processes.append(process)
    duplicate_roles = sorted(
        role for role, count in counts.items() if count > int(LIVE_BACKEND_MAX_PROCESS_COUNTS.get(role, 1))
    )
    duplicate_count = sum(max(0, counts[role] - int(LIVE_BACKEND_MAX_PROCESS_COUNTS.get(role, 1))) for role in counts)
    return {
        "counts": counts,
        "processes": processes,
        "supervised_processes": supervised_processes,
        "supervised_process_count": len(supervised_processes),
        "duplicate_roles": duplicate_roles,
        "duplicate_count": duplicate_count,
    }


def validate_live_backend_process_guard() -> dict[str, Any]:
    try:
        result = subprocess.run(
            ["ps", "axo", "pid=,ppid=,command="],
            text=True,
            capture_output=True,
            timeout=5,
            check=False,
        )
    except Exception as exc:
        return check("live_backend_process_guard", "WARN", f"Could not inspect live backend processes: {exc}")
    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "ps command failed").strip()
        return check(
            "live_backend_process_guard",
            "WARN",
            f"Could not inspect live backend processes: {detail[:300]}",
            returncode=result.returncode,
        )

    summary = live_backend_processes_from_ps_lines(result.stdout.splitlines())
    counts = summary["counts"]
    duplicate_roles = summary["duplicate_roles"]
    if duplicate_roles:
        status = "FAIL"
        detail = "Duplicate live backend processes: " + ", ".join(f"{role}={counts[role]}" for role in duplicate_roles)
    else:
        status = "OK"
        active = ", ".join(f"{role}={count}" for role, count in counts.items() if count)
        detail = f"No duplicate live backend processes detected ({active or 'none active'})"
        supervised_count = int(summary.get("supervised_process_count") or 0)
        if supervised_count:
            detail += f"; supervised daily scan={supervised_count}"
    return check(
        "live_backend_process_guard",
        status,
        detail,
        counts=counts,
        duplicate_roles=duplicate_roles,
        duplicate_count=summary["duplicate_count"],
        process_count=len(summary["processes"]),
        processes=summary["processes"],
        supervised_process_count=summary.get("supervised_process_count", 0),
        supervised_processes=summary.get("supervised_processes", []),
    )


def detect_video_ingest_staging_activity(staging_path: str | Path) -> dict[str, Any]:
    path = str(Path(staging_path).resolve(strict=False))
    try:
        result = subprocess.run(
            ["ps", "axo", "pid=,command="],
            text=True,
            capture_output=True,
            timeout=5,
            check=False,
        )
    except Exception as exc:
        return {"active": False, "process_count": 0, "error": f"{type(exc).__name__}: {exc}"}
    if result.returncode != 0:
        detail = (result.stderr or result.stdout or "ps command failed").strip()
        return {"active": False, "process_count": 0, "error": detail[:300]}

    processes: list[dict[str, Any]] = []
    for raw_line in result.stdout.splitlines():
        parsed = parse_ps_process_line(raw_line)
        if not parsed:
            continue
        command = str(parsed.get("command") or "")
        if path not in command:
            continue
        if "tools/video_learning_ingest.py" not in command and "ffmpeg" not in command:
            continue
        processes.append(
            {
                "pid": parsed.get("pid"),
                "role": "video_learning_ingest" if "tools/video_learning_ingest.py" in command else "ffmpeg",
            }
        )
    return {"active": bool(processes), "process_count": len(processes), "processes": processes[:5]}


def freshness_check(
    name: str, path: Path | None, *, max_age_minutes: float, now: datetime | None = None
) -> dict[str, Any]:
    if path is None:
        return check(name, "FAIL", "File not found", max_age_minutes=float(max_age_minutes))
    age_state = file_age_state(path, now=now)
    age = float(age_state["age_minutes"])
    modified_future_minutes = float(age_state["modified_future_minutes"])
    if modified_future_minutes > float(max_age_minutes):
        status = "FAIL"
    elif modified_future_minutes > 5.0:
        status = "WARN"
    elif age <= max_age_minutes:
        status = "OK"
    elif age <= max_age_minutes * 3:
        status = "WARN"
    else:
        status = "FAIL"
    detail = f"{path} age {age:.0f} min"
    if modified_future_minutes > 5.0:
        detail += f", modified future {modified_future_minutes:.1f}m"
    return check(
        name,
        status,
        detail,
        path=str(path),
        modified_at=age_state["modified_at"],
        age_minutes=age,
        modified_future_minutes=round(modified_future_minutes, 1),
        max_age_minutes=float(max_age_minutes),
    )


def heartbeat_check(
    heartbeat_path: Path,
    heartbeat: dict[str, Any],
    *,
    now: datetime | None = None,
    running_warn_minutes: float = 15.0,
    running_fail_minutes: float = 30.0,
    success_warn_seconds: float = 600.0,
    success_fail_seconds: float = 900.0,
) -> tuple[dict[str, Any], str]:
    if not heartbeat:
        return check("heartbeat", "WARN", "Heartbeat not found", path=str(heartbeat_path)), ""

    hb_status = str(heartbeat.get("status") or "").upper()
    if hb_status == "SUCCESS":
        raw_duration = heartbeat.get("duration_seconds")
        try:
            duration_seconds = float(raw_duration)
        except (TypeError, ValueError):
            duration_seconds = None
        duration_state = "unknown"
        if duration_seconds is None:
            status = "OK"
            detail = f"Last live run succeeded in {raw_duration or '-'}s"
        elif duration_seconds >= success_fail_seconds:
            status = "FAIL"
            detail = f"Last live run succeeded but took {duration_seconds:.1f}s; realtime scan too slow"
            duration_state = "too_slow"
        elif duration_seconds >= success_warn_seconds:
            status = "WARN"
            detail = f"Last live run succeeded but took {duration_seconds:.1f}s"
            duration_state = "slow"
        else:
            status = "OK"
            detail = f"Last live run succeeded in {duration_seconds:.1f}s"
            duration_state = "normal"
        return (
            check(
                "heartbeat",
                status,
                detail,
                path=str(heartbeat_path),
                duration_seconds=duration_seconds,
                duration_state=duration_state,
                slow_success=duration_state == "slow",
                success_warn_seconds=success_warn_seconds,
                success_fail_seconds=success_fail_seconds,
            ),
            hb_status,
        )
    if hb_status == "RUNNING":
        current = now or utc_now()
        if current.tzinfo is None:
            current = current.replace(tzinfo=timezone.utc)
        started_at = parse_utc_datetime(heartbeat.get("started_at"))
        if started_at is None:
            return (
                check("heartbeat", "WARN", "Live backend is running; started_at missing", path=str(heartbeat_path)),
                hb_status,
            )
        started_at_future_minutes = max(0.0, (started_at - current).total_seconds() / 60.0)
        running_minutes = max(0.0, (current - started_at).total_seconds() / 60.0)
        if started_at_future_minutes >= running_fail_minutes:
            status = "FAIL"
            detail = f"Live backend started_at future {started_at_future_minutes:.1f}m; heartbeat clock invalid"
            running_state = "future_started"
        elif started_at_future_minutes > 5.0:
            status = "WARN"
            detail = f"Live backend started_at future {started_at_future_minutes:.1f}m"
            running_state = "future_started"
        elif running_minutes >= running_fail_minutes:
            status = "FAIL"
            detail = f"Live backend running for {running_minutes:.0f} min; likely stuck"
            running_state = "stuck"
        elif running_minutes >= running_warn_minutes:
            status = "WARN"
            detail = f"Live backend running for {running_minutes:.0f} min"
            running_state = "long_running"
        else:
            status = "OK"
            detail = f"Live backend running normally for {running_minutes:.0f} min"
            running_state = "normal"
        return (
            check(
                "heartbeat",
                status,
                detail,
                path=str(heartbeat_path),
                running_minutes=running_minutes,
                started_at_future_minutes=round(started_at_future_minutes, 1),
                running_state=running_state,
                running_warn_minutes=running_warn_minutes,
                running_fail_minutes=running_fail_minutes,
            ),
            hb_status,
        )

    return (
        check(
            "heartbeat",
            "FAIL",
            str(heartbeat.get("error") or hb_status or "Live backend failed"),
            path=str(heartbeat_path),
        ),
        hb_status,
    )


def validate_live_scan_efficiency_report(
    report_path: str | Path,
    *,
    max_age_minutes: float = 15.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    path = Path(report_path)
    payload, load_state = read_json_object_report(path)
    if not load_state.get("exists"):
        return check("live_scan_efficiency", "WARN", "Live scan timing report missing", path=str(path))
    if load_state.get("malformed"):
        return check(
            "live_scan_efficiency",
            "FAIL",
            f"Live scan timing report malformed: {load_state.get('detail')}",
            path=str(path),
        )
    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check("live_scan_efficiency", "FAIL", "Live scan timing generated_at invalid", path=str(path))
    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    age_minutes = max(0.0, (current - generated_at).total_seconds() / 60.0)
    report_status = str(payload.get("status") or "UNKNOWN").upper()
    timeframes = [str(value).strip().lower() for value in payload.get("crypto_timeframes", [])]
    derived = [value for value in timeframes if value in {"2h", "4h"}]
    optimization = (
        payload.get("crypto_fetch_optimization")
        if isinstance(payload.get("crypto_fetch_optimization"), dict)
        else {}
    )
    enabled = bool(optimization.get("enabled"))
    saved_requests = int(optimization.get("saved_request_count") or 0)
    base_requests = int(optimization.get("base_request_count") or 0)
    steps = [row for row in payload.get("steps", []) if isinstance(row, dict)]
    step_modes = {str(row.get("timeframe") or "").lower(): str(row.get("fetch_mode") or "") for row in steps}
    issues: list[str] = []
    status = "OK"
    if age_minutes > max_age_minutes:
        status = "FAIL"
        issues.append(f"stale {age_minutes:.1f}m")
    if report_status not in {"SUCCESS", "RUNNING"}:
        status = "FAIL"
        issues.append(f"status {report_status}")
    if derived:
        if not enabled or saved_requests <= 0 or base_requests <= 0:
            status = "WARN" if status == "OK" else status
            issues.append("derived crypto reuse missing")
        missing_modes = [value for value in derived if step_modes.get(value) != "DERIVED_FROM_1H"]
        if report_status == "SUCCESS" and missing_modes:
            status = "WARN" if status == "OK" else status
            issues.append("direct derived timeframe " + ",".join(missing_modes))
    detail = (
        f"Live scan efficiency {report_status}, age {age_minutes:.1f}m, crypto frames "
        f"{','.join(timeframes) or '-'}, saved {saved_requests} provider request(s)/cycle, base {base_requests}"
    )
    if issues:
        detail += "; " + "; ".join(issues)
    return check(
        "live_scan_efficiency",
        status,
        detail,
        path=str(path),
        report_status=report_status,
        age_minutes=round(age_minutes, 1),
        crypto_timeframes=timeframes,
        derived_timeframes=derived,
        optimization_enabled=enabled,
        saved_request_count=saved_requests,
        base_request_count=base_requests,
        step_fetch_modes=step_modes,
    )


def normalize_tf(value: Any) -> str:
    return str(value or "").strip().lower()


def app_url_exception_is_timeout(exc: Exception) -> bool:
    text = str(exc).lower()
    return isinstance(exc, TimeoutError) or "timed out" in text or "timeout" in text


def app_url_status_code(url: str, *, timeout: float) -> tuple[int | None, Exception | None]:
    try:
        req = Request(url, method="HEAD")
        with urlopen(req, timeout=timeout) as response:
            return int(getattr(response, "status", 0) or 0), None
    except Exception:
        try:
            with urlopen(url, timeout=timeout) as response:
                return int(getattr(response, "status", 0) or 0), None
        except Exception as exc:
            return None, exc


def validate_app_url(
    url: str,
    *,
    timeout: float = 5.0,
    timeout_retry_seconds: float = 8.0,
    timeout_retry_delay_seconds: float = 1.0,
    log_paths: list[Path] | None = None,
    max_log_age_minutes: float = DEFAULT_OPERATIONAL_LOG_MAX_AGE_MINUTES,
    now: datetime | None = None,
) -> dict[str, Any]:
    if not url:
        return check("streamlit_app", "WARN", "App URL not provided")
    probe_attempts = 1
    status_code, probe_error = app_url_status_code(url, timeout=timeout)
    retried_after_timeout = False
    if probe_error is not None and app_url_exception_is_timeout(probe_error) and timeout_retry_seconds > 0:
        retried_after_timeout = True
        if timeout_retry_delay_seconds > 0:
            time.sleep(float(timeout_retry_delay_seconds))
        probe_attempts += 1
        status_code, probe_error = app_url_status_code(url, timeout=timeout_retry_seconds)
    if probe_error is not None:
        if isinstance(probe_error, URLError):
            return check(
                "streamlit_app",
                "FAIL",
                f"App not reachable: {probe_error}",
                url=url,
                probe_attempts=probe_attempts,
                retried_after_timeout=retried_after_timeout,
            )
        return check(
            "streamlit_app",
            "FAIL",
            f"App check failed: {probe_error}",
            url=url,
            probe_attempts=probe_attempts,
            retried_after_timeout=retried_after_timeout,
        )
    status = "OK" if 200 <= status_code < 400 else "FAIL"
    if status != "OK":
        return check(
            "streamlit_app",
            status,
            f"HTTP {status_code}",
            url=url,
            status_code=status_code,
            probe_attempts=probe_attempts,
            retried_after_timeout=retried_after_timeout,
        )

    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    recent_critical: list[dict[str, Any]] = []
    recent_logs = 0
    timestamp_filtered_logs = 0
    for path in log_paths if log_paths is not None else default_streamlit_log_paths():
        if not path.exists():
            continue
        try:
            modified = datetime.fromtimestamp(path.stat().st_mtime, timezone.utc)
        except OSError:
            continue
        age_minutes = max(0.0, (current - modified).total_seconds() / 60.0)
        if age_minutes > max_log_age_minutes:
            continue
        recent_logs += 1
        log_tail = read_log_tail(path)
        filtered_tail, timestamp_filtered = recent_log_text(
            log_tail,
            now=current,
            max_age_minutes=max_log_age_minutes,
        )
        if timestamp_filtered:
            timestamp_filtered_logs += 1
        critical, _, _ = operational_log_signals(filtered_tail)
        for line in critical:
            recent_critical.append({"path": str(path), "line": line, "age_minutes": age_minutes})
    if recent_critical:
        first = recent_critical[0]
        return check(
            "streamlit_app",
            "FAIL",
            f"HTTP {status_code}, recent Streamlit log critical: {first['line']}",
            url=url,
            status_code=status_code,
            probe_attempts=probe_attempts,
            retried_after_timeout=retried_after_timeout,
            recent_log_count=recent_logs,
            timestamp_filtered_log_count=timestamp_filtered_logs,
            recent_critical=recent_critical[:10],
        )

    return check(
        "streamlit_app",
        status,
        f"HTTP {status_code}",
        url=url,
        status_code=status_code,
        probe_attempts=probe_attempts,
        retried_after_timeout=retried_after_timeout,
        recent_log_count=recent_logs,
        timestamp_filtered_log_count=timestamp_filtered_logs,
    )


def validate_chart(symbol: str, market: str, timeframe: str) -> dict[str, Any]:
    if not symbol:
        return check("chart_indicators", "WARN", "No symbol available for chart check")
    try:
        from symbol_detail import fetch_symbol_history, prepare_symbol_chart_data

        history = fetch_symbol_history(symbol, market=market, timeframe=timeframe)
        chart_df = prepare_symbol_chart_data(history)
    except Exception as exc:
        return check("chart_indicators", "FAIL", f"Chart data failed for {symbol}: {exc}", symbol=symbol)
    if chart_df.empty:
        return check("chart_indicators", "FAIL", f"No chart rows for {symbol}", symbol=symbol)
    has_rsi = "rsi14" in chart_df.columns and chart_df["rsi14"].notna().any()
    has_macd = "macd_hist" in chart_df.columns and chart_df["macd_hist"].notna().any()
    status = "OK" if len(chart_df) >= 40 and has_rsi and has_macd else "FAIL"
    detail = f"{symbol} {timeframe}: rows={len(chart_df)}, RSI={has_rsi}, MACD={has_macd}"
    return check(
        "chart_indicators",
        status,
        detail,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        rows=len(chart_df),
        has_rsi=has_rsi,
        has_macd=has_macd,
    )


def validate_chart_provider_effective(
    symbol: str,
    market: str,
    timeframe: str,
    *,
    env: dict[str, str] | None = None,
) -> dict[str, Any]:
    if not symbol:
        return check("chart_provider_effective", "WARN", "No symbol available for provider/source check")
    try:
        from symbol_detail import fetch_symbol_history_with_source

        if env is None:
            _history, source = fetch_symbol_history_with_source(symbol, market=market, timeframe=timeframe)
        else:
            _history, source = fetch_symbol_history_with_source(symbol, market=market, timeframe=timeframe, env=env)
    except Exception as exc:
        return check(
            "chart_provider_effective",
            "WARN",
            f"Could not inspect effective chart provider for {symbol}: {exc}",
            symbol=symbol,
            market=market,
            timeframe=timeframe,
        )

    source = source if isinstance(source, dict) else {}
    provider = str(source.get("provider") or "-")
    source_name = str(source.get("source") or "-")
    source_mode = str(source.get("mode") or "-")
    fallback_reason = str(source.get("fallback_reason") or "-")
    fallback_detail = str(source.get("fallback_detail") or "")
    fallback_action = str(source.get("fallback_action") or "")
    polygon_fallback_reason = str(source.get("polygon_fallback_reason") or "-")
    polygon_fallback_detail = str(source.get("polygon_fallback_detail") or "")
    polygon_fallback_action = str(source.get("polygon_fallback_action") or "")
    is_fallback = bool(source.get("fallback")) or source_mode.upper() == "FALLBACK"
    premium_recovery_action = fallback_action
    if is_fallback and fallback_reason in {"alpaca_auth", "alpaca_feed_permission"}:
        if polygon_fallback_reason == "polygon_not_configured":
            premium_recovery_action = "Configurar POLYGON_API_KEY/POLYGON_API_TOKEN o corregir credenciales Alpaca para recuperar velas premium."
        elif polygon_fallback_reason not in {"", "-"}:
            premium_recovery_action = polygon_fallback_action or fallback_action
    market_value = str(market or "stock").lower()
    if market_value == "crypto":
        status = "OK" if source_mode.upper() == "EXCHANGE_API" else "WARN"
        detail = f"{symbol} {timeframe}: {provider}/{source_name} {source_mode}"
    elif is_fallback and fallback_reason in {"alpaca_auth", "alpaca_feed_permission"}:
        status = "WARN"
        detail = (
            f"{symbol} {timeframe}: premium provider fallback {fallback_reason}; {fallback_detail or fallback_action}"
        )
        if polygon_fallback_reason not in {"", "-"}:
            detail += f"; alternate {polygon_fallback_reason}"
    elif is_fallback and fallback_reason not in {"", "-", "alpaca_not_configured", "unsupported_timeframe"}:
        status = "WARN"
        detail = f"{symbol} {timeframe}: chart fallback {fallback_reason}; {fallback_detail or fallback_action}"
        if polygon_fallback_reason not in {"", "-"}:
            detail += f"; alternate {polygon_fallback_reason}"
    elif is_fallback:
        status = "INFO"
        detail = f"{symbol} {timeframe}: fallback {provider}/{source_name}; {fallback_reason}"
        if polygon_fallback_reason not in {"", "-"}:
            detail += f"; alternate {polygon_fallback_reason}"
    else:
        status = "OK"
        detail = f"{symbol} {timeframe}: provider {provider}/{source_name} {source_mode}"
    return check(
        "chart_provider_effective",
        status,
        detail,
        symbol=symbol,
        market=market,
        timeframe=timeframe,
        provider=provider,
        source=source_name,
        source_mode=source_mode,
        fallback=is_fallback,
        fallback_reason=fallback_reason,
        fallback_detail=fallback_detail,
        fallback_action=fallback_action,
        polygon_fallback_reason=polygon_fallback_reason,
        polygon_fallback_detail=polygon_fallback_detail,
        polygon_fallback_action=polygon_fallback_action,
        premium_recovery_action=premium_recovery_action,
    )


def validate_chart_providers_effective(
    targets: list[tuple[str, str]],
    *,
    timeframe: str,
    limit: int = 6,
    env: dict[str, str] | None = None,
) -> dict[str, Any]:
    deduped: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for symbol, market in targets or []:
        clean_symbol = str(symbol or "").strip().upper()
        if not clean_symbol:
            continue
        clean_market = str(market or ("crypto" if "/" in clean_symbol else "stock")).strip().lower()
        key = (clean_symbol, clean_market)
        if key in seen:
            continue
        seen.add(key)
        deduped.append(key)
        if len(deduped) >= max(1, int(limit)):
            break
    if not deduped:
        return check("chart_provider_effective", "WARN", "No active symbols available for provider/source check")

    results = [validate_chart_provider_effective(symbol, market, timeframe, env=env) for symbol, market in deduped]
    status = status_max(*(str(item.get("status") or "OK") for item in results))
    issue = next((item for item in results if str(item.get("status") or "") in {"FAIL", "WARN"}), {})
    fallback_count = sum(1 for item in results if bool(item.get("fallback")))
    auth_fallback_count = sum(
        1 for item in results if str(item.get("fallback_reason") or "") in {"alpaca_auth", "alpaca_feed_permission"}
    )
    polygon_missing_count = sum(
        1 for item in results if str(item.get("polygon_fallback_reason") or "") == "polygon_not_configured"
    )
    market_issue_counts = dict(
        Counter(
            str(item.get("market") or "unknown").lower()
            for item in results
            if str(item.get("status") or "").upper() in {"WARN", "FAIL"}
        )
    )
    market_checked_counts = dict(Counter(str(item.get("market") or "unknown").lower() for item in results))
    stock_issue_count = int(market_issue_counts.get("stock") or 0)
    crypto_issue_count = int(market_issue_counts.get("crypto") or 0)
    stock_auth_fallback_count = sum(
        1
        for item in results
        if str(item.get("market") or "").lower() == "stock"
        and str(item.get("fallback_reason") or "") in {"alpaca_auth", "alpaca_feed_permission"}
    )
    crypto_fallback_count = sum(
        1 for item in results if str(item.get("market") or "").lower() == "crypto" and bool(item.get("fallback"))
    )
    operable_market_issue_count = crypto_issue_count
    blocked_market_issue_count = stock_auth_fallback_count
    route_focus_label = ""
    if blocked_market_issue_count and operable_market_issue_count == 0:
        route_focus_label = "Crypto operable; stock/options bloqueado"
    elif operable_market_issue_count:
        route_focus_label = "Mercado operable requiere revision"
    fallback_reason_counts = dict(
        Counter(str(item.get("fallback_reason") or "-") for item in results if bool(item.get("fallback")))
    )
    alternate_reason_counts = dict(
        Counter(
            str(item.get("polygon_fallback_reason") or "-")
            for item in results
            if bool(item.get("fallback")) and str(item.get("polygon_fallback_reason") or "") not in {"", "-"}
        )
    )
    if status == "OK" and any(str(item.get("status") or "") == "INFO" for item in results):
        status = "INFO"
    if issue:
        detail = (
            f"{len(results)} provider source(s), issue {issue.get('symbol', '-')} "
            f"{issue.get('timeframe', '-')} {issue.get('fallback_reason', issue.get('source_mode', '-'))}"
        )
        if issue.get("polygon_fallback_reason") not in {"", None, "-"}:
            detail += f", alternate {issue.get('polygon_fallback_reason')}"
    else:
        reason_text = ", ".join(f"{key} x{value}" for key, value in sorted(fallback_reason_counts.items())) or "-"
        detail = f"{len(results)} provider source(s), fallback {fallback_count}, auth/perms {auth_fallback_count}, reasons {reason_text}"
        alternate_text = ", ".join(f"{key} x{value}" for key, value in sorted(alternate_reason_counts.items())) or "-"
        if alternate_text != "-":
            detail += f", alternate {alternate_text}"
    recovery_actions = [
        str(item.get("premium_recovery_action") or "")
        for item in results
        if bool(item.get("fallback")) and str(item.get("premium_recovery_action") or "").strip()
    ]
    premium_recovery_action = recovery_actions[0] if recovery_actions else ""
    return check(
        "chart_provider_effective",
        status,
        detail,
        checked_count=len(results),
        fallback_count=fallback_count,
        auth_fallback_count=auth_fallback_count,
        polygon_missing_count=polygon_missing_count,
        market_issue_counts=market_issue_counts,
        market_checked_counts=market_checked_counts,
        stock_issue_count=stock_issue_count,
        crypto_issue_count=crypto_issue_count,
        stock_auth_fallback_count=stock_auth_fallback_count,
        crypto_fallback_count=crypto_fallback_count,
        operable_market_issue_count=operable_market_issue_count,
        blocked_market_issue_count=blocked_market_issue_count,
        route_focus_label=route_focus_label,
        fallback_reason_counts=fallback_reason_counts,
        alternate_reason_counts=alternate_reason_counts,
        premium_recovery_action=premium_recovery_action,
        results=results,
        symbols=[symbol for symbol, _market in deduped],
        timeframe=timeframe,
    )


def provider_effective_targets_with_market_baseline(targets: list[tuple[str, str]]) -> list[tuple[str, str]]:
    normalized: list[tuple[str, str]] = []
    seen: set[tuple[str, str]] = set()
    for symbol, market in targets or []:
        clean_symbol = str(symbol or "").strip().upper()
        if not clean_symbol:
            continue
        clean_market = str(market or ("crypto" if "/" in clean_symbol else "stock")).strip().lower()
        key = (clean_symbol, clean_market)
        if key in seen:
            continue
        seen.add(key)
        normalized.append(key)
    crypto_targets = [item for item in normalized if item[1] == "crypto"]
    non_crypto_targets = [item for item in normalized if item[1] != "crypto"]
    if not crypto_targets:
        crypto_targets = [("ETH/USD", "crypto")]
    return [*non_crypto_targets[:1], crypto_targets[0], *non_crypto_targets[1:], *crypto_targets[1:]]


def provider_recovery_summary(checks: list[dict[str, Any]]) -> dict[str, Any]:
    chart = next((item for item in checks if str(item.get("name") or "") == "chart_provider_effective"), {})
    env = next((item for item in checks if str(item.get("name") or "") == "provider_env_parity"), {})
    alpaca_probe = next((item for item in checks if str(item.get("name") or "") == "alpaca_account_probe"), {})
    checked_count = int(chart.get("checked_count") or 0)
    fallback_count = int(chart.get("fallback_count") or int(bool(chart.get("fallback"))))
    auth_fallback_count = int(chart.get("auth_fallback_count") or 0)
    polygon_missing_count = int(chart.get("polygon_missing_count") or 0)
    market_checked_counts = (
        chart.get("market_checked_counts") if isinstance(chart.get("market_checked_counts"), dict) else {}
    )
    stock_checked_count = int(market_checked_counts.get("stock") or checked_count or 0)
    stock_auth_fallback_count = int(chart.get("stock_auth_fallback_count") or auth_fallback_count or 0)
    fallback_reason_counts = (
        chart.get("fallback_reason_counts") if isinstance(chart.get("fallback_reason_counts"), dict) else {}
    )
    alternate_reason_counts = (
        chart.get("alternate_reason_counts") if isinstance(chart.get("alternate_reason_counts"), dict) else {}
    )
    recovery_action = str(chart.get("premium_recovery_action") or "").strip()
    effective_premium = bool(env.get("effective_premium_configured"))
    launchd_premium = bool(env.get("launchd_premium_configured"))
    process_premium = bool(env.get("process_premium_configured"))
    shared_provider_value_mismatches = (
        env.get("shared_provider_value_mismatches")
        if isinstance(env.get("shared_provider_value_mismatches"), list)
        else []
    )
    shared_provider_values_aligned = env.get("shared_provider_values_aligned")
    missing_provider_keys: list[str] = []
    if polygon_missing_count:
        missing_provider_keys.extend(["POLYGON_API_KEY", "POLYGON_API_TOKEN"])

    alpaca_probe_auth_ok = alpaca_probe.get("auth_ok")
    alpaca_probe_status = str(alpaca_probe.get("status") or "").upper()
    alpaca_probe_diagnosis = str(alpaca_probe.get("diagnosis") or "").strip()
    alpaca_probe_error_category = str(alpaca_probe.get("error_category") or "").strip()
    alpaca_probe_mode = str(alpaca_probe.get("mode") or "").strip()
    alpaca_probe_expected_endpoint = str(alpaca_probe.get("expected_endpoint") or "").strip()
    alpaca_probe_endpoint_hint = str(alpaca_probe.get("endpoint_mode_hint") or "").strip()
    alpaca_probe_credential_names = (
        alpaca_probe.get("credential_names") if isinstance(alpaca_probe.get("credential_names"), list) else []
    )
    alpaca_effective_credentials_present = bool(alpaca_probe.get("configured"))
    alpaca_account_blocks_premium = (
        alpaca_probe_auth_ok is False
        and alpaca_probe_status == "WARN"
        and alpaca_probe_diagnosis == "alpaca_account_auth_failed"
    )
    chart_status = str(chart.get("status") or "").upper()
    if auth_fallback_count or alpaca_account_blocks_premium:
        label = "Premium bloqueado"
        tone = "avoid"
        status = "WARN"
        if not recovery_action:
            recovery_action = "Corregir credenciales/permisos del proveedor premium antes de operar acciones."
        if auth_fallback_count:
            detail = (
                f"{stock_auth_fallback_count or auth_fallback_count}/{stock_checked_count or '-'} "
                "acciones caen a fallback por auth/permisos."
            )
        else:
            mode_text = f" en modo {alpaca_probe_mode}" if alpaca_probe_mode else ""
            error_text = f" ({alpaca_probe_error_category})" if alpaca_probe_error_category else ""
            detail = f"Alpaca account auth failed{mode_text}{error_text}; stock/options bloqueados."
    elif fallback_count:
        label = "Fallback activo"
        tone = "watch"
        status = "INFO" if chart_status != "WARN" else "WARN"
        if not recovery_action:
            recovery_action = "Conectar proveedor premium para evitar depender de yfinance."
        detail = f"{fallback_count}/{checked_count or '-'} fuentes usan fallback."
    elif chart_status == "OK" and checked_count:
        label = "Premium activo"
        tone = "buy"
        status = "OK"
        recovery_action = ""
        detail = f"{checked_count} fuente(s) efectivas sin fallback premium."
    else:
        label = "Sin validacion"
        tone = "watch"
        status = chart_status or "UNKNOWN"
        recovery_action = recovery_action or "Ejecutar check realtime con fuente efectiva."
        detail = str(chart.get("detail") or "Sin check de proveedor efectivo.")

    if polygon_missing_count and "POLYGON_API_KEY" not in recovery_action:
        recovery_action = (
            "Configurar POLYGON_API_KEY/POLYGON_API_TOKEN o corregir credenciales Alpaca para recuperar velas premium."
        )

    if effective_premium and launchd_premium and not process_premium:
        credential_scope = "launchd_only"
    elif effective_premium and process_premium and not launchd_premium:
        credential_scope = "process_only"
    elif effective_premium and launchd_premium and process_premium:
        credential_scope = "aligned"
    elif effective_premium:
        credential_scope = "effective_only"
    else:
        credential_scope = "missing"

    premium_blocked = auth_fallback_count > 0 or alpaca_account_blocks_premium
    primary_provider_issue = ""
    if auth_fallback_count:
        if int(fallback_reason_counts.get("alpaca_feed_permission") or 0):
            primary_provider_issue = "alpaca_feed_permission"
        else:
            primary_provider_issue = "alpaca_auth"
    elif alpaca_account_blocks_premium:
        primary_provider_issue = "alpaca_auth"
    elif fallback_count:
        primary_provider_issue = next(iter(fallback_reason_counts.keys()), "fallback")
    alternate_provider_issue = ""
    if polygon_missing_count:
        alternate_provider_issue = "polygon_not_configured"
    elif alternate_reason_counts:
        alternate_provider_issue = next(iter(alternate_reason_counts.keys()), "")
    credential_diagnosis = ""
    recovery_priority: list[str] = []
    if premium_blocked:
        recovery_priority.append("validate_alpaca_credentials")
        if alpaca_probe_auth_ok is True:
            recovery_priority[0] = "validate_alpaca_market_data_feed"
            credential_diagnosis = (
                "Alpaca autentica correctamente en la cuenta, pero las velas premium caen en auth/permisos; "
                "validar suscripcion/feed de market data, IEX/SIP y permisos del endpoint de data."
            )
        elif alpaca_probe_status == "WARN" and alpaca_probe_diagnosis == "alpaca_account_auth_failed":
            if shared_provider_value_mismatches:
                recovery_priority[0] = "align_process_launchd_alpaca_credentials"
                credential_diagnosis = (
                    "Alpaca esta configurado en LaunchAgent y proceso, pero los valores compartidos difieren; "
                    "alinear el .env del servicio y el entorno manual antes de rotar o validar permisos/feed."
                )
            elif alpaca_probe_error_category == "ENDPOINT_OR_MODE" or alpaca_probe_endpoint_hint:
                recovery_priority[0] = "fix_alpaca_paper_live_endpoint"
                credential_diagnosis = (
                    f"Alpaca falla por posible mezcla paper/live o endpoint. Modo efectivo {alpaca_probe_mode or '-'}; "
                    f"endpoint esperado {alpaca_probe_expected_endpoint or '-'}. {alpaca_probe_endpoint_hint}".strip()
                )
            elif alpaca_probe_error_category in {"AUTH_INVALID", "AUTH_FORBIDDEN"}:
                recovery_priority[0] = "rotate_or_correct_alpaca_credentials"
                credential_diagnosis = (
                    f"Alpaca tiene credenciales efectivas presentes, pero no autentica ({alpaca_probe_error_category}); "
                    "rotar/corregir ALPACA_API_KEY y ALPACA_API_SECRET en el .env usado por LaunchAgent."
                )
            else:
                recovery_priority[0] = "validate_alpaca_credentials"
                credential_diagnosis = (
                    "Alpaca no autentica con las credenciales efectivas; revisar ALPACA_API_KEY/ALPACA_API_SECRET, "
                    "paper/live y el .env usado por LaunchAgent."
                )
        elif credential_scope == "launchd_only":
            credential_diagnosis = (
                "Alpaca esta configurado en LaunchAgent, pero el proveedor efectivo cae en auth/permisos; "
                "validar key/secret, paper/live y permisos/feed usados por el servicio."
            )
        elif credential_scope == "aligned":
            credential_diagnosis = (
                "Alpaca esta configurado en LaunchAgent y proceso, pero cae en auth/permisos; "
                "validar credenciales activas, tipo de cuenta y permisos/feed."
            )
        elif credential_scope == "process_only":
            credential_diagnosis = "Alpaca existe en el proceso manual pero no en LaunchAgent; alinear .env/servicio antes de confiar en realtime."
        elif credential_scope == "missing":
            credential_diagnosis = (
                "No hay credenciales Alpaca efectivas; configurar ALPACA_API_KEY y ALPACA_API_SECRET."
            )
        else:
            credential_diagnosis = "Proveedor premium cae en auth/permisos; validar credenciales y permisos."
        if polygon_missing_count:
            recovery_priority.append("configure_polygon_alternate")
        recovery_priority.append("rerun_realtime_health")
    if premium_blocked:
        impacted_markets = ["stock", "options"]
        safe_mode = "NO_STOCK_OR_OPTIONS_ALERTS"
        confirmation_gate = "NO_TRADE_FROM_FALLBACK"
        recovery_steps = [
            credential_diagnosis or "Corregir credenciales/permisos Alpaca usados por LaunchAgent/Streamlit.",
            "Configurar POLYGON_API_KEY/POLYGON_API_TOKEN como proveedor premium alterno.",
            "Reejecutar tools/roxy_realtime_check.py --no-fail y confirmar chart_provider_effective OK.",
        ]
    elif fallback_count:
        impacted_markets = ["stock"]
        safe_mode = "CONFIRM_FALLBACK_EXTERNALLY"
        confirmation_gate = "FALLBACK_CONFIRM"
        recovery_steps = [
            "Conectar proveedor premium para reducir dependencia de yfinance.",
            "Confirmar niveles en Finviz/TradingView antes de operar intradia.",
        ]
    elif chart_status == "OK" and checked_count:
        impacted_markets = []
        safe_mode = "PREMIUM_CONFIRMED"
        confirmation_gate = "LIVE_CONFIRMED"
        recovery_steps = []
    else:
        impacted_markets = []
        safe_mode = "PROVIDER_UNVERIFIED"
        confirmation_gate = "RUN_REALTIME_CHECK"
        recovery_steps = ["Ejecutar check realtime con simbolos activos y revisar fuente efectiva."]

    return {
        "status": status,
        "label": label,
        "tone": tone,
        "detail": detail,
        "action": recovery_action,
        "premium_blocked": premium_blocked,
        "stock_alerts_allowed": not premium_blocked,
        "impacted_markets": impacted_markets,
        "safe_mode": safe_mode,
        "confirmation_gate": confirmation_gate,
        "credential_scope": credential_scope,
        "credential_diagnosis": credential_diagnosis,
        "shared_provider_values_aligned": shared_provider_values_aligned,
        "shared_provider_value_mismatches": shared_provider_value_mismatches[:5],
        "primary_provider_issue": primary_provider_issue,
        "alternate_provider_issue": alternate_provider_issue,
        "alpaca_account_auth_ok": alpaca_probe_auth_ok,
        "alpaca_account_probe_status": alpaca_probe_status or "",
        "alpaca_account_probe_diagnosis": alpaca_probe_diagnosis,
        "alpaca_account_error_category": alpaca_probe_error_category,
        "alpaca_account_mode": alpaca_probe_mode,
        "alpaca_expected_endpoint": alpaca_probe_expected_endpoint,
        "alpaca_endpoint_mode_hint": alpaca_probe_endpoint_hint,
        "alpaca_effective_credentials_present": alpaca_effective_credentials_present,
        "alpaca_configured_credential_names": [str(name) for name in alpaca_probe_credential_names],
        "recovery_priority": recovery_priority,
        "recovery_steps": recovery_steps,
        "checked_count": checked_count,
        "fallback_count": fallback_count,
        "auth_fallback_count": auth_fallback_count,
        "stock_checked_count": stock_checked_count,
        "stock_auth_fallback_count": stock_auth_fallback_count,
        "polygon_missing_count": polygon_missing_count,
        "missing_provider_keys": sorted(set(missing_provider_keys)),
        "fallback_reason_counts": fallback_reason_counts,
        "alternate_reason_counts": alternate_reason_counts,
        "effective_premium_configured": effective_premium,
        "launchd_premium_configured": launchd_premium,
        "process_premium_configured": process_premium,
    }


def market_realtime_summary(
    checks: list[dict[str, Any]], provider_recovery: dict[str, Any] | None = None
) -> dict[str, Any]:
    provider_recovery = provider_recovery if isinstance(provider_recovery, dict) else {}
    chart = next((item for item in checks if str(item.get("name") or "") == "chart_provider_effective"), {})
    results = chart.get("results") if isinstance(chart.get("results"), list) else []
    by_market: dict[str, list[dict[str, Any]]] = {"stock": [], "crypto": []}
    for item in results:
        if not isinstance(item, dict):
            continue
        market = str(item.get("market") or "").lower()
        if market in by_market:
            by_market[market].append(item)

    def status_counts(rows: list[dict[str, Any]]) -> dict[str, int]:
        return {
            "checked": len(rows),
            "ok": sum(1 for row in rows if str(row.get("status") or "").upper() == "OK"),
            "warn": sum(1 for row in rows if str(row.get("status") or "").upper() == "WARN"),
            "fail": sum(1 for row in rows if str(row.get("status") or "").upper() == "FAIL"),
            "fallback": sum(1 for row in rows if bool(row.get("fallback"))),
            "auth_fallback": sum(
                1 for row in rows if str(row.get("fallback_reason") or "") in {"alpaca_auth", "alpaca_feed_permission"}
            ),
        }

    stock_counts = status_counts(by_market["stock"])
    crypto_counts = status_counts(by_market["crypto"])
    stock_action = str(provider_recovery.get("action") or chart.get("premium_recovery_action") or "").strip()
    stock_blocked = bool(provider_recovery.get("premium_blocked")) or stock_counts["auth_fallback"] > 0
    if stock_blocked:
        stock = {
            "market": "stock",
            "label": "Acciones bloqueadas",
            "status": "WARN",
            "tone": "avoid",
            "alerts_allowed": False,
            "detail": f"{stock_counts['auth_fallback'] or stock_counts['fallback']}/{stock_counts['checked'] or '-'} fuentes con auth/permisos premium.",
            "action": stock_action or "Corregir proveedor premium de acciones.",
            **stock_counts,
        }
    elif stock_counts["checked"] and stock_counts["fallback"]:
        stock = {
            "market": "stock",
            "label": "Acciones en fallback",
            "status": "INFO",
            "tone": "watch",
            "alerts_allowed": True,
            "detail": f"{stock_counts['fallback']}/{stock_counts['checked']} fuentes usan fallback.",
            "action": stock_action or "Conectar proveedor premium para acciones.",
            **stock_counts,
        }
    elif stock_counts["checked"]:
        stock = {
            "market": "stock",
            "label": "Acciones realtime",
            "status": "OK",
            "tone": "buy",
            "alerts_allowed": True,
            "detail": f"{stock_counts['checked']} fuente(s) premium validas.",
            "action": "",
            **stock_counts,
        }
    else:
        stock = {
            "market": "stock",
            "label": "Acciones sin validar",
            "status": "UNKNOWN",
            "tone": "watch",
            "alerts_allowed": True,
            "detail": "Sin muestra efectiva de acciones en chart_provider_effective.",
            "action": "Ejecutar check realtime con simbolos de acciones activos.",
            **stock_counts,
        }

    if (
        crypto_counts["checked"]
        and crypto_counts["fail"] == 0
        and crypto_counts["warn"] == 0
        and crypto_counts["fallback"] == 0
    ):
        crypto = {
            "market": "crypto",
            "label": "Cripto realtime",
            "status": "OK",
            "tone": "buy",
            "alerts_allowed": True,
            "detail": f"{crypto_counts['checked']} fuente(s) exchange/API validas.",
            "action": "",
            **crypto_counts,
        }
    elif crypto_counts["checked"]:
        crypto = {
            "market": "crypto",
            "label": "Cripto revisar",
            "status": "WARN" if crypto_counts["fail"] == 0 else "FAIL",
            "tone": "watch" if crypto_counts["fail"] == 0 else "avoid",
            "alerts_allowed": crypto_counts["fail"] == 0,
            "detail": f"{crypto_counts['ok']}/{crypto_counts['checked']} fuentes cripto OK.",
            "action": "Revisar exchange/API cripto si hay fallos persistentes.",
            **crypto_counts,
        }
    else:
        crypto = {
            "market": "crypto",
            "label": "Cripto sin validar",
            "status": "UNKNOWN",
            "tone": "watch",
            "alerts_allowed": True,
            "detail": "Sin muestra cripto en chart_provider_effective.",
            "action": "Ejecutar check realtime con BTC/ETH.",
            **crypto_counts,
        }

    options = {
        "market": "options",
        "label": "Opciones bloqueadas" if not stock["alerts_allowed"] else "Opciones listas",
        "status": "WARN" if not stock["alerts_allowed"] else "OK",
        "tone": "avoid" if not stock["alerts_allowed"] else "buy",
        "alerts_allowed": bool(stock["alerts_allowed"]),
        "detail": (
            "Opciones dependen del proveedor realtime de acciones."
            if not stock["alerts_allowed"]
            else "Opciones pueden usar acciones realtime como subyacente."
        ),
        "action": stock.get("action", "") if not stock["alerts_allowed"] else "",
        "checked": stock_counts["checked"],
        "ok": stock_counts["ok"],
        "warn": stock_counts["warn"],
        "fail": stock_counts["fail"],
        "fallback": stock_counts["fallback"],
        "auth_fallback": stock_counts["auth_fallback"],
    }
    rows = [stock, crypto, options]
    blocked = [row["market"] for row in rows if not row.get("alerts_allowed")]
    allowed = [
        row["market"]
        for row in rows
        if bool(row.get("alerts_allowed")) and str(row.get("tone") or "").lower() != "avoid"
    ]
    if allowed and blocked:
        active_route = "PARTIAL_MARKET_ROUTE"
        active_route_label = "Operar solo " + ", ".join(item.upper() for item in allowed)
        active_route_detail = (
            "Operable "
            + ", ".join(item.upper() for item in allowed)
            + "; bloqueado "
            + ", ".join(item.upper() for item in blocked)
            + "."
        )
    elif allowed:
        active_route = "ALL_MARKETS_ROUTE"
        active_route_label = "Operar mercados realtime"
        active_route_detail = "Operable " + ", ".join(item.upper() for item in allowed) + "."
    elif blocked:
        active_route = "NO_MARKET_ROUTE"
        active_route_label = "No operar realtime"
        active_route_detail = "Bloqueado " + ", ".join(item.upper() for item in blocked) + "."
    else:
        active_route = "UNKNOWN_MARKET_ROUTE"
        active_route_label = "Ruta sin validar"
        active_route_detail = "Sin mapa de mercados realtime."
    return {
        "status": "WARN" if blocked else "OK",
        "label": "Mercados parciales" if blocked else "Mercados realtime",
        "tone": "avoid" if "stock" in blocked else "watch" if blocked else "buy",
        "blocked_markets": blocked,
        "allowed_markets": allowed,
        "active_route": active_route,
        "active_route_label": active_route_label,
        "active_route_detail": active_route_detail,
        "rows": rows,
        "markets": {row["market"]: row for row in rows},
    }


def launchd_env_key_names(path: str | Path = DEFAULT_LAUNCHD_ENV_PATH) -> set[str]:
    env_path = Path(path)
    if not env_path.exists():
        return set()
    keys: set[str] = set()
    pattern = re.compile(r"^\s*(?:export\s+)?([A-Za-z_][A-Za-z0-9_]*)\s*=")
    try:
        for raw_line in env_path.read_text(errors="ignore").splitlines():
            line = raw_line.strip()
            if not line or line.startswith("#"):
                continue
            match = pattern.match(raw_line)
            if match:
                keys.add(match.group(1))
    except Exception:
        return set()
    return keys


def launchd_env_values(path: str | Path = DEFAULT_LAUNCHD_ENV_PATH) -> dict[str, str]:
    env_path = Path(path)
    if not env_path.exists():
        return {}
    values: dict[str, str] = {}
    pattern = re.compile(r"^\s*(?:export\s+)?([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)$")
    try:
        lines = env_path.read_text(errors="ignore").splitlines()
    except Exception:
        return {}
    for raw_line in lines:
        line = raw_line.strip()
        if not line or line.startswith("#"):
            continue
        match = pattern.match(raw_line)
        if not match:
            continue
        key = match.group(1)
        if key not in PROVIDER_ENV_KEYS:
            continue
        raw_value = match.group(2).strip()
        try:
            parts = shlex.split(raw_value, comments=True, posix=True)
            value = parts[0] if parts else ""
        except ValueError:
            value = raw_value.split("#", 1)[0].strip().strip("'\"")
        if value:
            values[key] = value
    return values


def effective_provider_env(
    *,
    process_env: dict[str, str] | None = None,
    launchd_env_path: str | Path = DEFAULT_LAUNCHD_ENV_PATH,
) -> tuple[dict[str, str], list[str]]:
    source = dict(process_env if process_env is not None else os.environ)
    launchd_values = launchd_env_values(launchd_env_path)
    loaded_keys: list[str] = []
    for key, value in launchd_values.items():
        if key in PROVIDER_ENV_KEYS and not str(source.get(key) or "").strip():
            source[key] = value
            loaded_keys.append(key)
    return source, sorted(loaded_keys)


def _alpaca_configured_from_keys(keys: set[str]) -> bool:
    return "ALPACA_API_KEY" in keys and ("ALPACA_API_SECRET" in keys or "ALPACA_SECRET_KEY" in keys)


def _polygon_configured_from_keys(keys: set[str]) -> bool:
    return bool({"POLYGON_API_KEY", "POLYGON_API_TOKEN"} & keys)


def validate_provider_env_parity(
    *,
    launchd_env_path: str | Path = DEFAULT_LAUNCHD_ENV_PATH,
    process_env: dict[str, str] | None = None,
) -> dict[str, Any]:
    source = process_env if process_env is not None else os.environ
    provider_keys = set(PROVIDER_ENV_KEYS)
    process_keys = {key for key in provider_keys if str(source.get(key) or "").strip()}
    effective_env, effective_loaded_keys = effective_provider_env(process_env=source, launchd_env_path=launchd_env_path)
    launchd_keys = launchd_env_key_names(launchd_env_path) & provider_keys
    effective_keys = {key for key in provider_keys if str(effective_env.get(key) or "").strip()}
    env_path = Path(launchd_env_path)
    launchd_configured = _alpaca_configured_from_keys(launchd_keys)
    process_configured = _alpaca_configured_from_keys(process_keys)
    effective_configured = _alpaca_configured_from_keys(effective_keys)
    launchd_polygon_configured = _polygon_configured_from_keys(launchd_keys)
    process_polygon_configured = _polygon_configured_from_keys(process_keys)
    effective_polygon_configured = _polygon_configured_from_keys(effective_keys)
    launchd_premium_configured = launchd_configured or launchd_polygon_configured
    process_premium_configured = process_configured or process_polygon_configured
    effective_premium_configured = effective_configured or effective_polygon_configured
    launchd_only = sorted(launchd_keys - process_keys)
    process_only = sorted(process_keys - launchd_keys)
    shared = sorted(launchd_keys & process_keys)
    launchd_values = launchd_env_values(launchd_env_path)
    shared_value_mismatches = sorted(
        key
        for key in shared
        if str(launchd_values.get(key) or "").strip()
        and str(source.get(key) or "").strip()
        and str(launchd_values.get(key) or "").strip() != str(source.get(key) or "").strip()
    )
    shared_provider_values_aligned = not shared_value_mismatches

    if shared_value_mismatches and launchd_premium_configured and process_premium_configured:
        status = "WARN"
        detail = "LaunchAgent env and current process share premium credential names but some values differ; realtime service and manual checks may authenticate differently."
    elif effective_premium_configured and launchd_premium_configured and not process_premium_configured:
        status = "OK"
        detail = "LaunchAgent env has premium provider credentials; current process env does not. Provider checks load LaunchAgent .env as effective service context."
    elif process_premium_configured and not launchd_premium_configured:
        status = "WARN"
        detail = "Current process has premium provider credentials but LaunchAgent env does not; 24/7 services may run fallback."
    elif launchd_premium_configured and process_premium_configured:
        status = "OK"
        detail = "LaunchAgent env and current process both expose premium provider credential names."
    elif launchd_keys or process_keys:
        status = "INFO"
        detail = "Provider env is partially configured; premium data not fully available in both contexts."
    else:
        status = "INFO"
        detail = "No provider credential names found in LaunchAgent env or current process; fallback expected."
    if launchd_only:
        detail += f" launchd-only {', '.join(launchd_only)}."
    if process_only:
        detail += f" process-only {', '.join(process_only)}."
    if shared_value_mismatches:
        detail += f" mismatched shared values {', '.join(shared_value_mismatches)}."
    return check(
        "provider_env_parity",
        status,
        detail,
        launchd_env_path=str(env_path),
        launchd_env_exists=env_path.exists(),
        launchd_provider_keys=sorted(launchd_keys),
        process_provider_keys=sorted(process_keys),
        effective_provider_keys=sorted(effective_keys),
        shared_provider_keys=shared,
        shared_provider_values_aligned=shared_provider_values_aligned,
        shared_provider_value_mismatches=shared_value_mismatches,
        launchd_only_provider_keys=launchd_only,
        process_only_provider_keys=process_only,
        effective_loaded_provider_keys=effective_loaded_keys,
        launchd_alpaca_configured=launchd_configured,
        process_alpaca_configured=process_configured,
        effective_alpaca_configured=effective_configured,
        launchd_polygon_configured=launchd_polygon_configured,
        process_polygon_configured=process_polygon_configured,
        effective_polygon_configured=effective_polygon_configured,
        launchd_premium_configured=launchd_premium_configured,
        process_premium_configured=process_premium_configured,
        effective_premium_configured=effective_premium_configured,
    )


def _env_bool(value: Any, default: bool = False) -> bool:
    text = str(value or "").strip().lower()
    if not text:
        return default
    return text in {"1", "true", "yes", "y", "on", "paper"}


def _alpaca_auth_error(exc: Exception) -> bool:
    text = f"{exc.__class__.__name__} {exc}".lower()
    return any(token in text for token in ("401", "403", "unauthorized", "forbidden", "invalid", "auth"))


def alpaca_expected_endpoint(paper: bool) -> str:
    return "https://paper-api.alpaca.markets" if paper else "https://api.alpaca.markets"


def alpaca_error_category(exc: Exception) -> str:
    text = f"{exc.__class__.__name__} {exc}".lower()
    if any(token in text for token in ("401", "unauthorized", "invalid", "auth")):
        return "AUTH_INVALID"
    if any(token in text for token in ("403", "forbidden", "permission")):
        return "AUTH_FORBIDDEN"
    if any(token in text for token in ("paper", "live", "endpoint", "base url")):
        return "ENDPOINT_OR_MODE"
    if any(token in text for token in ("timeout", "timed out")):
        return "TIMEOUT"
    if any(token in text for token in ("connection", "network", "dns", "503", "502", "500")):
        return "NETWORK"
    return "UNKNOWN"


def validate_alpaca_account_probe(
    *,
    env: dict[str, str] | None = None,
    client_factory: Any | None = None,
    timeout_seconds: float = 8.0,
) -> dict[str, Any]:
    source = env if env is not None else os.environ
    api_key = str(source.get("ALPACA_API_KEY") or "").strip()
    secret_name = "ALPACA_API_SECRET" if str(source.get("ALPACA_API_SECRET") or "").strip() else "ALPACA_SECRET_KEY"
    secret_key = str(source.get(secret_name) or "").strip()
    paper = _env_bool(source.get("ALPACA_PAPER"), default=True)
    url_override = (
        str(
            source.get("ALPACA_BASE_URL") or source.get("ALPACA_ENDPOINT") or source.get("ALPACA_API_BASE_URL") or ""
        ).strip()
        or None
    )
    mode = "paper" if paper else "live"
    expected_endpoint = alpaca_expected_endpoint(paper)
    credential_names = [name for name, value in [("ALPACA_API_KEY", api_key), (secret_name, secret_key)] if value]
    endpoint_mode_hint = ""
    if url_override:
        override_lower = url_override.lower()
        if paper and "paper" not in override_lower:
            endpoint_mode_hint = "ALPACA_PAPER=true pero endpoint override no parece paper."
        elif not paper and "paper" in override_lower:
            endpoint_mode_hint = "ALPACA_PAPER=false pero endpoint override parece paper."
    url_override_ignored = bool(endpoint_mode_hint)
    effective_url_override = None if url_override_ignored else url_override
    if not api_key or not secret_key:
        missing_names = [
            name
            for name, value in [("ALPACA_API_KEY", api_key), ("ALPACA_API_SECRET/ALPACA_SECRET_KEY", secret_key)]
            if not value
        ]
        return check(
            "alpaca_account_probe",
            "INFO",
            "Alpaca account probe skipped; credential names missing in effective env.",
            configured=False,
            auth_ok=False,
            paper=paper,
            mode=mode,
            credential_names=credential_names,
            missing_credential_names=missing_names,
            expected_endpoint=expected_endpoint,
            url_override_configured=bool(url_override),
            url_override_ignored=url_override_ignored,
            effective_endpoint=expected_endpoint if url_override_ignored or not url_override else url_override,
            endpoint_mode_hint=endpoint_mode_hint,
        )

    def run_probe() -> Any:
        if client_factory is None:
            from alpaca.trading.client import TradingClient

            factory = TradingClient
        else:
            factory = client_factory
        kwargs: dict[str, Any] = {"api_key": api_key, "secret_key": secret_key, "paper": paper}
        if effective_url_override:
            kwargs["url_override"] = effective_url_override
        client = factory(**kwargs)
        return client.get_account()

    result_queue: queue.Queue[tuple[str, Any]] = queue.Queue(maxsize=1)

    def worker() -> None:
        try:
            result_queue.put(("ok", run_probe()), block=False)
        except BaseException as exc:
            try:
                result_queue.put(("error", exc), block=False)
            except Exception:
                pass

    thread = threading.Thread(target=worker, name="roxy-alpaca-account-probe", daemon=True)
    thread.start()
    try:
        kind, payload = result_queue.get(timeout=max(0.001, float(timeout_seconds)))
    except queue.Empty:
        return check(
            "alpaca_account_probe",
            "INFO",
            f"Alpaca account probe timed out after {float(timeout_seconds):.1f}s in {mode} mode; health continues without blocking.",
            configured=True,
            auth_ok=None,
            diagnosis="alpaca_account_probe_timeout",
            paper=paper,
            mode=mode,
            credential_names=credential_names,
            expected_endpoint=expected_endpoint,
            timeout_seconds=float(timeout_seconds),
            url_override_configured=bool(url_override),
            url_override_ignored=url_override_ignored,
            effective_endpoint=expected_endpoint if url_override_ignored or not url_override else url_override,
            endpoint_mode_hint=endpoint_mode_hint,
        )

    if kind == "ok":
        account = payload
    else:
        exc = payload
        if isinstance(exc, ImportError):
            return check(
                "alpaca_account_probe",
                "INFO",
                "Alpaca trading SDK unavailable; account auth probe skipped.",
                configured=True,
                auth_ok=None,
                paper=paper,
                mode=mode,
                credential_names=credential_names,
                expected_endpoint=expected_endpoint,
                url_override_configured=bool(url_override),
                url_override_ignored=url_override_ignored,
                effective_endpoint=expected_endpoint if url_override_ignored or not url_override else url_override,
                endpoint_mode_hint=endpoint_mode_hint,
            )
        if not isinstance(exc, Exception):
            exc = RuntimeError(str(exc))
        auth_error = _alpaca_auth_error(exc)
        category = alpaca_error_category(exc)
        status = "WARN" if auth_error else "INFO"
        hint = f" {endpoint_mode_hint}" if endpoint_mode_hint else ""
        detail = (
            f"Alpaca account auth failed in {mode} mode ({category}); revisar credenciales, ALPACA_PAPER y endpoint.{hint}"
            if auth_error
            else f"Alpaca account probe inconclusive in {mode} mode: {exc.__class__.__name__}."
        )
        return check(
            "alpaca_account_probe",
            status,
            detail,
            configured=True,
            auth_ok=False if auth_error else None,
            diagnosis="alpaca_account_auth_failed" if auth_error else "alpaca_account_probe_inconclusive",
            paper=paper,
            mode=mode,
            credential_names=credential_names,
            expected_endpoint=expected_endpoint,
            url_override_configured=bool(url_override),
            url_override_ignored=url_override_ignored,
            effective_endpoint=expected_endpoint if url_override_ignored or not url_override else url_override,
            endpoint_mode_hint=endpoint_mode_hint,
            error_category=category,
            error_class=exc.__class__.__name__,
        )

    account_status = str(getattr(account, "status", "") or "").strip()
    trading_blocked = bool(getattr(account, "trading_blocked", False))
    return check(
        "alpaca_account_probe",
        "OK",
        f"Alpaca account auth OK in {mode} mode; account status {account_status or '-'}; trading_blocked={trading_blocked}.",
        configured=True,
        auth_ok=True,
        paper=paper,
        mode=mode,
        credential_names=credential_names,
        expected_endpoint=expected_endpoint,
        account_status=account_status,
        trading_blocked=trading_blocked,
        url_override_configured=bool(url_override),
        url_override_ignored=url_override_ignored,
        effective_endpoint=expected_endpoint if url_override_ignored or not url_override else url_override,
        endpoint_mode_hint=endpoint_mode_hint,
    )


def chart_market_for_symbol(symbol: str, fallback: str = "stock") -> str:
    clean_symbol = str(symbol or "").strip()
    if "/" in clean_symbol:
        return "crypto"
    return str(fallback or "stock").strip().lower() or "stock"


def choose_chart_symbol(
    scan_df: pd.DataFrame,
    explicit_symbol: str | None,
    *,
    operational_focus_symbol: str | None = None,
    operational_focus_market: str | None = None,
) -> tuple[str, str]:
    def clean_candidate(value: Any) -> str:
        candidate = str(value or "").strip().upper()
        return "" if candidate in {"", "-", "NONE", "NULL", "N/A"} else candidate

    clean_symbol = clean_candidate(explicit_symbol)
    if clean_symbol:
        return clean_symbol, chart_market_for_symbol(clean_symbol)
    clean_symbol = clean_candidate(operational_focus_symbol)
    if clean_symbol:
        return clean_symbol, chart_market_for_symbol(clean_symbol, fallback=operational_focus_market or "stock")
    if scan_df.empty or "symbol" not in scan_df.columns:
        return "", "stock"
    for _, scan_row in scan_df.iterrows():
        row = scan_row.to_dict()
        clean_symbol = clean_candidate(row.get("symbol"))
        if clean_symbol:
            return clean_symbol, str(row.get("market") or "stock").lower()
    return "", "stock"


def sample_salto_chart() -> pd.DataFrame:
    rows = []
    for idx in range(240):
        close = 50.0 + idx * 0.22
        rows.append(
            {
                "ts": pd.Timestamp("2026-01-01") + pd.to_timedelta(idx, unit="h"),
                "open": close - 0.05,
                "high": close + 0.15,
                "low": close - 0.20,
                "close": close,
                "volume": 1_000_000 + idx * 1_000,
            }
        )
    try:
        from symbol_detail import prepare_symbol_chart_data

        return prepare_symbol_chart_data(pd.DataFrame(rows))
    except Exception:
        return pd.DataFrame(rows)


def validate_salto_integration() -> dict[str, Any]:
    try:
        from roxy_ai import build_strategy_lab
        from salto_strategies import SALTO_STRATEGIES, SALTO_STRATEGY_FAMILIES, detect_salto_setups
        from trade_brief import CORE_STRATEGIES, strategy_family_from_setup

        families = set(SALTO_STRATEGY_FAMILIES)
        core_missing = sorted(families - set(CORE_STRATEGIES))
        lab_rows = build_strategy_lab({"strategy_stats": {}, "signal_journal": []})
        lab_families = {str(row.get("strategy_family")) for row in lab_rows}
        lab_missing = sorted(families - lab_families)
        key_mapping_ok = all(strategy_family_from_setup(item.key) == item.family for item in SALTO_STRATEGIES)
        detected = detect_salto_setups(sample_salto_chart(), {"setup": "TREND_CONTINUATION", "signal": "WATCH"})
        active_or_watch = [row for row in detected if row.get("status") in {"ACTIVE", "WATCH"}]
        issues = []
        if len(SALTO_STRATEGIES) < 5:
            issues.append("expected at least 5 salto definitions")
        if core_missing:
            issues.append(f"missing in CORE_STRATEGIES: {', '.join(core_missing)}")
        if lab_missing:
            issues.append(f"missing in strategy lab: {', '.join(lab_missing)}")
        if not key_mapping_ok:
            issues.append("strategy_family_from_setup does not map every salto key")
        if not active_or_watch:
            issues.append("isolated validation fixture did not produce active/watch salto setup")
        status = "OK" if not issues else "FAIL"
        detail = (
            f"{len(SALTO_STRATEGIES)} definitions, {len(active_or_watch)} isolated fixture detections; "
            "fixture-only, 0 market rows published"
            if not issues
            else "; ".join(issues)
        )
        return check(
            "salto_integration",
            status,
            detail,
            definitions=len(SALTO_STRATEGIES),
            active_or_watch=len(active_or_watch),
            fixture_only=True,
            published_market_rows=0,
            core_missing=core_missing,
            lab_missing=lab_missing,
        )
    except Exception as exc:
        return check("salto_integration", "FAIL", f"Salto integration check failed: {exc}")


def validate_smart_alert_contract(path: str | Path = BASE_DIR / "smart_alerts.py") -> dict[str, Any]:
    source_path = Path(path)
    if not source_path.exists():
        return check("smart_alert_contract", "FAIL", "smart_alerts.py not found", path=str(source_path))
    try:
        source = source_path.read_text()
    except OSError as exc:
        return check("smart_alert_contract", "FAIL", f"Could not read smart alerts: {exc}", path=str(source_path))
    required_tokens = [
        "_chart_contract_is_healthy",
        "Grafica operable",
        "BLOCKING_CHART_GATES",
        "NO_TRADE_FROM_FALLBACK",
        "NO_TRADE_STALE_DATA",
        "WAIT_NEXT_CANDLE",
        "MARKET_CLOSED_RECHECK",
        "EXTERNAL_CONFIRM_REQUIRED",
        "CHART_CONTRACT_MISSING",
        "BLOCKED_REALTIME_DATA",
    ]
    missing = [token for token in required_tokens if token not in source]
    status = "OK" if not missing else "FAIL"
    detail = (
        "Smart alerts block notifications when chart data contract is not operable"
        if not missing
        else "smart alert chart contract missing " + ", ".join(missing)
    )
    return check(
        "smart_alert_contract",
        status,
        detail,
        path=str(source_path),
        missing=missing,
        chart_contract_gate_present="_chart_contract_is_healthy" in source,
        chart_operable_check_present="Grafica operable" in source,
    )


def command_has_timeframes(command: str, option: str, required_timeframes: set[str]) -> bool:
    marker = f"{option} "
    if marker not in command:
        return False
    value = command.split(marker, 1)[1].split(" ", 1)[0]
    present = {item.strip().lower() for item in value.split(",") if item.strip()}
    return required_timeframes.issubset(present)


def command_option_int(command: str, option: str) -> int | None:
    marker = f"{option} "
    if marker not in command:
        return None
    value = command.split(marker, 1)[1].split(" ", 1)[0]
    try:
        return int(value)
    except ValueError:
        return None


def command_option_value(command: str, option: str) -> str | None:
    try:
        parts = shlex.split(str(command or ""))
    except ValueError:
        parts = str(command or "").split()
    if option not in parts:
        return None
    idx = parts.index(option)
    if idx + 1 >= len(parts):
        return None
    return parts[idx + 1]


def command_has_flag(command: str, flag: str) -> bool:
    return flag in str(command or "").split()


def command_script_segment(command: str, script_name: str) -> str:
    for segment in str(command or "").split("&&"):
        if script_name in segment:
            return segment
    return ""


def command_script_has_flag(command: str, script_name: str, flag: str) -> bool:
    return command_has_flag(command_script_segment(command, script_name), flag)


def command_script_option_value(command: str, script_name: str, option: str) -> str | None:
    return command_option_value(command_script_segment(command, script_name), option)


def command_script_position(command: str, script_name: str) -> int | None:
    for idx, segment in enumerate(str(command or "").split("&&")):
        if script_name in segment:
            return idx
    return None


def validate_disk_space(base_dir: Path, *, warn_free_gb: float, fail_free_gb: float) -> dict[str, Any]:
    usage = shutil.disk_usage(base_dir)
    free_gb = usage.free / (1024**3)
    total_gb = usage.total / (1024**3)
    free_pct = (usage.free / usage.total * 100.0) if usage.total else 0.0
    if free_gb < fail_free_gb:
        status = "FAIL"
    elif free_gb < warn_free_gb:
        status = "WARN"
    else:
        status = "OK"
    return check(
        "disk_space",
        status,
        f"{free_gb:.2f} GiB free ({free_pct:.1f}% of {total_gb:.0f} GiB)",
        free_gb=free_gb,
        free_pct=free_pct,
        warn_free_gb=warn_free_gb,
        fail_free_gb=fail_free_gb,
    )


def annotate_local_storage_cleanup_plan(status: dict[str, Any]) -> dict[str, Any]:
    top_entries = status.get("top_entries") if isinstance(status.get("top_entries"), list) else []
    safe_names = {item.lower() for item in DEFAULT_LOCAL_STORAGE_SAFE_CLEANUP_CANDIDATES}
    manual_names = {item.lower() for item in DEFAULT_LOCAL_STORAGE_MANUAL_REVIEW_CANDIDATES}
    annotated_entries: list[dict[str, Any]] = []
    safe_entries: list[dict[str, Any]] = []
    manual_entries: list[dict[str, Any]] = []

    for raw_entry in top_entries:
        if not isinstance(raw_entry, dict):
            continue
        entry = dict(raw_entry)
        name = str(entry.get("name") or "").strip()
        normalized_name = name.lower()
        if normalized_name in safe_names:
            policy = "SAFE_CACHE_REVIEW"
            risk = "low"
            hint = "Cache candidate; close apps and clear through OS/app tools."
        elif normalized_name in manual_names:
            policy = "MANUAL_REVIEW_REQUIRED"
            risk = "user_data"
            hint = "User data candidate; inspect before deleting or moving to external storage."
        else:
            policy = "INSPECT_MANUALLY"
            risk = "unknown"
            hint = "Inspect path before cleanup."
        entry["cleanup_policy"] = policy
        entry["cleanup_risk"] = risk
        entry["cleanup_hint"] = hint
        annotated_entries.append(entry)
        if policy == "SAFE_CACHE_REVIEW":
            safe_entries.append(entry)
        elif policy == "MANUAL_REVIEW_REQUIRED":
            manual_entries.append(entry)

    safe_total_gb = round(sum(float(item.get("size_gb") or 0.0) for item in safe_entries), 4)
    manual_total_gb = round(sum(float(item.get("size_gb") or 0.0) for item in manual_entries), 4)
    pressure_active = bool(status.get("pressure_active"))
    visible_safe_entries = [item for item in safe_entries if float(item.get("size_gb") or 0.0) >= 0.05] or safe_entries
    visible_manual_entries = [
        item for item in manual_entries if float(item.get("size_gb") or 0.0) >= 0.05
    ] or manual_entries
    safe_label = ", ".join(
        f"{item.get('name')} {float(item.get('size_gb') or 0.0):.1f}GiB" for item in visible_safe_entries[:3]
    )
    manual_label = ", ".join(
        f"{item.get('name')} {float(item.get('size_gb') or 0.0):.1f}GiB" for item in visible_manual_entries[:3]
    )
    if not pressure_active:
        cleanup_action = "No local cleanup action needed."
    elif manual_entries and manual_entries[0] == annotated_entries[0]:
        cleanup_action = f"Review user storage manually: {manual_label}."
        if safe_entries:
            cleanup_action += f" Safe cache candidates: {safe_label}."
    elif safe_entries:
        cleanup_action = f"Review safe cache cleanup candidates: {safe_label}."
    elif manual_entries:
        cleanup_action = f"Review user storage manually: {manual_label}."
    else:
        cleanup_action = "Inspect local storage manually; no safe cleanup candidates found."

    if not pressure_active:
        cleanup_plan_state = "CLEAR"
        automation_ready = False
        automation_blocked_reason = ""
        cleanup_priority = "none"
    elif manual_entries and manual_entries[0] == annotated_entries[0]:
        cleanup_plan_state = "MANUAL_REVIEW_REQUIRED"
        automation_ready = False
        automation_blocked_reason = "manual_top_source"
        cleanup_priority = "manual_review"
    elif safe_entries:
        cleanup_plan_state = "SAFE_CACHE_REVIEW_READY"
        automation_ready = True
        automation_blocked_reason = ""
        cleanup_priority = "safe_cache"
    elif manual_entries:
        cleanup_plan_state = "MANUAL_REVIEW_REQUIRED"
        automation_ready = False
        automation_blocked_reason = "manual_candidates_present"
        cleanup_priority = "manual_review"
    else:
        cleanup_plan_state = "INSPECT_MANUALLY"
        automation_ready = False
        automation_blocked_reason = "no_safe_candidates"
        cleanup_priority = "inspect"

    status["top_entries"] = annotated_entries
    status["safe_cleanup_entries"] = safe_entries[:3]
    status["safe_cleanup_total_gb"] = safe_total_gb
    status["manual_review_entries"] = manual_entries[:3]
    status["manual_review_total_gb"] = manual_total_gb
    status["cleanup_action"] = cleanup_action
    status["cleanup_plan_state"] = cleanup_plan_state
    status["cleanup_priority"] = cleanup_priority
    status["cleanup_automation_ready"] = automation_ready
    status["cleanup_automation_blocked_reason"] = automation_blocked_reason
    return status


def validate_local_storage_pressure_sources(
    *,
    home_dir: str | Path | None = None,
    free_pct: float | None = None,
    scan_threshold_pct: float = DEFAULT_LOCAL_STORAGE_PRESSURE_SCAN_PCT,
    candidate_relpaths: tuple[str, ...] = DEFAULT_LOCAL_STORAGE_PRESSURE_CANDIDATES,
    top_limit: int = 5,
) -> dict[str, Any]:
    root = Path(home_dir) if home_dir is not None else Path.home()
    candidates: list[dict[str, Any]] = []
    missing_count = 0
    unreadable_entries: list[dict[str, str]] = []
    measurable_paths: list[tuple[str, Path]] = []
    for relpath in candidate_relpaths:
        rel = str(relpath).strip()
        if not rel:
            continue
        path = root / rel
        exists = path.exists() or path.is_symlink()
        if not exists:
            missing_count += 1
            continue
        measurable_paths.append((rel, path))

    if home_dir is not None:
        measured_sizes = [path_size_bytes(path) for _, path in measurable_paths]
    else:
        # Each production probe is already subprocess-bounded. Run the independent
        # probes together so several slow macOS-protected/cache directories cannot
        # add their timeout budgets serially to the watchdog heartbeat.
        with ThreadPoolExecutor(max_workers=min(4, max(1, len(measurable_paths)))) as executor:
            measured_sizes = list(executor.map(bounded_directory_size_bytes, (path for _, path in measurable_paths)))

    for (rel, path), size in zip(measurable_paths, measured_sizes):
        if size is None:
            unreadable_entries.append(
                {
                    "name": rel,
                    "path": str(path),
                    "reason": "timeout_or_unreadable",
                }
            )
            continue
        candidates.append(
            {
                "name": rel,
                "path": str(path),
                "size_bytes": size,
                "size_gb": round(size / (1024**3), 4),
                "is_dir": path.is_dir(),
                "is_symlink": path.is_symlink(),
            }
        )
    unreadable_count = len(unreadable_entries)
    candidates = sorted(candidates, key=lambda item: int(item.get("size_bytes") or 0), reverse=True)
    top_entries = candidates[: max(1, int(top_limit))]
    top_total_gb = round(sum(int(item.get("size_bytes") or 0) for item in top_entries) / (1024**3), 4)
    scanned_total_gb = round(sum(int(item.get("size_bytes") or 0) for item in candidates) / (1024**3), 4)
    pressure_active = free_pct is not None and float(free_pct) <= float(scan_threshold_pct)
    # This is an advisory inventory. Capacity severity belongs to validate_disk_space;
    # an individual directory timing out must not make the runtime core unavailable.
    status = "INFO"
    leaders = ", ".join(f"{item['name']} {float(item['size_gb']):.2f} GiB" for item in top_entries[:3])
    if leaders:
        detail = f"Local storage pressure sources: {leaders}"
    else:
        detail = "Local storage pressure source scan found no candidate data"
    if free_pct is not None:
        detail += f"; disk free {float(free_pct):.1f}%"
    if unreadable_count:
        unreadable_names = ", ".join(item["name"] for item in unreadable_entries[:3])
        detail += f"; unreadable {unreadable_count} ({unreadable_names})"
    result = check(
        "local_storage_pressure_sources",
        status,
        detail,
        path=str(root),
        free_pct=free_pct,
        scan_threshold_pct=float(scan_threshold_pct),
        pressure_active=pressure_active,
        candidate_count=len(candidates),
        missing_candidate_count=missing_count,
        unreadable_candidate_count=unreadable_count,
        unreadable_entries=unreadable_entries,
        measurement_complete=unreadable_count == 0,
        measurement_state="COMPLETE" if unreadable_count == 0 else "PARTIAL",
        scanned_total_gb=scanned_total_gb,
        top_total_gb=top_total_gb,
        top_entries=top_entries,
    )
    result = annotate_local_storage_cleanup_plan(result)
    if result.get("cleanup_action") and pressure_active:
        result["detail"] = f"{result.get('detail')}; action {result.get('cleanup_action')}"
    return result


def enrich_local_storage_pressure_with_maintenance(
    status: dict[str, Any],
    maintenance_payload: dict[str, Any] | None,
) -> dict[str, Any]:
    if not isinstance(maintenance_payload, dict) or not maintenance_payload:
        return status
    local_status = str(maintenance_payload.get("local_cache_cleanup_status") or "").upper()
    local_plan = str(maintenance_payload.get("local_cache_cleanup_plan_state") or "").upper()
    if local_status not in {"DONE", "DRY_RUN", "SKIPPED"}:
        return status
    if local_plan != "SAFE_CACHE_REVIEW_READY":
        return status
    try:
        fresh_protected_count = int(maintenance_payload.get("local_cache_cleanup_fresh_protected_count") or 0)
    except (TypeError, ValueError):
        fresh_protected_count = 0
    try:
        fresh_protected_mb = float(maintenance_payload.get("local_cache_cleanup_fresh_protected_mb") or 0.0)
    except (TypeError, ValueError):
        fresh_protected_mb = 0.0
    try:
        eligible_count = int(maintenance_payload.get("local_cache_cleanup_eligible_count") or 0)
    except (TypeError, ValueError):
        eligible_count = 0
    try:
        eligible_mb = float(maintenance_payload.get("local_cache_cleanup_eligible_mb") or 0.0)
    except (TypeError, ValueError):
        eligible_mb = 0.0
    if not (fresh_protected_count or eligible_count):
        return status
    status["cleanup_fresh_protected_count"] = fresh_protected_count
    status["cleanup_fresh_protected_mb"] = round(fresh_protected_mb, 3)
    status["cleanup_eligible_count"] = eligible_count
    status["cleanup_eligible_mb"] = round(eligible_mb, 3)
    detail = str(status.get("detail") or "Local storage pressure sources").rstrip()
    if detail.endswith("."):
        detail = detail[:-1]
    if fresh_protected_count and "fresh protected" not in detail:
        detail += f"; fresh protected {fresh_protected_count}/{fresh_protected_mb:.1f}MB under age policy"
    if eligible_count and "eligible safe cache" not in detail:
        detail += f"; eligible safe cache {eligible_count}/{eligible_mb:.1f}MB"
    status["detail"] = detail
    return status


def attach_local_storage_cache_refresh_fields(status: dict[str, Any]) -> dict[str, Any]:
    try:
        cache_age = float(status.get("cache_age_minutes"))
        cache_max_age = float(status.get("cache_max_age_minutes"))
    except (TypeError, ValueError):
        return status
    if cache_max_age <= 0:
        return status
    cache_refresh_margin = round(cache_max_age - cache_age, 4)
    cache_refresh_ratio = round(cache_refresh_margin / cache_max_age, 4)
    if cache_refresh_margin <= 0:
        pressure = "EXPIRED"
    elif cache_refresh_ratio <= 0.1:
        pressure = "DUE_SOON"
    else:
        pressure = "CLEAR"
    status["cache_refresh_margin_minutes"] = cache_refresh_margin
    status["cache_refresh_margin_ratio"] = cache_refresh_ratio
    status["cache_refresh_pressure"] = pressure
    return status


def local_storage_cache_refresh_detail(status: dict[str, Any]) -> str:
    pressure = str(status.get("cache_refresh_pressure") or "").upper()
    try:
        margin_minutes = float(status.get("cache_refresh_margin_minutes"))
        max_age_minutes = float(status.get("cache_max_age_minutes"))
    except (TypeError, ValueError):
        return ""
    if pressure == "EXPIRED":
        return f"refresh expired by {abs(margin_minutes):.1f}m/{max_age_minutes:.1f}m"
    if pressure == "DUE_SOON":
        return f"refresh due soon in {margin_minutes:.1f}m/{max_age_minutes:.1f}m"
    if pressure == "CLEAR":
        return f"refresh margin {margin_minutes:.1f}m/{max_age_minutes:.1f}m"
    return ""


def validate_cached_local_storage_pressure_sources(
    *,
    cache_path: str | Path = DEFAULT_LOCAL_STORAGE_PRESSURE_CACHE_PATH,
    cache_max_age_minutes: float = DEFAULT_LOCAL_STORAGE_PRESSURE_CACHE_MAX_AGE_MINUTES,
    maintenance_report_path: str | Path | None = None,
    now: datetime | None = None,
    **kwargs: Any,
) -> dict[str, Any]:
    path = Path(cache_path)
    payload, load_state = read_json_object_report(path, allow_empty=True)
    age_minutes = None
    cache_invalidated_by_maintenance = False
    maintenance_payload: dict[str, Any] | None = None
    if load_state.get("exists") and not load_state.get("malformed"):
        try:
            age_minutes = file_age_minutes(path, now=now)
        except OSError:
            age_minutes = None
        if maintenance_report_path is not None:
            loaded_maintenance_payload, maintenance_state = read_json_object_report(
                maintenance_report_path,
                allow_empty=True,
            )
            if maintenance_state.get("exists") and not maintenance_state.get("malformed"):
                maintenance_payload = loaded_maintenance_payload
                local_removed = int(maintenance_payload.get("local_cache_cleanup_removed_count") or 0)
                local_status = str(maintenance_payload.get("local_cache_cleanup_status") or "").upper()
                maintenance_generated_at = parse_utc_datetime(maintenance_payload.get("generated_at"))
                if local_removed > 0 and local_status == "DONE" and maintenance_generated_at is not None:
                    try:
                        cache_mtime = datetime.fromtimestamp(path.stat().st_mtime, tz=timezone.utc)
                    except OSError:
                        cache_mtime = None
                    cache_invalidated_by_maintenance = bool(
                        cache_mtime is not None and maintenance_generated_at >= cache_mtime
                    )
        cached_check = payload.get("check") if isinstance(payload.get("check"), dict) else {}
        if (
            cached_check
            and age_minutes is not None
            and age_minutes <= float(cache_max_age_minutes)
            and not cache_invalidated_by_maintenance
        ):
            cached = dict(cached_check)
            cached_unreadable = int(cached.get("unreadable_candidate_count") or 0)
            cached["status"] = "INFO"
            cached["measurement_complete"] = cached_unreadable == 0
            cached["measurement_state"] = "COMPLETE" if cached_unreadable == 0 else "PARTIAL"
            cached["cached"] = True
            cached["cache_path"] = str(path)
            cached["cache_age_minutes"] = round(age_minutes, 1)
            cached["cache_max_age_minutes"] = float(cache_max_age_minutes)
            if kwargs.get("free_pct") is not None:
                cached["free_pct"] = kwargs.get("free_pct")
                cached["pressure_active"] = float(kwargs.get("free_pct")) <= float(
                    cached.get("scan_threshold_pct") or DEFAULT_LOCAL_STORAGE_PRESSURE_SCAN_PCT
                )
            cached = annotate_local_storage_cleanup_plan(cached)
            cached = enrich_local_storage_pressure_with_maintenance(cached, maintenance_payload)
            cached = attach_local_storage_cache_refresh_fields(cached)
            cache_detail = local_storage_cache_refresh_detail(cached)
            cache_suffix = f"cached {age_minutes:.1f}m"
            if cache_detail:
                cache_suffix += f", {cache_detail}"
            cached["detail"] = f"{cached.get('detail', 'Local storage pressure sources')} ({cache_suffix})"
            return cached

    result = validate_local_storage_pressure_sources(**kwargs)
    result = enrich_local_storage_pressure_with_maintenance(result, maintenance_payload)
    result["cached"] = False
    result["cache_path"] = str(path)
    result["cache_age_minutes"] = 0.0
    result["cache_max_age_minutes"] = float(cache_max_age_minutes)
    result["cache_invalidated_by_maintenance"] = cache_invalidated_by_maintenance
    result = attach_local_storage_cache_refresh_fields(result)
    path.parent.mkdir(parents=True, exist_ok=True)
    try:
        path.write_text(
            json.dumps(
                {
                    "generated_at": (now or utc_now()).isoformat(),
                    "check": json_safe(result),
                },
                indent=2,
                sort_keys=True,
            )
        )
    except OSError as exc:
        result["cache_write_error"] = str(exc)
        result["status"] = status_max(str(result.get("status") or "INFO"), "WARN")
        result["detail"] = f"{result.get('detail', 'Local storage pressure sources')}; cache write failed"
    return result


def validate_external_disk(
    disk_path: str | Path,
    *,
    warn_free_gb: float = 100.0,
    fail_free_gb: float = 20.0,
    operational_report_path: str | Path | None = None,
    operational_max_age_hours: float = DEFAULT_RUNTIME_BACKUP_MAX_AGE_HOURS,
    now: datetime | None = None,
) -> dict[str, Any]:
    path = Path(disk_path)
    if not path.exists() or not path.is_dir():
        return check("external_disk", "FAIL", f"{path} is not mounted", path=str(path), mounted=False, writable=False)
    try:
        usage = shutil.disk_usage(path)
    except Exception as exc:
        return check(
            "external_disk", "FAIL", f"Cannot read {path}: {exc}", path=str(path), mounted=True, writable=False
        )

    test_file = path / f".roxy_write_test_{os.getpid()}_{int(datetime.now(timezone.utc).timestamp() * 1000)}"
    writable = False
    try:
        test_file.write_text("ok")
        writable = test_file.read_text() == "ok"
    except Exception:
        writable = False
    finally:
        try:
            if test_file.exists():
                test_file.unlink()
        except Exception:
            pass

    free_gb = usage.free / (1024**3)
    total_gb = usage.total / (1024**3)
    free_pct = (usage.free / usage.total * 100.0) if usage.total else 0.0
    operational_write_verified = False
    operational_age_hours = None
    operational_archive_path = ""
    if not writable and operational_report_path:
        payload = read_json(Path(operational_report_path))
        generated_at = parse_utc_datetime(payload.get("generated_at"))
        current = now or utc_now()
        if current.tzinfo is None:
            current = current.replace(tzinfo=timezone.utc)
        if generated_at is not None:
            operational_age_hours = max(0.0, (current - generated_at).total_seconds() / 3600.0)
        archive_value = str(payload.get("archive_path") or "")
        archive = Path(archive_value) if archive_value else None
        try:
            archive_on_disk = bool(
                archive
                and archive.exists()
                and archive.stat().st_size > 0
                and archive.resolve().is_relative_to(path.resolve())
            )
        except AttributeError:
            archive_on_disk = bool(
                archive
                and archive.exists()
                and archive.stat().st_size > 0
                and str(archive.resolve()).startswith(str(path.resolve()))
            )
        except Exception:
            archive_on_disk = False
        operational_write_verified = bool(
            archive_on_disk
            and operational_age_hours is not None
            and operational_age_hours <= operational_max_age_hours
            and str(payload.get("status") or "").upper() == "OK"
        )
        operational_archive_path = archive_value

    if not writable and not operational_write_verified:
        # macOS LaunchAgents can read a mounted volume while TCC denies only
        # ad-hoc writes. This is an auxiliary permission issue, not proof that
        # market data or the mounted archive is unavailable.
        status = "WARN"
    elif free_gb < fail_free_gb:
        status = "FAIL"
    elif free_gb < warn_free_gb:
        status = "WARN"
    else:
        status = "OK"
    detail = f"{path} mounted, {free_gb:.2f} GiB free ({free_pct:.1f}% of {total_gb:.0f} GiB)"
    if not writable:
        if operational_write_verified:
            detail = f"{path} mounted, backup write verified, {free_gb:.2f} GiB free"
        else:
            detail = f"{path} mounted but write permission is required for this process"
    return check(
        "external_disk",
        status,
        detail,
        path=str(path),
        mounted=True,
        writable=writable,
        permission_required=bool(not writable and not operational_write_verified),
        operational_write_verified=operational_write_verified,
        operational_age_hours=operational_age_hours,
        operational_archive_path=operational_archive_path,
        free_gb=free_gb,
        free_pct=free_pct,
        warn_free_gb=warn_free_gb,
        fail_free_gb=fail_free_gb,
    )


def path_size_bytes(path: Path) -> int | None:
    if not path.exists() and not path.is_symlink():
        return None
    if path.is_file() or path.is_symlink():
        try:
            return path.stat().st_size
        except OSError:
            return None
    total = 0
    try:
        for child in path.rglob("*"):
            try:
                if child.is_file() and not child.is_symlink():
                    total += child.stat().st_size
            except OSError:
                continue
    except OSError:
        return None
    return total


def bounded_directory_size_bytes(path: Path, *, timeout_seconds: float = 2.0) -> int | None:
    """Measure operator directories out of process so health checks cannot hang on I/O."""
    if not path.exists() and not path.is_symlink():
        return None
    if path.is_file() or path.is_symlink():
        return path_size_bytes(path)
    try:
        result = subprocess.run(
            ["du", "-sk", str(path)],
            capture_output=True,
            text=True,
            timeout=max(0.1, float(timeout_seconds)),
            check=False,
        )
    except (OSError, subprocess.TimeoutExpired):
        return None
    if result.returncode != 0:
        return None
    try:
        return int(result.stdout.split()[0]) * 1024
    except (IndexError, TypeError, ValueError):
        return None


def read_tail(path: Path, max_bytes: int = 6000) -> str:
    if not path.exists():
        return ""
    try:
        with path.open("rb") as fh:
            if path.stat().st_size > max_bytes:
                fh.seek(-max_bytes, os.SEEK_END)
            return fh.read().decode("utf-8", errors="replace")
    except OSError:
        return ""


def validate_local_training_media(
    media_path: str | Path,
    *,
    external_disk_path: str | Path = DEFAULT_EXTERNAL_DISK_PATH,
    warn_size_gb: float = DEFAULT_TRAINING_MEDIA_WARN_GB,
    fail_size_gb: float = DEFAULT_TRAINING_MEDIA_FAIL_GB,
) -> dict[str, Any]:
    path = Path(media_path)
    external_disk = Path(external_disk_path)
    external_suggestion = external_disk / "MacArchive" / Path.home().name / "roxy_trading" / path.name
    exists = path.exists() or path.is_symlink()
    is_symlink = path.is_symlink()
    symlink_target = resolve_symlink_target(path) if is_symlink else ""
    size_bytes = path_size_bytes(path) if exists and not is_symlink else None
    size_gb = (size_bytes or 0) / (1024**3)

    if not exists:
        status = "OK"
        state = "ABSENT"
        detail = f"{path.name} no esta presente localmente"
    elif is_symlink:
        status = "OK"
        state = "EXTERNAL_LINKED" if symlink_target.startswith(str(external_disk.resolve(strict=False))) else "LINKED"
        detail = f"{path.name} esta enlazado a {symlink_target}"
    elif size_gb >= fail_size_gb:
        status = "FAIL"
        state = "LOCAL_TOO_LARGE"
        detail = f"{path.name} ocupa {size_gb:.2f} GiB local; mover a {external_suggestion}"
    elif size_gb >= warn_size_gb:
        status = "WARN"
        state = "LOCAL_GROWING"
        detail = f"{path.name} ocupa {size_gb:.2f} GiB local; preparar migracion a {external_suggestion}"
    else:
        status = "OK"
        state = "LOCAL_SMALL"
        detail = f"{path.name} ocupa {size_gb:.2f} GiB local"

    return check(
        "local_training_media",
        status,
        detail,
        state=state,
        path=str(path),
        exists=exists,
        is_symlink=is_symlink,
        symlink_target=symlink_target,
        size_bytes=size_bytes,
        size_gb=round(size_gb, 4),
        warn_size_gb=warn_size_gb,
        fail_size_gb=fail_size_gb,
        external_suggestion=str(external_suggestion),
    )


PARTIAL_DOWNLOAD_MARKERS = (".download", ".crdownload", ".part", ".tmp")


def path_has_partial_download_marker(value: str) -> bool:
    if not value:
        return False
    for part in Path(str(value)).parts:
        lower = part.lower()
        if lower.endswith(PARTIAL_DOWNLOAD_MARKERS):
            return True
        if any(f"{marker}." in lower for marker in PARTIAL_DOWNLOAD_MARKERS):
            return True
    return False


def validate_video_learning_library(
    media_path: str | Path,
    *,
    unarchived_source_warn_gb: float = 1.0,
    video_ingest_active: bool = False,
    external_volume_root: str | Path = "/Volumes",
) -> dict[str, Any]:
    root = Path(media_path)
    index_path = root / "video_learning_index.json"
    sync_path = root / "ROXY_LEARNING_SYNC.md"
    if not root.exists():
        return check(
            "video_learning_library",
            "INFO",
            "Video learning library not initialized",
            path=str(root),
            exists=False,
            video_count=0,
        )
    if not index_path.exists():
        has_artifacts = any(root.iterdir()) if root.is_dir() else False
        status = "WARN" if has_artifacts else "INFO"
        detail = (
            "Video learning index missing while artifacts exist"
            if has_artifacts
            else "Video learning index not created yet"
        )
        return check(
            "video_learning_library",
            status,
            detail,
            path=str(root),
            exists=True,
            index_path=str(index_path),
            index_exists=False,
            sync_exists=sync_path.exists(),
            video_count=0,
        )

    index, load_state = read_json_object_report(index_path)
    if not index:
        malformed = bool(load_state.get("malformed"))
        return check(
            "video_learning_library",
            "FAIL" if malformed else "WARN",
            (
                f"Video learning index malformed: {load_state.get('detail')}"
                if malformed
                else "Video learning index empty"
            ),
            path=str(root),
            index_path=str(index_path),
            index_exists=True,
            index_malformed=malformed,
            payload_type=load_state.get("payload_type"),
            video_count=0,
        )

    videos = index.get("videos") if isinstance(index.get("videos"), list) else []
    materials = index.get("materials") if isinstance(index.get("materials"), list) else []
    updated_at = parse_utc_datetime(index.get("updated_at"))
    missing_target_dirs: list[str] = []
    missing_manifests: list[str] = []
    missing_notes: list[str] = []
    unarchived_sources: list[str] = []
    pending_archive_sources: list[str] = []
    externally_archived_sources: list[str] = []
    partial_source_refs: list[str] = []
    unarchived_source_bytes = 0
    pending_archive_source_bytes = 0
    topic_counter: Counter[str] = Counter()
    staging_root = root.parent / "data" / "video_ingest_staging"
    external_root = Path(external_volume_root).absolute()
    indexed_target_dirs = {
        str(item.get("target_dir") or "")
        for item in [*videos, *materials]
        if isinstance(item, dict) and str(item.get("target_dir") or "")
    }
    manifest_paths = sorted(root.glob("*/manifest.json"))
    indexable_manifest_paths: list[Path] = []
    partial_manifest_paths: list[str] = []
    for manifest_path in manifest_paths:
        manifest_payload, _manifest_state = read_json_object_report(manifest_path)
        source_value = ""
        if isinstance(manifest_payload, dict):
            source_value = str(manifest_payload.get("source_path") or "")
        if path_has_partial_download_marker(source_value):
            partial_manifest_paths.append(str(manifest_path))
            continue
        indexable_manifest_paths.append(manifest_path)
    unindexed_manifest_paths = [
        str(path) for path in indexable_manifest_paths if str(path.parent) not in indexed_target_dirs
    ]

    for item in videos:
        if not isinstance(item, dict):
            continue
        target_value = str(item.get("target_dir") or "")
        target_dir = Path(target_value) if target_value else None
        if target_dir is None or not target_dir.exists():
            missing_target_dirs.append(target_value or "-")
        elif not (target_dir / "manifest.json").exists():
            missing_manifests.append(str(target_dir / "manifest.json"))
        notes_value = str(item.get("notes_path") or "")
        notes_path = Path(notes_value) if notes_value else None
        if notes_path is None or not notes_path.exists() or path_size_bytes(notes_path) in {None, 0}:
            missing_notes.append(notes_value or "-")
        source_value = str(item.get("source_path") or "")
        if path_has_partial_download_marker(source_value):
            partial_source_refs.append(source_value)
        source_path = Path(source_value) if source_value else None
        archived_path = str(item.get("archived_path") or "")
        externally_hosted = bool(
            source_path is not None
            and source_path.absolute().is_relative_to(external_root)
        )
        if source_path is not None and not archived_path and externally_hosted:
            # The source already lives off the local disk. Do not touch a volume that may be offline.
            externally_archived_sources.append(str(source_path))
        elif source_path is not None and source_path.exists() and not archived_path:
            size = path_size_bytes(source_path) or 0
            try:
                in_active_staging = source_path.resolve().is_relative_to(staging_root.resolve())
            except OSError:
                in_active_staging = False
            if video_ingest_active and in_active_staging:
                pending_archive_sources.append(str(source_path))
                pending_archive_source_bytes += size
            else:
                unarchived_sources.append(str(source_path))
                unarchived_source_bytes += size
        for topic in item.get("topics") or []:
            topic_text = str(topic or "").strip()
            if topic_text:
                topic_counter[topic_text] += 1

    unarchived_source_gb = unarchived_source_bytes / (1024**3)
    pending_archive_source_gb = pending_archive_source_bytes / (1024**3)
    issues: list[str] = []
    if updated_at is None:
        issues.append("updated_at invalid")
    if videos and not sync_path.exists():
        issues.append("sync file missing")
    if missing_target_dirs:
        issues.append(f"missing target dirs {len(missing_target_dirs)}")
    if missing_manifests:
        issues.append(f"missing manifests {len(missing_manifests)}")
    if missing_notes:
        issues.append(f"missing notes {len(missing_notes)}")
    if unarchived_source_gb >= float(unarchived_source_warn_gb):
        issues.append(f"unarchived sources {unarchived_source_gb:.2f} GiB")
    if unindexed_manifest_paths and not video_ingest_active:
        issues.append(f"unindexed manifests {len(unindexed_manifest_paths)}")

    status = "WARN" if issues else "OK"
    top_topics = [topic for topic, _count in topic_counter.most_common(5)]
    detail = f"{len(videos)} video(s), topics {len(topic_counter)}"
    if sync_path.exists():
        detail += ", sync ok"
    if top_topics:
        detail += ", top " + "/".join(top_topics[:3])
    if unindexed_manifest_paths and video_ingest_active:
        detail += f", index pending {len(unindexed_manifest_paths)} manifest(s) while ingest active"
    if pending_archive_sources and video_ingest_active:
        detail += f", archive pending {pending_archive_source_gb:.2f} GiB while ingest active"
    if partial_manifest_paths:
        detail += f", partial manifests ignored {len(partial_manifest_paths)}"
    if partial_source_refs:
        detail += f", partial source refs {len(partial_source_refs)}"
    if issues:
        detail += "; " + "; ".join(issues)

    return check(
        "video_learning_library",
        status,
        detail,
        path=str(root),
        exists=True,
        index_path=str(index_path),
        index_exists=True,
        index_malformed=False,
        sync_path=str(sync_path),
        sync_exists=sync_path.exists(),
        updated_at=index.get("updated_at"),
        updated_at_valid=updated_at is not None,
        video_count=len(videos),
        material_count=len(materials),
        manifest_count=len(manifest_paths),
        indexable_manifest_count=len(indexable_manifest_paths),
        partial_manifest_count=len(partial_manifest_paths),
        partial_manifest_samples=partial_manifest_paths[:5],
        indexed_target_count=len(indexed_target_dirs),
        unindexed_manifest_count=len(unindexed_manifest_paths),
        unindexed_manifest_samples=unindexed_manifest_paths[:5],
        index_pending_due_to_active_ingest=bool(unindexed_manifest_paths and video_ingest_active),
        topic_count=len(topic_counter),
        top_topics=top_topics,
        missing_target_dir_count=len(missing_target_dirs),
        missing_manifest_count=len(missing_manifests),
        missing_note_count=len(missing_notes),
        unarchived_source_count=len(unarchived_sources),
        unarchived_source_gb=round(unarchived_source_gb, 4),
        unarchived_source_warn_gb=float(unarchived_source_warn_gb),
        pending_archive_source_count=len(pending_archive_sources),
        pending_archive_source_gb=round(pending_archive_source_gb, 4),
        archive_pending_due_to_active_ingest=bool(pending_archive_sources and video_ingest_active),
        externally_archived_source_count=len(externally_archived_sources),
        external_volume_root=str(external_root),
        partial_source_ref_count=len(partial_source_refs),
        partial_source_ref_samples=partial_source_refs[:5],
        issues=issues,
    )


def project_storage_entries(base_dir: str | Path, *, exclude_names: set[str] | None = None) -> list[dict[str, Any]]:
    root = Path(base_dir)
    excluded = exclude_names or {".git"}
    entries: list[dict[str, Any]] = []
    if not root.exists() or not root.is_dir():
        return entries
    for child in root.iterdir():
        if child.name in excluded:
            continue
        size = path_size_bytes(child)
        if size is None:
            continue
        entries.append(
            {
                "name": child.name,
                "path": str(child),
                "size_bytes": size,
                "size_gb": round(size / (1024**3), 4),
                "is_dir": child.is_dir(),
                "is_symlink": child.is_symlink(),
            }
        )
    return sorted(entries, key=lambda item: int(item.get("size_bytes") or 0), reverse=True)


def project_storage_top_entries(
    base_dir: str | Path, *, limit: int = 5, exclude_names: set[str] | None = None
) -> list[dict[str, Any]]:
    return project_storage_entries(base_dir, exclude_names=exclude_names)[: max(1, int(limit))]


def validate_project_storage_footprint(
    base_dir: str | Path,
    *,
    warn_size_gb: float = DEFAULT_PROJECT_STORAGE_WARN_GB,
    fail_size_gb: float = DEFAULT_PROJECT_STORAGE_FAIL_GB,
    top_limit: int = 5,
    video_ingest_active: bool = False,
    video_ingest_process_count: int = 0,
    video_ingest_archive_path: str | Path = DEFAULT_EXTERNAL_DISK_PATH / "RoxyVideosAnalizados",
) -> dict[str, Any]:
    root = Path(base_dir)
    entries = project_storage_entries(root)
    if root.exists() and root.is_dir():
        size_bytes = sum(int(item.get("size_bytes") or 0) for item in entries)
    else:
        size_bytes = path_size_bytes(root)
    if size_bytes is None:
        return check(
            "project_storage_footprint", "WARN", f"No se pudo medir {root}", path=str(root), exists=root.exists()
        )
    size_gb = size_bytes / (1024**3)
    if size_gb >= fail_size_gb:
        status = "FAIL"
    elif size_gb >= warn_size_gb:
        status = "WARN"
    else:
        status = "OK"
    top_entries = entries[: max(1, int(top_limit))]
    leaders = (
        ", ".join(f"{item['name']} {float(item['size_gb']):.2f} GiB" for item in top_entries[:3]) or "sin entradas"
    )
    video_staging_path = root / "data" / "video_ingest_staging"
    video_staging_size_bytes = path_size_bytes(video_staging_path) if video_staging_path.exists() else None
    video_staging_size_gb = (video_staging_size_bytes or 0) / (1024**3)
    non_staging_size_gb = max(0.0, size_gb - video_staging_size_gb)
    video_staging_archive_suggestion = Path(video_ingest_archive_path)
    state = "LOCAL_TOO_LARGE" if status == "FAIL" else "LOCAL_GROWING" if status == "WARN" else "LOCAL_OK"
    if (
        status == "FAIL"
        and bool(video_ingest_active)
        and video_staging_size_gb >= 1.0
        and non_staging_size_gb < float(fail_size_gb)
    ):
        status = "WARN"
        state = "VIDEO_INGEST_ACTIVE"
    elif (
        status == "WARN"
        and bool(video_ingest_active)
        and video_staging_size_gb >= 1.0
        and non_staging_size_gb < float(warn_size_gb)
    ):
        state = "VIDEO_INGEST_ACTIVE"
    staging_detail = ""
    if video_staging_size_gb >= 1.0:
        staging_detail = (
            f"; staging video {video_staging_path.relative_to(root)} {video_staging_size_gb:.2f} GiB"
            f" -> {video_staging_archive_suggestion}"
        )
        if video_ingest_active:
            staging_detail += f"; ingest active x{int(video_ingest_process_count or 0)}"
    return check(
        "project_storage_footprint",
        status,
        f"{root.name} ocupa {size_gb:.2f} GiB local; top: {leaders}{staging_detail}",
        path=str(root),
        state=state,
        size_bytes=size_bytes,
        size_gb=round(size_gb, 4),
        warn_size_gb=warn_size_gb,
        fail_size_gb=fail_size_gb,
        top_entries=top_entries,
        video_ingest_staging_path=str(video_staging_path),
        video_ingest_staging_exists=video_staging_path.exists(),
        video_ingest_staging_size_bytes=video_staging_size_bytes,
        video_ingest_staging_size_gb=round(video_staging_size_gb, 4),
        video_ingest_staging_non_staging_size_gb=round(non_staging_size_gb, 4),
        video_ingest_staging_archive_suggestion=str(video_staging_archive_suggestion),
        video_ingest_active=bool(video_ingest_active),
        video_ingest_process_count=int(video_ingest_process_count or 0),
    )


def validate_storage_migration(
    *,
    source_path: str | Path = DEFAULT_PARALLELS_SOURCE_PATH,
    destination_path: str | Path = DEFAULT_PARALLELS_DESTINATION_PATH,
    log_path: str | Path = DEFAULT_PARALLELS_MIGRATION_LOG_PATH,
    external_disk_path: str | Path = DEFAULT_EXTERNAL_DISK_PATH,
    now: datetime | None = None,
) -> dict[str, Any]:
    source = Path(source_path)
    destination = Path(destination_path)
    log = Path(log_path)
    external_disk = Path(external_disk_path)
    source_exists = source.exists() or source.is_symlink()
    destination_exists = destination.exists()
    source_is_symlink = source.is_symlink()
    source_broken_symlink = source_is_symlink and not source.exists()
    symlink_target = str(source.resolve()) if source_is_symlink and source_exists else ""
    source_size = path_size_bytes(source) if source_exists and not source_is_symlink else None
    destination_size = path_size_bytes(destination) if destination_exists else None
    log_tail = read_tail(log)
    log_age_minutes = file_age_minutes(log, now=now) if log.exists() else None
    waiting_for_parallels = "Parallels sigue corriendo" in log_tail
    completed = source_is_symlink and destination_exists and str(destination.resolve()) == symlink_target

    if not external_disk.exists():
        status = "FAIL"
        state = "EXTERNAL_MISSING"
        detail = f"{external_disk} no esta montado; no se puede completar la migracion"
    elif source_broken_symlink and not destination_exists:
        status = "WARN"
        state = "BROKEN_SYMLINK"
        detail = f"Parallels apunta a {destination}, pero el destino externo no existe"
    elif completed:
        status = "OK"
        state = "MIGRATED"
        detail = f"Parallels apunta al disco externo ({destination})"
    elif destination_exists and not source_exists:
        status = "INFO"
        state = "DESTINATION_ONLY"
        detail = f"Destino existe en {destination}, pero fuente local no esta como symlink"
    elif source_exists and destination_exists:
        status = "INFO"
        state = "COPY_PRESENT"
        detail = "Fuente local y destino externo existen; falta completar symlink/limpieza"
    elif source_exists and waiting_for_parallels:
        status = "INFO"
        state = "WAITING_FOR_PARALLELS"
        detail = "Migracion pendiente: Parallels sigue abierto; se movera al cerrar la app"
    elif source_exists:
        status = "INFO"
        state = "LOCAL_ONLY"
        detail = "Parallels sigue ocupando espacio local; migracion externa pendiente"
    elif not source_exists and not destination_exists:
        status = "OK"
        state = "NOT_PRESENT"
        detail = "No se encontro carpeta Parallels local para migrar"
    else:
        status = "INFO"
        state = "UNKNOWN"
        detail = "Estado de migracion Parallels no concluyente"

    return check(
        "storage_migration",
        status,
        detail,
        state=state,
        source_path=str(source),
        destination_path=str(destination),
        log_path=str(log),
        source_exists=source_exists,
        destination_exists=destination_exists,
        source_is_symlink=source_is_symlink,
        source_broken_symlink=source_broken_symlink,
        symlink_target=symlink_target,
        source_size_bytes=source_size,
        destination_size_bytes=destination_size,
        log_exists=log.exists(),
        log_age_minutes=log_age_minutes,
        waiting_for_parallels=waiting_for_parallels,
    )


def resolve_symlink_target(path: Path) -> str:
    if not path.is_symlink():
        return ""
    try:
        raw_target = Path(os.readlink(path))
    except OSError:
        return ""
    if not raw_target.is_absolute():
        raw_target = path.parent / raw_target
    return str(raw_target.resolve(strict=False))


def validate_runtime_cache_migration(
    *,
    source_path: str | Path = DEFAULT_RUNTIME_CACHE_SOURCE_PATH,
    destination_path: str | Path = DEFAULT_RUNTIME_CACHE_DESTINATION_PATH,
    external_disk_path: str | Path = DEFAULT_EXTERNAL_DISK_PATH,
) -> dict[str, Any]:
    source = Path(source_path)
    destination = Path(destination_path)
    external_disk = Path(external_disk_path)
    source_exists = source.exists() or source.is_symlink()
    destination_exists = destination.exists()
    source_is_symlink = source.is_symlink()
    source_broken_symlink = source_is_symlink and not source.exists()
    symlink_target = resolve_symlink_target(source)
    expected_target = str(destination.resolve(strict=False))
    completed = source_is_symlink and destination_exists and symlink_target == expected_target
    source_size = path_size_bytes(source) if source_exists and not source_is_symlink else None
    destination_size = path_size_bytes(destination) if destination_exists else None

    if not external_disk.exists():
        status = "FAIL"
        state = "EXTERNAL_MISSING"
        detail = f"{external_disk} no esta montado; cache runtime externa no disponible"
    elif source_broken_symlink and symlink_target == expected_target:
        status = "WARN"
        state = "BROKEN_SYMLINK"
        detail = f"Cache runtime apunta a {destination}, pero el destino externo no existe"
    elif completed:
        status = "OK"
        state = "MIGRATED"
        detail = f"Cache runtime Codex apunta al disco externo ({destination})"
    elif destination_exists and not source_exists:
        status = "INFO"
        state = "DESTINATION_ONLY"
        detail = f"Cache runtime existe en {destination}, pero la fuente local no esta enlazada"
    elif source_exists and destination_exists:
        status = "WARN"
        state = "COPY_PRESENT"
        detail = "Cache runtime existe local y externa; falta completar enlace/limpieza"
    elif source_exists:
        status = "WARN"
        state = "LOCAL_ONLY"
        detail = "Cache runtime sigue ocupando espacio local; migracion externa pendiente"
    else:
        status = "OK"
        state = "NOT_PRESENT"
        detail = "No se encontro cache runtime local para migrar"

    return check(
        "runtime_cache_migration",
        status,
        detail,
        state=state,
        source_path=str(source),
        destination_path=str(destination),
        external_disk_path=str(external_disk),
        source_exists=source_exists,
        destination_exists=destination_exists,
        source_is_symlink=source_is_symlink,
        source_broken_symlink=source_broken_symlink,
        symlink_target=symlink_target,
        expected_target=expected_target,
        source_size_bytes=source_size,
        destination_size_bytes=destination_size,
    )


def storage_migration_needs_recovery(report: dict[str, Any]) -> bool:
    item = named_check(report, "storage_migration")
    if not item:
        return True
    return str(item.get("state") or "").upper() == "BROKEN_SYMLINK"


def ensure_storage_migration_target(
    *,
    source_path: str | Path = DEFAULT_PARALLELS_SOURCE_PATH,
    destination_path: str | Path = DEFAULT_PARALLELS_DESTINATION_PATH,
    external_disk_path: str | Path = DEFAULT_EXTERNAL_DISK_PATH,
    log_path: str | Path = DEFAULT_PARALLELS_MIGRATION_LOG_PATH,
    now: datetime | None = None,
) -> dict[str, Any]:
    source = Path(source_path)
    destination = Path(destination_path)
    external_disk = Path(external_disk_path)
    log = Path(log_path)
    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    status = validate_storage_migration(
        source_path=source,
        destination_path=destination,
        log_path=log,
        external_disk_path=external_disk,
        now=current,
    )
    if str(status.get("state") or "").upper() != "BROKEN_SYMLINK":
        return {"action": "not_needed", "ok": True, "status": status}
    if not external_disk.exists():
        return {"action": "error", "ok": False, "error": f"{external_disk} is not mounted", "status": status}
    expected_target = str(destination.resolve(strict=False))
    symlink_target = str(status.get("symlink_target") or "")
    if symlink_target != expected_target:
        return {
            "action": "error",
            "ok": False,
            "error": "source symlink does not point to expected destination",
            "symlink_target": symlink_target,
            "expected_target": expected_target,
            "status": status,
        }
    try:
        destination.mkdir(parents=True, exist_ok=True)
        log.parent.mkdir(parents=True, exist_ok=True)
        with log.open("a") as handle:
            handle.write(f"{current.isoformat()} Recreated missing Parallels destination {destination}\n")
    except Exception as exc:
        return {"action": "error", "ok": False, "error": f"{type(exc).__name__}: {exc}", "status": status}
    after = validate_storage_migration(
        source_path=source,
        destination_path=destination,
        log_path=log,
        external_disk_path=external_disk,
        now=current,
    )
    return {
        "action": "created_missing_destination",
        "ok": str(after.get("status") or "").upper() == "OK",
        "destination_path": str(destination),
        "before": status,
        "after": after,
    }


def validate_live_service(required_timeframes: set[str]) -> dict[str, Any]:
    try:
        from tools import ma_live_launchd

        info = ma_live_launchd.status()
    except Exception as exc:
        return check("live_service_24h", "WARN", f"Could not inspect LaunchAgent: {exc}")

    command = str(info.get("command") or "")
    issues = []
    if not info.get("installed"):
        issues.append("not installed")
    if not info.get("loaded"):
        issues.append("not loaded")
    if not info.get("keep_alive"):
        issues.append("KeepAlive disabled")
    if not command_has_timeframes(command, "--stock-intervals", required_timeframes):
        issues.append("stock intervals missing 2h/4h")
    if not command_has_timeframes(command, "--crypto-timeframes", required_timeframes):
        issues.append("crypto timeframes missing 2h/4h")
    retention_count = command_option_int(command, "--retention-count")
    if retention_count is None:
        issues.append("retention missing")
    elif retention_count <= 0 or retention_count > 288:
        issues.append(f"retention count out of range: {retention_count}")
    embedded_health_check = command_has_flag(command, "--health-check")
    if embedded_health_check:
        issues.append("embedded health check duplicates watchdog")
    status = "OK" if not issues else "FAIL"
    detail = (
        "LaunchAgent live 24h loaded with full timeframes and retention; health checks owned by watchdog"
        if not issues
        else "; ".join(issues)
    )
    return check(
        "live_service_24h",
        status,
        detail,
        installed=bool(info.get("installed")),
        loaded=bool(info.get("loaded")),
        keep_alive=bool(info.get("keep_alive")),
        command=command,
        retention_count=retention_count,
        health_check=embedded_health_check,
        health_check_owner="watchdog",
    )


