def validate_output_maintenance_service() -> dict[str, Any]:
    try:
        from tools import output_maintenance_launchd

        info = output_maintenance_launchd.status()
    except Exception as exc:
        return check("output_maintenance_service", "WARN", f"Could not inspect output maintenance LaunchAgent: {exc}")

    command = str(info.get("command") or "")
    schedule = dict(info.get("schedule") or {})
    issues = []
    if not info.get("installed"):
        issues.append("not installed")
    if not info.get("loaded"):
        issues.append("not loaded")
    if "output_maintenance.py" not in command:
        issues.append("command does not run output_maintenance.py")
    local_cache_cleanup_enabled = command_has_flag(command, "--enable-local-cache-cleanup")
    if not local_cache_cleanup_enabled:
        issues.append("local cache cleanup disabled")
    partial_video_artifact_cleanup_enabled = not command_has_flag(command, "--no-partial-video-artifact-cleanup")
    if not partial_video_artifact_cleanup_enabled:
        issues.append("partial video artifact cleanup disabled")
    if "Hour" not in schedule or "Minute" not in schedule:
        issues.append("daily schedule missing")
    status = "OK" if not issues else "FAIL"
    detail = (
        "Output maintenance LaunchAgent loaded with daily schedule, local cache cleanup enabled, partial video cleanup enabled"
        if not issues
        else "; ".join(issues)
    )
    return check(
        "output_maintenance_service",
        status,
        detail,
        installed=bool(info.get("installed")),
        loaded=bool(info.get("loaded")),
        command=command,
        schedule=schedule,
        local_cache_cleanup_enabled=local_cache_cleanup_enabled,
        partial_video_artifact_cleanup_enabled=partial_video_artifact_cleanup_enabled,
    )


def validate_runtime_backup_service(*, now: datetime | None = None) -> dict[str, Any]:
    heartbeat_path = DEFAULT_RUNTIME_BACKUP_DAEMON_HEARTBEAT_PATH
    daemon_heartbeat, heartbeat_load_state = read_json_object_report(heartbeat_path)
    heartbeat_exists = bool(heartbeat_load_state.get("exists"))
    heartbeat_malformed = bool(heartbeat_load_state.get("malformed"))
    heartbeat_payload_type = heartbeat_load_state.get("payload_type")
    heartbeat_load_detail = str(heartbeat_load_state.get("detail") or "")
    daemon_generated_at = parse_utc_datetime(daemon_heartbeat.get("generated_at")) if daemon_heartbeat else None
    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    daemon_age_minutes = (
        max(0.0, (current - daemon_generated_at).total_seconds() / 60.0) if daemon_generated_at is not None else None
    )
    daemon_generated_at_future_minutes = (
        max(0.0, (daemon_generated_at - current).total_seconds() / 60.0) if daemon_generated_at is not None else None
    )
    daemon_running = bool(
        daemon_heartbeat
        and daemon_age_minutes is not None
        and daemon_age_minutes <= 15.0
        and (daemon_generated_at_future_minutes is None or daemon_generated_at_future_minutes <= 5.0)
        and pid_is_running(daemon_heartbeat.get("pid"))
        and str(daemon_heartbeat.get("status") or "").upper() in {"RUNNING", "DEGRADED"}
    )
    daemon_ok = bool(
        daemon_running and str(daemon_heartbeat.get("last_backup_status") or "").upper() in {"OK", "DRY_RUN"}
    )

    try:
        from tools import runtime_backup_launchd

        info = runtime_backup_launchd.status()
    except Exception as exc:
        if daemon_ok:
            return check(
                "runtime_backup_service",
                "OK",
                "Runtime backup daemon active; LaunchAgent inspection unavailable",
                daemon_heartbeat_path=str(heartbeat_path),
                daemon_heartbeat_exists=heartbeat_exists,
                daemon_heartbeat_malformed=heartbeat_malformed,
                daemon_heartbeat_payload_type=heartbeat_payload_type,
                daemon_heartbeat_load_detail=heartbeat_load_detail,
                daemon_running=daemon_running,
                daemon_age_minutes=daemon_age_minutes,
                daemon_generated_at_future_minutes=daemon_generated_at_future_minutes,
                daemon_pid=daemon_heartbeat.get("pid") if daemon_heartbeat else None,
                daemon_status=daemon_heartbeat.get("status") if daemon_heartbeat else None,
                daemon_last_backup_status=daemon_heartbeat.get("last_backup_status") if daemon_heartbeat else None,
                daemon_last_backup_at=daemon_heartbeat.get("last_backup_at") if daemon_heartbeat else None,
                daemon_next_backup_at=daemon_heartbeat.get("next_backup_at") if daemon_heartbeat else None,
            )
        if heartbeat_malformed:
            return check(
                "runtime_backup_service",
                "WARN",
                f"Runtime backup LaunchAgent inspection failed and daemon heartbeat malformed: {heartbeat_load_detail}; {exc}",
                daemon_heartbeat_path=str(heartbeat_path),
                daemon_heartbeat_exists=heartbeat_exists,
                daemon_heartbeat_malformed=heartbeat_malformed,
                daemon_heartbeat_payload_type=heartbeat_payload_type,
                daemon_heartbeat_load_detail=heartbeat_load_detail,
            )
        return check("runtime_backup_service", "WARN", f"Could not inspect runtime backup LaunchAgent: {exc}")

    command = str(info.get("command") or "")
    schedule = dict(info.get("schedule") or {})
    issues = []
    if not info.get("installed"):
        issues.append("not installed")
    if not info.get("loaded"):
        issues.append("not loaded")
    if "runtime_backup.py" not in command:
        issues.append("command does not run runtime_backup.py")
    if "Hour" not in schedule or "Minute" not in schedule:
        issues.append("daily schedule missing")
    launchd_ok = not issues
    base_status = "OK" if launchd_ok or daemon_ok else "FAIL"
    if daemon_generated_at_future_minutes is not None and daemon_generated_at_future_minutes > 15.0:
        heartbeat_status = "FAIL"
    elif daemon_generated_at_future_minutes is not None and daemon_generated_at_future_minutes > 5.0:
        heartbeat_status = "WARN"
    else:
        heartbeat_status = "WARN" if heartbeat_malformed else "OK"
    status = status_max(base_status, heartbeat_status)
    if daemon_ok and launchd_ok:
        detail = "Runtime backup LaunchAgent and daemon active"
    elif daemon_ok:
        detail = "Runtime backup daemon active; LaunchAgent not primary"
    elif launchd_ok:
        detail = "Runtime backup LaunchAgent loaded with daily schedule"
    else:
        detail = "; ".join(issues)
    if heartbeat_malformed:
        detail += f"; daemon heartbeat malformed: {heartbeat_load_detail}"
    if daemon_generated_at_future_minutes is not None and daemon_generated_at_future_minutes > 5.0:
        detail += f"; daemon heartbeat future {daemon_generated_at_future_minutes:.1f}m"
    return check(
        "runtime_backup_service",
        status,
        detail,
        installed=bool(info.get("installed")),
        loaded=bool(info.get("loaded")),
        command=command,
        schedule=schedule,
        daemon_heartbeat_path=str(heartbeat_path),
        daemon_heartbeat_exists=heartbeat_exists,
        daemon_heartbeat_malformed=heartbeat_malformed,
        daemon_heartbeat_payload_type=heartbeat_payload_type,
        daemon_heartbeat_load_detail=heartbeat_load_detail,
        daemon_running=daemon_running,
        daemon_age_minutes=daemon_age_minutes,
        daemon_generated_at_future_minutes=daemon_generated_at_future_minutes,
        daemon_pid=daemon_heartbeat.get("pid") if daemon_heartbeat else None,
        daemon_status=daemon_heartbeat.get("status") if daemon_heartbeat else None,
        daemon_last_backup_status=daemon_heartbeat.get("last_backup_status") if daemon_heartbeat else None,
        daemon_last_backup_at=daemon_heartbeat.get("last_backup_at") if daemon_heartbeat else None,
        daemon_next_backup_at=daemon_heartbeat.get("next_backup_at") if daemon_heartbeat else None,
    )


def status_max(*statuses: str) -> str:
    rank = {"OK": 0, "WARN": 1, "FAIL": 2}
    return max((status for status in statuses if status), key=lambda status: rank.get(status, 0), default="OK")


def current_output_maintenance_history_budget_snapshot(
    *,
    alerts_path: str | Path,
    max_history_lines: Any = None,
    max_history_bytes: Any = None,
) -> dict[str, Any]:
    try:
        from tools import output_maintenance

        effective_max_lines = int(max_history_lines or output_maintenance.DEFAULT_MAX_HISTORY_LINES)
        effective_max_bytes = (
            int(max_history_bytes)
            if max_history_bytes is not None
            else int(output_maintenance.DEFAULT_MAX_HISTORY_BYTES)
        )
        reports = output_maintenance.history_file_budget_reports(
            alerts_path=alerts_path,
            max_lines=effective_max_lines,
            max_bytes=effective_max_bytes,
            warn_ratio=output_maintenance.DEFAULT_HISTORY_BUDGET_WARN_RATIO,
        )
    except Exception as exc:
        return {
            "available": False,
            "error": f"{type(exc).__name__}: {exc}",
            "reports": [],
            "report_count": 0,
            "near_limit_count": 0,
            "over_limit_count": 0,
            "at_cap_count": 0,
            "status": "",
            "pressure": "",
            "attention_file_count": 0,
            "attention_files": [],
            "projected_near_limit_count": 0,
            "projected_over_limit_count": 0,
            "projected_attention_file_count": 0,
            "projected_attention_files": [],
            "projected_top": {},
            "top": {},
        }

    near_limit = [item for item in reports if item.get("status") == "NEAR_LIMIT"]
    over_limit = [item for item in reports if item.get("status") == "OVER_LIMIT"]
    at_cap = [item for item in reports if item.get("status") == "AT_CAP"]
    projected_near_limit = [
        item for item in reports if item.get("status") == "OK" and item.get("projected_next_status") == "NEAR_LIMIT"
    ]
    projected_over_limit = [
        item for item in reports if item.get("status") == "OK" and item.get("projected_next_status") == "OVER_LIMIT"
    ]
    attention_files = over_limit + at_cap + near_limit
    projected_attention_files = projected_over_limit + projected_near_limit
    if over_limit:
        status = "FAIL"
        pressure = "OVER_LIMIT"
    elif at_cap:
        status = "WARN"
        pressure = "AT_CAP"
    elif near_limit:
        status = "WARN"
        pressure = "NEAR_LIMIT"
    else:
        status = "OK"
        pressure = "CLEAR"
    top = max(
        attention_files,
        key=lambda item: max(float(item.get("line_ratio") or 0.0), float(item.get("byte_ratio") or 0.0)),
        default={},
    )
    projected_top = max(
        projected_attention_files,
        key=lambda item: max(
            float(item.get("projected_next_line_ratio") or 0.0),
            float(item.get("projected_next_byte_ratio") or 0.0),
        ),
        default={},
    )
    append_estimates: list[tuple[int, dict[str, Any]]] = []
    for item in reports:
        if not isinstance(item, dict):
            continue
        try:
            if item.get("estimated_appends_until_warn") is not None:
                append_estimates.append((int(item.get("estimated_appends_until_warn") or 0), item))
        except (TypeError, ValueError):
            pass
    min_append_estimate = None
    min_append_estimate_item: dict[str, Any] = {}
    if append_estimates:
        min_append_estimate, min_append_estimate_item = min(append_estimates, key=lambda entry: entry[0])
    return {
        "available": True,
        "reports": reports,
        "report_count": len(reports),
        "near_limit_count": len(near_limit),
        "over_limit_count": len(over_limit),
        "at_cap_count": len(at_cap),
        "status": status,
        "pressure": pressure,
        "attention_file_count": len(attention_files),
        "attention_files": attention_files,
        "top": top,
        "projected_near_limit_count": len(projected_near_limit),
        "projected_over_limit_count": len(projected_over_limit),
        "projected_attention_file_count": len(projected_attention_files),
        "projected_attention_files": projected_attention_files,
        "projected_top": projected_top,
        "min_estimated_appends_until_warn": min_append_estimate,
        "min_estimated_appends_until_warn_name": (
            str(min_append_estimate_item.get("name") or Path(str(min_append_estimate_item.get("path") or "")).name)
            if min_append_estimate_item
            else ""
        ),
        "min_estimated_appends_until_line_warn": (
            min_append_estimate_item.get("estimated_appends_until_line_warn") if min_append_estimate_item else None
        ),
        "min_estimated_appends_until_byte_warn": (
            min_append_estimate_item.get("estimated_appends_until_byte_warn") if min_append_estimate_item else None
        ),
        "max_history_lines": effective_max_lines,
        "max_history_bytes": effective_max_bytes,
    }


def validate_output_maintenance_report(
    report_path: Path,
    *,
    max_age_hours: float = 36.0,
    max_runtime_footprint_mb: float = 512.0,
    max_output_footprint_mb: float = 384.0,
    max_alerts_footprint_mb: float = 64.0,
    max_logs_footprint_mb: float = 64.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    payload, load_state = read_json_object_report(report_path)
    if not payload:
        exists = bool(load_state.get("exists"))
        malformed = bool(load_state.get("malformed"))
        detail = (
            f"Maintenance report malformed: {load_state.get('detail')}" if malformed else "Maintenance report not found"
        )
        return check(
            "output_maintenance_report",
            "WARN",
            detail,
            path=str(report_path),
            exists=exists,
            malformed=malformed,
            payload_type=load_state.get("payload_type"),
        )

    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check(
            "output_maintenance_report",
            "FAIL",
            "Maintenance report generated_at missing or invalid",
            path=str(report_path),
        )

    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    generated_at_future_minutes = max(0.0, (generated_at - current).total_seconds() / 60.0)
    age_hours = max(0.0, (current - generated_at).total_seconds() / 3600.0)
    if generated_at_future_minutes > float(max_age_hours) * 60.0:
        age_status = "FAIL"
    elif generated_at_future_minutes > 5.0:
        age_status = "WARN"
    elif age_hours <= max_age_hours:
        age_status = "OK"
    elif age_hours <= max_age_hours * 2:
        age_status = "WARN"
    else:
        age_status = "FAIL"

    output_value = str(payload.get("output_dir") or "")
    output_path = Path(output_value) if output_value else None
    output_exists = bool(output_path and output_path.exists())
    output_status = "OK" if output_exists else "FAIL"
    dry_run = bool(payload.get("dry_run"))
    dry_run_status = "WARN" if dry_run else "OK"
    output_archive_error_count = int(payload.get("output_archive_error_count", 0) or 0)
    archive_status = "WARN" if output_archive_error_count else "OK"
    output_archive_fallback = bool(payload.get("output_archive_fallback"))
    output_archive_requested_dir = str(payload.get("output_archive_requested_dir") or "")
    output_archive_effective_dir = str(
        payload.get("output_archive_effective_dir")
        or payload.get("output_archive_dir")
        or payload.get("archive_dir")
        or ""
    )
    output_archive_writable = bool(payload.get("output_archive_writable", True))
    log_snapshot_counts = (
        payload.get("log_snapshot_counts") if isinstance(payload.get("log_snapshot_counts"), dict) else {}
    )
    log_snapshot_scan_status = str(log_snapshot_counts.get("scan_status") or "OK").upper()
    log_snapshot_scan_errors = (
        log_snapshot_counts.get("scan_errors")
        if isinstance(log_snapshot_counts.get("scan_errors"), dict)
        else {}
    )
    sqlite_maintenance = (
        payload.get("sqlite_maintenance") if isinstance(payload.get("sqlite_maintenance"), dict) else {}
    )
    hygiene_summary = payload.get("hygiene_summary") if isinstance(payload.get("hygiene_summary"), dict) else {}
    operation_summary = payload.get("operation_summary") if isinstance(payload.get("operation_summary"), dict) else {}
    sqlite_status = str(sqlite_maintenance.get("status") or "") if sqlite_maintenance else ""
    hygiene_status = str(hygiene_summary.get("status") or "").upper()
    report_status_alias = str(payload.get("status") or "").upper()
    report_label_alias = str(payload.get("label") or "")
    report_tone_alias = str(payload.get("tone") or "")
    report_protected_alias = payload.get("protected")
    operation_status = str(operation_summary.get("status") or "").upper()
    operation_label = str(operation_summary.get("label") or "")
    operation_tone = str(operation_summary.get("tone") or "")
    operation_protected = operation_summary.get("protected") if operation_summary else None
    hygiene_issues = hygiene_summary.get("issues") if isinstance(hygiene_summary.get("issues"), list) else []
    normalized_hygiene_issues = {str(issue or "").strip().lower() for issue in hygiene_issues if str(issue).strip()}
    sqlite_status_check = "WARN" if sqlite_status == "ERROR" else "OK"
    hygiene_status_check = "FAIL" if hygiene_status == "FAIL" else "WARN" if hygiene_status == "WARN" else "OK"
    details = [f"age {age_hours:.1f}h"]
    if generated_at_future_minutes > 5.0:
        details.append(f"generated future {generated_at_future_minutes:.1f}m")
    if not output_exists:
        details.append("output_dir missing")
    if dry_run:
        details.append("last run was dry-run")
    removed_count = int(payload.get("removed_count", 0) or 0)
    output_archive_count = int(payload.get("output_archive_count", 0) or 0)
    stale_output_removed_count = int(payload.get("stale_output_removed_count", 0) or 0)
    trimmed_log_count = int(payload.get("trimmed_log_count", 0) or 0)
    trimmed_history_count = int(payload.get("trimmed_history_count", 0) or 0)
    trimmed_history_removed_lines = int(payload.get("trimmed_history_removed_lines", 0) or 0)
    trimmed_history_removed_bytes = int(payload.get("trimmed_history_removed_bytes", 0) or 0)
    trimmed_history_min_lines_relaxed_count = int(payload.get("trimmed_history_min_lines_relaxed_count") or 0)
    trimmed_history_min_lines_relaxed_files = (
        payload.get("trimmed_history_min_lines_relaxed_files")
        if isinstance(payload.get("trimmed_history_min_lines_relaxed_files"), list)
        else []
    )
    history_budget_reports = [item for item in (payload.get("history_budget_reports") or []) if isinstance(item, dict)]
    history_budget_report_count = int(payload.get("history_budget_report_count", len(history_budget_reports)) or 0)
