    def to_float(value: Any) -> float | None:
        try:
            return float(value)
        except (TypeError, ValueError):
            return None

    def current_history_budget_alias_mismatch(
        key: str,
        expected: Any,
        *,
        numeric: bool = False,
        tolerance: float = 0.0001,
    ) -> None:
        if key not in payload:
            return
        provided = payload.get(key)
        if numeric:
            try:
                provided_float = float(provided)
                expected_float = float(expected)
            except (TypeError, ValueError):
                if provided != expected:
                    contract_issues.append(f"{key} alias mismatch {provided!s} != {expected!s}")
                return
            if abs(provided_float - expected_float) > tolerance:
                contract_issues.append(f"{key} alias mismatch {provided!s} != {expected!s}")
            return
        if str(provided or "") != str(expected or ""):
            contract_issues.append(f"{key} alias mismatch {provided!s} != {expected!s}")

    def footprint_status(value: Any, limit: float, label: str) -> str:
        value_float = to_float(value)
        limit_float = max(0.0, float(limit))
        if value_float is None or limit_float <= 0:
            return "OK"
        if value_float > limit_float * 1.5:
            footprint_budget_issues.append(f"{label} {value_float:.1f}>{limit_float:.1f}MB hard")
            return "FAIL"
        if value_float > limit_float:
            footprint_budget_issues.append(f"{label} {value_float:.1f}>{limit_float:.1f}MB")
            return "WARN"
        return "OK"

