def runtime_backup_archive_names_with_retry(
    archive_path: str | Path,
    *,
    attempts: int = 2,
    retry_delay_seconds: float = 0.2,
) -> list[str]:
    last_error: Exception | None = None
    for attempt in range(max(1, int(attempts))):
        try:
            with tarfile.open(archive_path, "r:gz") as archive:
                return archive.getnames()
        except PermissionError as exc:
            last_error = exc
            if attempt + 1 >= max(1, int(attempts)):
                break
            time.sleep(max(0.0, float(retry_delay_seconds)))
        except Exception:
            raise
    if last_error is not None:
        raise last_error
    return []


def recent_runtime_backup_history_verification(
    history_path: str | Path,
    *,
    archive_path: str,
    archive_size_bytes: int,
    expected_paths: list[str],
    required_critical_members: list[str],
    requires_db_archive_member: bool,
    now: datetime,
    max_age_hours: float = 6.0,
) -> dict[str, Any]:
    path = Path(history_path)
    if not path.exists():
        return {}
    try:
        lines = path.read_text().splitlines()
    except OSError:
        return {}
    for raw_line in reversed(lines[-200:]):
        try:
            row = json.loads(raw_line)
        except json.JSONDecodeError:
            continue
        metrics = row.get("metrics") if isinstance(row.get("metrics"), dict) else {}
        if metrics.get("runtime_backup_archive_verified") is not True:
            continue
        recorded_path = str(metrics.get("runtime_backup_archive_path") or "")
        if recorded_path and archive_path and recorded_path != archive_path:
            continue
        try:
            recorded_size = int(metrics.get("runtime_backup_archive_size_bytes") or 0)
        except (TypeError, ValueError):
            recorded_size = 0
        if archive_size_bytes > 0 and recorded_size != archive_size_bytes:
            continue
        generated_at = parse_utc_datetime(row.get("generated_at"))
        if generated_at is None:
            continue
        age_hours = max(0.0, (now - generated_at).total_seconds() / 3600.0)
        if age_hours > float(max_age_hours):
            continue
        if int(metrics.get("runtime_backup_archive_missing_verified_path_count") or 0):
            continue
        if int(metrics.get("runtime_backup_archive_missing_critical_member_count") or 0):
            continue
        if requires_db_archive_member and metrics.get("runtime_backup_archive_database_member_verified") is not True:
            continue
        verified_member_count = int(metrics.get("runtime_backup_archive_verified_member_count") or 0)
        if verified_member_count < len(required_critical_members):
            continue
        return {
            "source": "health_history",
            "age_hours": round(age_hours, 3),
            "archive_member_count": int(metrics.get("runtime_backup_archive_member_count") or 0),
            "archive_verified_paths": list(expected_paths),
            "archive_verified_members": list(required_critical_members),
            "archive_database_member_verified": True,
            "recorded_at": generated_at.isoformat(),
            "recorded_path": recorded_path,
        }
    return {}


def validate_runtime_backup_report(
    report_path: Path,
    *,
    max_age_hours: float = DEFAULT_RUNTIME_BACKUP_MAX_AGE_HOURS,
    health_history_path: str | Path | None = None,
    now: datetime | None = None,
) -> dict[str, Any]:
    payload, load_state = read_json_object_report(report_path)
    if not payload:
        exists = bool(load_state.get("exists"))
        malformed = bool(load_state.get("malformed"))
        detail = (
            f"Runtime backup report malformed: {load_state.get('detail')}"
            if malformed
            else "Runtime backup report not found"
        )
        return check(
            "runtime_backup_report",
            "WARN",
            detail,
            path=str(report_path),
            exists=exists,
            malformed=malformed,
            payload_type=load_state.get("payload_type"),
        )

    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check(
            "runtime_backup_report", "FAIL", "Runtime backup generated_at missing or invalid", path=str(report_path)
        )

    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    generated_at_future_minutes = max(0.0, (generated_at - current).total_seconds() / 60.0)
    age_hours = max(0.0, (current - generated_at).total_seconds() / 3600.0)
    if generated_at_future_minutes > float(max_age_hours) * 60.0:
        age_status = "FAIL"
    elif generated_at_future_minutes > 5.0:
        age_status = "WARN"
    elif age_hours <= max_age_hours:
        age_status = "OK"
    elif age_hours <= max_age_hours * 2:
        age_status = "WARN"
    else:
        age_status = "FAIL"

    archive_value = str(payload.get("archive_path") or "")
    archive_path = Path(archive_value) if archive_value else None
    archive_exists = bool(archive_path and archive_path.exists())
    archive_size_bytes = int(payload.get("archive_size_bytes") or 0)
    if archive_exists and archive_path:
        try:
            archive_size_bytes = archive_path.stat().st_size
        except OSError:
            archive_exists = False
            archive_size_bytes = 0
    dry_run = bool(payload.get("dry_run"))
    archive_status = "OK" if dry_run or (archive_exists and archive_size_bytes > 0) else "FAIL"
    dry_run_status = "WARN" if dry_run else "OK"
    payload_status = str(payload.get("status") or "OK").upper()
    if payload_status not in {"OK", "DRY_RUN"}:
        report_status = "FAIL"
    else:
        report_status = "WARN" if payload_status == "DRY_RUN" else "OK"

    expected_paths = [
        str(value).strip().strip("/")
        for value in (payload.get("include_paths") or DEFAULT_RUNTIME_BACKUP_REQUIRED_PATHS)
        if str(value).strip()
    ]
    expected_path_set = set(expected_paths)
    required_critical_members: list[str] = []
    if "alerts" in expected_path_set:
        required_critical_members.extend(DEFAULT_RUNTIME_BACKUP_REQUIRED_ALERT_MEMBERS)
    if "db" in expected_path_set:
        required_critical_members.extend(DEFAULT_RUNTIME_BACKUP_REQUIRED_DB_MEMBERS)
    requires_db_archive_member = "db" in expected_path_set
    archive_readable = bool(payload.get("archive_readable"))
    reported_archive_readable = archive_readable
    reported_archive_verified = bool(payload.get("archive_verified"))
    archive_member_count = int(payload.get("archive_member_count") or 0)
    archive_verified_paths = [str(value) for value in (payload.get("archive_verified_paths") or [])]
    archive_missing_verified_paths = [str(value) for value in (payload.get("archive_missing_verified_paths") or [])]
    archive_verified_members = [
        str(value).strip().strip("/") for value in (payload.get("archive_verified_members") or []) if str(value).strip()
    ]
    archive_missing_critical_members = [
        str(value).strip().strip("/")
        for value in (payload.get("archive_missing_critical_members") or [])
        if str(value).strip()
    ]
    archive_database_member_verified = bool(payload.get("archive_database_member_verified"))
    archive_verification_error = str(payload.get("archive_verification_error") or "")
    archive_verification_source = "report" if reported_archive_verified else "runtime"
    archive_history_verification: dict[str, Any] = {}
    if archive_exists and archive_path and not dry_run:
        try:
            names = runtime_backup_archive_names_with_retry(archive_path)
            normalized_names = {str(name).strip().strip("/") for name in names if str(name).strip()}
            archive_readable = True
            archive_member_count = len(names)
            archive_verified_paths = [
                expected_path
                for expected_path in expected_paths
                if any(name == expected_path or name.startswith(f"{expected_path}/") for name in normalized_names)
            ]
            archive_missing_verified_paths = [
                path for path in expected_paths if path not in set(archive_verified_paths)
            ]
            archive_verified_members = [member for member in required_critical_members if member in normalized_names]
            archive_missing_critical_members = [
                member for member in required_critical_members if member not in set(archive_verified_members)
            ]
            archive_database_member_verified = not requires_db_archive_member or any(
                name.startswith("db/") and Path(name).suffix.lower() in {".db", ".sqlite", ".sqlite3"}
                for name in normalized_names
            )
            if requires_db_archive_member and not archive_database_member_verified:
                archive_missing_critical_members.append("db/*.db")
            archive_verification_error = ""
            archive_verification_source = "runtime"
        except Exception as exc:
            error = f"{type(exc).__name__}: {exc}"
            reported_verified_set = {str(value) for value in archive_verified_paths}
            expected_set = set(expected_paths)
            reported_verified_member_set = {str(value).strip().strip("/") for value in archive_verified_members}
            required_critical_set = set(required_critical_members)
            can_trust_report_verification = (
                isinstance(exc, PermissionError)
                and reported_archive_readable
                and reported_archive_verified
                and expected_set.issubset(reported_verified_set)
                and required_critical_set.issubset(reported_verified_member_set)
                and (not requires_db_archive_member or archive_database_member_verified)
                and not archive_missing_verified_paths
                and not archive_missing_critical_members
                and archive_size_bytes > 0
            )
            if can_trust_report_verification:
                archive_verification_error = error
                archive_verification_source = "report"
            else:
                history_verification = (
                    recent_runtime_backup_history_verification(
                        health_history_path or report_path.parent / DEFAULT_HEALTH_HISTORY_PATH.name,
                        archive_path=archive_value,
                        archive_size_bytes=archive_size_bytes,
                        expected_paths=expected_paths,
                        required_critical_members=required_critical_members,
                        requires_db_archive_member=requires_db_archive_member,
                        now=current,
                    )
                    if isinstance(exc, PermissionError)
                    else {}
                )
                if history_verification:
                    archive_readable = True
                    archive_member_count = int(history_verification.get("archive_member_count") or 0)
                    archive_verified_paths = list(history_verification.get("archive_verified_paths") or expected_paths)
                    archive_missing_verified_paths = []
                    archive_verified_members = list(
                        history_verification.get("archive_verified_members") or required_critical_members
                    )
                    archive_missing_critical_members = []
                    archive_database_member_verified = bool(
                        history_verification.get("archive_database_member_verified")
                    )
                    archive_verification_error = error
                    archive_verification_source = "health_history"
                    archive_history_verification = history_verification
                else:
                    archive_readable = False
                    archive_member_count = 0
                    archive_verified_paths = []
                    archive_missing_verified_paths = expected_paths
                    archive_verified_members = []
                    archive_missing_critical_members = list(required_critical_members)
                    if requires_db_archive_member:
                        archive_missing_critical_members.append("db/*.db")
                    archive_database_member_verified = not requires_db_archive_member
                    archive_verification_error = error
                    archive_verification_source = "runtime"
    archive_verified = bool(
        dry_run
        or (
            archive_readable
            and not archive_missing_verified_paths
            and not archive_missing_critical_members
            and (not requires_db_archive_member or archive_database_member_verified)
        )
    )
    verification_status = "OK" if dry_run or archive_verified else "FAIL"
    status = status_max(age_status, archive_status, dry_run_status, report_status, verification_status)

    details = [f"age {age_hours:.1f}h"]
    if generated_at_future_minutes > 5.0:
        details.append(f"generated future {generated_at_future_minutes:.1f}m")
    if archive_exists:
        details.append(f"archive {archive_size_bytes} bytes")
    else:
        details.append("archive missing")
    if archive_verified:
        details.append(f"verified {len(archive_verified_paths)}/{len(expected_paths)}")
        if required_critical_members or requires_db_archive_member:
            critical_total = len(required_critical_members) + (1 if requires_db_archive_member else 0)
            critical_verified = len(archive_verified_members) + (
                1 if archive_database_member_verified and requires_db_archive_member else 0
            )
            details.append(f"critical {critical_verified}/{critical_total}")
    elif not dry_run:
        details.append("archive not verified")
    if archive_missing_critical_members:
        details.append("missing critical " + ",".join(archive_missing_critical_members))
    removed_count = int(payload.get("removed_count", 0) or 0)
    details.append(f"removed {removed_count}")
    if dry_run:
        details.append("dry-run")

    return check(
        "runtime_backup_report",
        status,
        ", ".join(details),
        path=str(report_path),
        generated_at=generated_at.isoformat(),
        age_hours=age_hours,
        generated_at_future_minutes=round(generated_at_future_minutes, 1),
        max_age_hours=max_age_hours,
        archive_path=archive_value,
        archive_exists=archive_exists,
        archive_size_bytes=archive_size_bytes,
        target_dir=str(payload.get("target_dir") or ""),
        malformed=False,
        dry_run=dry_run,
        removed_count=removed_count,
        archive_readable=archive_readable,
        archive_verified=archive_verified,
        archive_member_count=archive_member_count,
        archive_verified_paths=archive_verified_paths,
        archive_missing_verified_paths=archive_missing_verified_paths,
        archive_verified_members=archive_verified_members,
        archive_missing_critical_members=archive_missing_critical_members,
        archive_database_member_verified=archive_database_member_verified,
        archive_verification_error=archive_verification_error,
        archive_verification_source=archive_verification_source,
        archive_history_verification=archive_history_verification,
    )


def validate_launchd_recovery_report(
    report_path: str | Path = DEFAULT_LAUNCHD_RECOVERY_REPORT_PATH,
    *,
    max_age_minutes: float = 30.0,
    expected_services: tuple[str, ...] | list[str] = EXPECTED_LAUNCHD_RECOVERY_SERVICES,
    now: datetime | None = None,
) -> dict[str, Any]:
    path = Path(report_path)
    payload, load_state = read_json_object_report(path)
    if not load_state.get("exists"):
        return check(
            "launchd_recovery_report",
            "INFO",
            "Launchd recovery report not generated yet",
            path=str(path),
            exists=False,
        )
    if load_state.get("malformed"):
        return check(
            "launchd_recovery_report",
            "FAIL",
            f"Launchd recovery report malformed: {load_state.get('detail')}",
            path=str(path),
            exists=True,
            malformed=True,
            load_detail=load_state.get("detail"),
        )

    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check(
            "launchd_recovery_report",
            "FAIL",
            "Launchd recovery report generated_at missing or invalid",
            path=str(path),
            exists=True,
            malformed=False,
        )

    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    generated_at_future_minutes = max(0.0, (generated_at - current).total_seconds() / 60.0)
    age_minutes = max(0.0, (current - generated_at).total_seconds() / 60.0)
    recovered = payload.get("recovered") if isinstance(payload.get("recovered"), list) else []
    failed = payload.get("failed") if isinstance(payload.get("failed"), list) else []
    services = payload.get("services") if isinstance(payload.get("services"), dict) else {}
    expected_service_names = [str(name) for name in expected_services if str(name).strip()]
    missing_expected_services = [name for name in expected_service_names if name not in services]
    unhealthy_expected_services = [
        name
        for name in expected_service_names
        if name in services and not bool((services.get(name) if isinstance(services.get(name), dict) else {}).get("ok"))
    ]
    service_count = int(payload.get("service_count") or 0)
    report_status = str(payload.get("status") or "").upper()

    issues: list[str] = []
    status = "OK"
    if generated_at_future_minutes > float(max_age_minutes):
        status = "FAIL"
        issues.append(f"generated future {generated_at_future_minutes:.1f}m")
    elif generated_at_future_minutes > 5.0:
        status = "WARN"
        issues.append(f"generated future {generated_at_future_minutes:.1f}m")
    if age_minutes > float(max_age_minutes):
        status = "WARN" if status == "OK" else status
        issues.append(f"stale {age_minutes:.1f}m")
    if report_status == "WARN" or failed:
        status = "WARN" if status == "OK" else status
        issues.append(f"failed services {', '.join(str(item) for item in failed) or '-'}")
    elif report_status != "OK":
        status = "WARN" if status == "OK" else status
        issues.append(f"status {report_status or '-'}")
    if missing_expected_services:
        status = "WARN" if status == "OK" else status
        issues.append(f"missing services {', '.join(missing_expected_services)}")
    if unhealthy_expected_services:
        status = "WARN" if status == "OK" else status
        issues.append(f"unhealthy services {', '.join(unhealthy_expected_services)}")
    if service_count <= 0:
        status = "WARN" if status == "OK" else status
        issues.append("service count missing")
    elif expected_service_names and service_count < len(expected_service_names):
        status = "WARN" if status == "OK" else status
        issues.append(f"service count {service_count}/{len(expected_service_names)}")

    detail = (
        f"Launchd recovery OK for {service_count} service(s), recovered {len(recovered)}"
        if status == "OK"
        else "Launchd recovery report " + "; ".join(issues)
    )
    return check(
        "launchd_recovery_report",
        status,
        detail,
        path=str(path),
        exists=True,
        malformed=False,
        generated_at=generated_at.isoformat(),
        age_minutes=round(age_minutes, 1),
        generated_at_future_minutes=round(generated_at_future_minutes, 1),
        report_status=report_status,
        service_count=service_count,
        expected_services=expected_service_names,
        missing_expected_services=missing_expected_services,
        missing_expected_service_count=len(missing_expected_services),
        unhealthy_expected_services=unhealthy_expected_services,
        unhealthy_expected_service_count=len(unhealthy_expected_services),
        recovered=recovered,
        recovered_count=len(recovered),
        failed=failed,
        failed_count=len(failed),
    )


def validate_price_alert_monitor_report(
    report_path: str | Path,
    *,
    max_age_minutes: float = 3.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    path = Path(report_path)
    payload, load_state = read_json_object_report(path)
    if not load_state.get("exists"):
        return check("price_alert_monitor", "FAIL", "Price alert monitor report missing", path=str(path))
    if load_state.get("malformed"):
        return check(
            "price_alert_monitor", "FAIL", f"Price alert monitor report malformed: {load_state.get('detail')}", path=str(path)
        )
    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check("price_alert_monitor", "FAIL", "Price alert monitor generated_at invalid", path=str(path))
    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    age_minutes = max(0.0, (current - generated_at).total_seconds() / 60.0)
    contract = str(payload.get("contract_version") or "")
    report_status = str(payload.get("status") or "UNKNOWN").upper()
    issues: list[str] = []
    status = "OK"
    if contract != "roxy-durable-alert-monitor/2.0.0":
        status = "FAIL"
        issues.append(f"contract {contract or '-'}")
    if age_minutes > float(max_age_minutes):
        status = "FAIL"
        issues.append(f"stale {age_minutes:.1f}m")
    if report_status == "WARNING" and status == "OK":
        status = "WARN"
        issues.append("provider gate blocked one or more rules")
    elif report_status not in {"OK", "NO_DATA", "WARNING"}:
        status = "FAIL"
        issues.append(f"status {report_status}")
    active = int(payload.get("active_alerts") or 0)
    evaluated = int(payload.get("evaluated") or 0)
    blocked = int(payload.get("blocked") or 0)
    triggered = int(payload.get("triggered") or 0)
    expired = int(payload.get("expired") or 0)
    pending = int(payload.get("notification_pending") or 0)
    delivery_failures = int(payload.get("permanent_delivery_failures") or 0)
    detail = (
        f"Durable price/EMA/volume alert monitor {report_status}, age {age_minutes:.1f}m, active {active}, "
        f"evaluated {evaluated}, blocked {blocked}, triggered {triggered}, expired {expired}, "
        f"delivery pending {pending}, permanent delivery failures {delivery_failures}"
    )
    if issues:
        detail += "; " + "; ".join(issues)
    return check(
        "price_alert_monitor",
        status,
        detail,
        path=str(path),
        contract_version=contract,
        report_status=report_status,
        age_minutes=round(age_minutes, 1),
        active_alert_count=active,
        evaluated_count=evaluated,
        blocked_count=blocked,
        expired_count=expired,
        notification_pending_count=pending,
        permanent_delivery_failure_count=delivery_failures,
        triggered_count=triggered,
        notification_count=int(payload.get("notifications") or 0),
        provider_states=payload.get("provider_states") if isinstance(payload.get("provider_states"), dict) else {},
    )


def validate_opportunity_sync_report(
    report_path: str | Path,
    *,
    max_age_minutes: float = 15.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    path = Path(report_path)
    payload, load_state = read_json_object_report(path)
    if not load_state.get("exists"):
        return check("opportunity_sync", "FAIL", "Opportunity sync report missing", path=str(path))
    if load_state.get("malformed"):
        return check("opportunity_sync", "FAIL", f"Opportunity sync report malformed: {load_state.get('detail')}", path=str(path))
    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check("opportunity_sync", "FAIL", "Opportunity sync generated_at invalid", path=str(path))
    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    age_minutes = max(0.0, (current - generated_at).total_seconds() / 60.0)
    contract = str(payload.get("contract_version") or payload.get("contract") or "")
    report_status = str(payload.get("status") or "UNKNOWN").upper()
    issues: list[str] = []
    status = "OK"
    if contract != "roxy-opportunity-sync/1.0.0":
        status = "FAIL"
        issues.append(f"contract {contract or '-'}")
    if age_minutes > max_age_minutes:
        status = "FAIL"
        issues.append(f"stale {age_minutes:.1f}m")
    if report_status == "WARNING" and status == "OK":
        status = "WARN"
        issues.append("source degraded; last known list preserved")
    elif report_status not in {"OK", "WARNING"}:
        status = "FAIL"
        issues.append(f"status {report_status}")
    users = payload.get("users") if isinstance(payload.get("users"), dict) else {}
    detail = (
        f"Opportunity sync {report_status}, age {age_minutes:.1f}m, candidates "
        f"{int(payload.get('candidate_count') or 0)}, ready {int(payload.get('trade_ready_count') or 0)}, users {len(users)}"
    )
    if issues:
        detail += "; " + "; ".join(issues)
    return check(
        "opportunity_sync",
        status,
        detail,
        path=str(path),
        contract_version=contract,
        report_status=report_status,
        age_minutes=round(age_minutes, 1),
        candidate_count=int(payload.get("candidate_count") or 0),
        trade_ready_count=int(payload.get("trade_ready_count") or 0),
        user_count=len(users),
        source_healthy=bool(payload.get("source_healthy")),
    )


def validate_opportunity_lifecycle_report(
    report_path: str | Path,
    brief_path: str | Path,
    *,
    max_age_minutes: float = 15.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    path = Path(report_path)
    payload, load_state = read_json_object_report(path)
    if not load_state.get("exists"):
        return check("opportunity_lifecycle", "FAIL", "Opportunity lifecycle report missing", path=str(path))
    if load_state.get("malformed"):
        return check(
            "opportunity_lifecycle",
            "FAIL",
            f"Opportunity lifecycle report malformed: {load_state.get('detail')}",
            path=str(path),
        )
    updated_at = parse_utc_datetime(payload.get("updated_at"))
    if updated_at is None:
        return check("opportunity_lifecycle", "FAIL", "Opportunity lifecycle updated_at invalid", path=str(path))
    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    age_minutes = max(0.0, (current - updated_at).total_seconds() / 60.0)
    contract = str(payload.get("contract") or "")
    events = payload.get("archived_opportunities")
    issues: list[str] = []
    if contract != "roxy-opportunity-lifecycle/1.0.0":
        issues.append(f"contract {contract or '-'}")
    if age_minutes > max_age_minutes:
        issues.append(f"stale {age_minutes:.1f}m")
    if not isinstance(events, list):
        issues.append("archived_opportunities is not a list")
        events = []
    symbols: list[str] = []
    for index, event in enumerate(events):
        if not isinstance(event, dict):
            issues.append(f"event {index} is not an object")
            continue
        symbol = str(event.get("symbol") or "").strip().upper()
        if not symbol or symbol == "-":
            issues.append(f"event {index} missing symbol")
            continue
        symbols.append(symbol)
        if str(event.get("status") or "") != "Invalidada":
            issues.append(f"{symbol} status is not Invalidada")
        if str(event.get("reactivation_policy") or "") != "FRESH_ALERT_READY":
            issues.append(f"{symbol} reactivation policy invalid")
        if not parse_utc_datetime(event.get("archived_at")):
            issues.append(f"{symbol} archived_at invalid")
    duplicate_symbols = sorted({symbol for symbol in symbols if symbols.count(symbol) > 1})
    if duplicate_symbols:
        issues.append("duplicate archived symbols " + ",".join(duplicate_symbols))

    brief_payload, brief_state = read_json_object_report(Path(brief_path))
    active_symbols: set[str] = set()
    if brief_state.get("malformed") or not brief_state.get("exists"):
        issues.append("active brief unavailable")
    else:
        active_symbols = {
            str(row.get("symbol") or "").strip().upper()
            for row in brief_payload.get("opportunities", [])
            if isinstance(row, dict) and str(row.get("symbol") or "").strip()
        }
    overlap = sorted(set(symbols) & active_symbols)
    if overlap:
        issues.append("archived symbols still active " + ",".join(overlap))
    status = "FAIL" if issues else "OK"
    detail = (
        f"Opportunity lifecycle {contract or '-'}, age {age_minutes:.1f}m, archived {len(symbols)}, "
        f"active overlap {len(overlap)}"
    )
    if issues:
        detail += "; " + "; ".join(issues)
    return check(
        "opportunity_lifecycle",
        status,
        detail,
        path=str(path),
        contract_version=contract,
        age_minutes=round(age_minutes, 1),
        archived_count=len(symbols),
        duplicate_symbol_count=len(duplicate_symbols),
        active_overlap_count=len(overlap),
        active_overlap_symbols=overlap,
    )


def validate_chart_health_report(
    report_path: Path,
    *,
    max_age_minutes: float = 30.0,
    required_symbols: list[str] | None = None,
    now: datetime | None = None,
) -> dict[str, Any]:
    payload, load_state = read_json_object_report(report_path)
    if not payload:
        exists = bool(load_state.get("exists"))
        malformed = bool(load_state.get("malformed"))
        detail = (
            f"Chart realtime report malformed: {load_state.get('detail')}"
            if malformed
            else "Chart realtime report not found"
        )
        return check(
            "chart_realtime_health_report",
            "WARN",
            detail,
            path=str(report_path),
            exists=exists,
            malformed=malformed,
            payload_type=load_state.get("payload_type"),
        )

    generated_at = parse_utc_datetime(payload.get("generated_at"))
    if generated_at is None:
        return check(
            "chart_realtime_health_report",
            "FAIL",
            "Chart realtime report generated_at missing or invalid",
            path=str(report_path),
            exists=True,
            malformed=False,
        )

    current = now or utc_now()
    if current.tzinfo is None:
        current = current.replace(tzinfo=timezone.utc)
    generated_at_future_minutes = max(0.0, (generated_at - current).total_seconds() / 60.0)
    age_minutes = max(0.0, (current - generated_at).total_seconds() / 60.0)
    if generated_at_future_minutes > float(max_age_minutes):
        age_status = "FAIL"
    elif generated_at_future_minutes > 5.0:
        age_status = "WARN"
    else:
        age_status = (
            "OK" if age_minutes <= max_age_minutes else "WARN" if age_minutes <= max_age_minutes * 3 else "FAIL"
        )
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    summary_status = str(summary.get("status") or "WARN").upper()
    if summary_status not in {"OK", "WARN", "FAIL"}:
        summary_status = "WARN"
    status = status_max(age_status, summary_status)
    checked_count = int(summary.get("checked_count", 0) or 0)
    fail_count = int(summary.get("fail_count", 0) or 0)
    warn_count = int(summary.get("warn_count", 0) or 0)
    checked_alias = payload.get("checked")
    max_chart_age_alias = payload.get("max_chart_age_minutes")
    operable_max_chart_age_alias = payload.get("operable_max_chart_age_minutes")
    next_candle_alias = payload.get("next_candle_minutes")
    operable_next_candle_alias = payload.get("operable_next_candle_minutes")
    min_freshness_margin_alias = payload.get("min_freshness_margin_minutes")
    min_freshness_margin_ratio_alias = payload.get("min_freshness_margin_ratio")
    min_freshness_budget_alias = payload.get("min_freshness_budget_minutes")
    operable_min_freshness_margin_alias = payload.get("operable_min_freshness_margin_minutes")
    operable_min_freshness_margin_ratio_alias = payload.get("operable_min_freshness_margin_ratio")
    operable_min_freshness_budget_alias = payload.get("operable_min_freshness_budget_minutes")
    operable_freshness_margin_state_alias = payload.get("operable_freshness_margin_state")
    operable_freshness_margin_warn_threshold_alias = payload.get("operable_freshness_margin_warn_threshold_minutes")
    min_freshness_margin_chart_alias = (
        payload.get("min_freshness_margin_chart") if isinstance(payload.get("min_freshness_margin_chart"), dict) else {}
    )
    operable_min_freshness_margin_chart_alias = (
        payload.get("operable_min_freshness_margin_chart")
        if isinstance(payload.get("operable_min_freshness_margin_chart"), dict)
        else {}
    )
    market_closed_ok_count = int(summary.get("market_closed_ok_count", 0) or 0)
    operable_checked_count = int(summary.get("operable_checked_count", 0) or 0)
    max_chart_age_minutes = summary.get("max_age_minutes")
    operable_max_chart_age_minutes = summary.get("operable_max_age_minutes")
    avg_chart_age_minutes = summary.get("avg_age_minutes")
    operable_avg_chart_age_minutes = summary.get("operable_avg_age_minutes")
    max_cadence_lag_minutes = summary.get("max_cadence_lag_minutes")
    operable_max_cadence_lag_minutes = summary.get("operable_max_cadence_lag_minutes")
    max_health_lag_minutes = summary.get("max_health_lag_minutes")
    operable_max_health_lag_minutes = summary.get("operable_max_health_lag_minutes")
    next_expected_update_in_minutes = summary.get("next_expected_update_in_minutes")
    operable_next_expected_update_in_minutes = summary.get("operable_next_expected_update_in_minutes")
    stalest_chart = summary.get("stalest_chart") if isinstance(summary.get("stalest_chart"), dict) else {}
    operable_stalest_chart = (
        summary.get("operable_stalest_chart") if isinstance(summary.get("operable_stalest_chart"), dict) else {}
    )
    most_overdue_chart = (
        summary.get("most_overdue_chart") if isinstance(summary.get("most_overdue_chart"), dict) else {}
    )
    operable_most_overdue_chart = (
        summary.get("operable_most_overdue_chart")
        if isinstance(summary.get("operable_most_overdue_chart"), dict)
        else {}
    )
    charts = payload.get("charts") if isinstance(payload.get("charts"), list) else []
    try:
        from chart_health import normalize_chart_symbol

        required_chart_symbols = [
            symbol for symbol in (normalize_chart_symbol(value) for value in (required_symbols or [])) if symbol
        ]
        required_chart_symbols = list(dict.fromkeys(required_chart_symbols))
        covered_chart_symbols = sorted(
            {
                normalize_chart_symbol(row.get("symbol"))
                for row in charts
                if isinstance(row, dict) and normalize_chart_symbol(row.get("symbol"))
            }
        )
    except Exception:
        required_chart_symbols = []
        covered_chart_symbols = []
    missing_required_chart_symbols = [
        symbol for symbol in required_chart_symbols if symbol not in set(covered_chart_symbols)
    ]
    freshness_margin_rows: list[dict[str, Any]] = []
    for row in charts:
        if not isinstance(row, dict):
            continue
        try:
            row_age = float(row.get("age_minutes"))
            row_budget = float(row.get("freshness_budget_minutes"))
        except (TypeError, ValueError):
            continue
        if row_budget <= 0:
            continue
        margin = row_budget - row_age
        freshness_margin_rows.append(
            {
                "symbol": row.get("symbol"),
                "timeframe": row.get("timeframe"),
                "market": row.get("market"),
                "age_minutes": round(row_age, 1),
                "freshness_budget_minutes": round(row_budget, 1),
                "margin_minutes": round(margin, 1),
                "margin_ratio": round(margin / row_budget, 4),
                "market_closed_accepted": bool(row.get("market_closed_accepted")),
            }
        )
    min_freshness_margin_chart = (
        min(freshness_margin_rows, key=lambda row: float(row.get("margin_minutes") or 0.0))
        if freshness_margin_rows
        else {}
    )
    operable_freshness_margin_rows = [
        row for row in freshness_margin_rows if not bool(row.get("market_closed_accepted"))
    ]
    operable_min_freshness_margin_chart = (
        min(operable_freshness_margin_rows, key=lambda row: float(row.get("margin_minutes") or 0.0))
        if operable_freshness_margin_rows
        else {}
    )
    operable_min_freshness_margin_minutes = operable_min_freshness_margin_chart.get("margin_minutes")
    operable_min_freshness_budget_minutes = operable_min_freshness_margin_chart.get("freshness_budget_minutes")
    operable_margin_state, operable_margin_warn_threshold_minutes = chart_freshness_margin_state(
        float(operable_min_freshness_margin_minutes) if operable_min_freshness_margin_minutes is not None else None,
        float(operable_min_freshness_budget_minutes) if operable_min_freshness_budget_minutes is not None else None,
    )
    if missing_required_chart_symbols:
        status = status_max(status, "WARN")
    contract_issues: list[str] = []

    def numeric_alias_mismatch(alias_value: Any, expected_value: Any) -> bool:
        if expected_value is None:
            return alias_value is not None
        try:
            return abs(float(alias_value) - float(expected_value)) > 0.001
        except (TypeError, ValueError):
            return True

    def chart_alias_mismatch(alias_value: dict[str, Any], expected_value: dict[str, Any]) -> bool:
        if not expected_value:
            return bool(alias_value)
        if not alias_value:
            return True
        for key in ("symbol", "timeframe", "market"):
            expected = expected_value.get(key)
            if expected is None:
                continue
            if str(alias_value.get(key) or "") != str(expected or ""):
                return True
        return False

    if checked_alias is None:
        contract_issues.append("checked alias missing")
    elif numeric_alias_mismatch(checked_alias, checked_count):
        contract_issues.append(f"checked alias mismatch {checked_alias} != {checked_count}")
    if max_chart_age_alias is None and max_chart_age_minutes is not None:
        contract_issues.append("max chart age alias missing")
    elif max_chart_age_alias is not None and numeric_alias_mismatch(max_chart_age_alias, max_chart_age_minutes):
        contract_issues.append(f"max chart age alias mismatch {max_chart_age_alias} != {max_chart_age_minutes}")
    if operable_max_chart_age_alias is None and operable_max_chart_age_minutes is not None:
        contract_issues.append("operable max chart age alias missing")
    elif operable_max_chart_age_alias is not None and numeric_alias_mismatch(
        operable_max_chart_age_alias, operable_max_chart_age_minutes
    ):
        contract_issues.append(
            f"operable max chart age alias mismatch {operable_max_chart_age_alias} != {operable_max_chart_age_minutes}"
        )
    if next_candle_alias is None and next_expected_update_in_minutes is not None:
        contract_issues.append("next candle alias missing")
    elif next_candle_alias is not None and numeric_alias_mismatch(next_candle_alias, next_expected_update_in_minutes):
        contract_issues.append(f"next candle alias mismatch {next_candle_alias} != {next_expected_update_in_minutes}")
    if operable_next_candle_alias is None and operable_next_expected_update_in_minutes is not None:
        contract_issues.append("operable next candle alias missing")
    elif operable_next_candle_alias is not None and numeric_alias_mismatch(
        operable_next_candle_alias, operable_next_expected_update_in_minutes
    ):
        contract_issues.append(
            f"operable next candle alias mismatch {operable_next_candle_alias} != {operable_next_expected_update_in_minutes}"
        )
    if min_freshness_margin_alias is None and min_freshness_margin_chart.get("margin_minutes") is not None:
        contract_issues.append("min freshness margin alias missing")
    elif min_freshness_margin_alias is not None and numeric_alias_mismatch(
        min_freshness_margin_alias, min_freshness_margin_chart.get("margin_minutes")
    ):
        contract_issues.append(
            f"min freshness margin alias mismatch {min_freshness_margin_alias} != {min_freshness_margin_chart.get('margin_minutes')}"
        )
    if min_freshness_margin_ratio_alias is None and min_freshness_margin_chart.get("margin_ratio") is not None:
        contract_issues.append("min freshness margin ratio alias missing")
    elif min_freshness_margin_ratio_alias is not None and numeric_alias_mismatch(
        min_freshness_margin_ratio_alias, min_freshness_margin_chart.get("margin_ratio")
    ):
        contract_issues.append(
            "min freshness margin ratio alias mismatch "
            f"{min_freshness_margin_ratio_alias} != {min_freshness_margin_chart.get('margin_ratio')}"
        )
    if min_freshness_budget_alias is None and min_freshness_margin_chart.get("freshness_budget_minutes") is not None:
        contract_issues.append("min freshness budget alias missing")
    elif min_freshness_budget_alias is not None and numeric_alias_mismatch(
        min_freshness_budget_alias, min_freshness_margin_chart.get("freshness_budget_minutes")
    ):
        contract_issues.append(
            f"min freshness budget alias mismatch {min_freshness_budget_alias} != {min_freshness_margin_chart.get('freshness_budget_minutes')}"
        )
    if chart_alias_mismatch(min_freshness_margin_chart_alias, min_freshness_margin_chart):
        contract_issues.append("min freshness margin chart alias mismatch")
    if operable_min_freshness_margin_alias is None and operable_min_freshness_margin_minutes is not None:
        contract_issues.append("operable min freshness margin alias missing")
    elif operable_min_freshness_margin_alias is not None and numeric_alias_mismatch(
        operable_min_freshness_margin_alias, operable_min_freshness_margin_minutes
    ):
        contract_issues.append(
            "operable min freshness margin alias mismatch "
            f"{operable_min_freshness_margin_alias} != {operable_min_freshness_margin_minutes}"
        )
    if (
        operable_min_freshness_margin_ratio_alias is None
        and operable_min_freshness_margin_chart.get("margin_ratio") is not None
    ):
        contract_issues.append("operable min freshness margin ratio alias missing")
    elif operable_min_freshness_margin_ratio_alias is not None and numeric_alias_mismatch(
        operable_min_freshness_margin_ratio_alias,
        operable_min_freshness_margin_chart.get("margin_ratio"),
    ):
        contract_issues.append(
            "operable min freshness margin ratio alias mismatch "
            f"{operable_min_freshness_margin_ratio_alias} != {operable_min_freshness_margin_chart.get('margin_ratio')}"
        )
    if operable_min_freshness_budget_alias is None and operable_min_freshness_budget_minutes is not None:
        contract_issues.append("operable min freshness budget alias missing")
    elif operable_min_freshness_budget_alias is not None and numeric_alias_mismatch(
        operable_min_freshness_budget_alias, operable_min_freshness_budget_minutes
    ):
        contract_issues.append(
            "operable min freshness budget alias mismatch "
            f"{operable_min_freshness_budget_alias} != {operable_min_freshness_budget_minutes}"
        )
    if operable_min_freshness_margin_minutes is not None:
        if operable_freshness_margin_state_alias is None:
            contract_issues.append("operable freshness margin state alias missing")
        elif str(operable_freshness_margin_state_alias or "").upper() != str(operable_margin_state or "").upper():
            contract_issues.append(
                "operable freshness margin state alias mismatch "
                f"{operable_freshness_margin_state_alias} != {operable_margin_state}"
            )
        if (
            operable_freshness_margin_warn_threshold_alias is None
            and operable_margin_warn_threshold_minutes is not None
        ):
            contract_issues.append("operable freshness margin warn threshold alias missing")
        elif operable_freshness_margin_warn_threshold_alias is not None and numeric_alias_mismatch(
            operable_freshness_margin_warn_threshold_alias,
            operable_margin_warn_threshold_minutes,
        ):
            contract_issues.append(
                "operable freshness margin warn threshold alias mismatch "
                f"{operable_freshness_margin_warn_threshold_alias} != {operable_margin_warn_threshold_minutes}"
            )
    if chart_alias_mismatch(
        operable_min_freshness_margin_chart_alias,
        operable_min_freshness_margin_chart,
    ):
        contract_issues.append("operable min freshness margin chart alias mismatch")
    if contract_issues:
        status = status_max(status, "WARN")
    details = [f"age {age_minutes:.0f}m", f"checked {checked_count}", f"fail {fail_count}", f"warn {warn_count}"]
    if generated_at_future_minutes > 5.0:
        details.append(f"generated future {generated_at_future_minutes:.1f}m")
    if missing_required_chart_symbols:
        details.append("missing active charts " + "/".join(missing_required_chart_symbols[:5]))
    if contract_issues:
        details.append("contract " + "; ".join(contract_issues))
    if market_closed_ok_count:
        details.append(f"market closed ok {market_closed_ok_count}")
    if operable_checked_count:
        details.append(f"operable {operable_checked_count}")
    if max_chart_age_minutes is not None:
        details.append(f"max chart age {float(max_chart_age_minutes):.1f}m")
    if operable_max_chart_age_minutes is not None:
        details.append(f"operable max {float(operable_max_chart_age_minutes):.1f}m")
    if operable_min_freshness_margin_minutes is not None:
        details.append(
            "operable freshness margin "
            f"{float(operable_min_freshness_margin_minutes):.1f}m {operable_margin_state.lower()}"
        )
    if max_cadence_lag_minutes is not None and float(max_cadence_lag_minutes) > 0:
        details.append(f"cadence lag {float(max_cadence_lag_minutes):.1f}m")
    elif next_expected_update_in_minutes is not None:
        details.append(f"next candle {float(next_expected_update_in_minutes):.1f}m")
    if operable_max_cadence_lag_minutes is not None and float(operable_max_cadence_lag_minutes) > 0:
        details.append(f"operable lag {float(operable_max_cadence_lag_minutes):.1f}m")
    elif operable_next_expected_update_in_minutes is not None:
        details.append(f"operable next {float(operable_next_expected_update_in_minutes):.1f}m")
    if max_health_lag_minutes is not None and float(max_health_lag_minutes) > 0:
        details.append(f"health lag {float(max_health_lag_minutes):.1f}m")
    if stalest_chart:
        details.append(f"stalest {stalest_chart.get('symbol', '-')} {stalest_chart.get('timeframe', '-')}")
    if operable_stalest_chart:
        details.append(
            f"operable stalest {operable_stalest_chart.get('symbol', '-')} {operable_stalest_chart.get('timeframe', '-')}"
        )
    if most_overdue_chart and max_cadence_lag_minutes is not None and float(max_cadence_lag_minutes) > 0:
        details.append(f"overdue {most_overdue_chart.get('symbol', '-')} {most_overdue_chart.get('timeframe', '-')}")
    if (
        operable_most_overdue_chart
        and operable_max_cadence_lag_minutes is not None
        and float(operable_max_cadence_lag_minutes) > 0
    ):
        details.append(
            "operable overdue "
            f"{operable_most_overdue_chart.get('symbol', '-')} {operable_most_overdue_chart.get('timeframe', '-')}"
        )
    return check(
        "chart_realtime_health_report",
        status,
        ", ".join(details),
        path=str(report_path),
        exists=True,
        malformed=False,
        generated_at=generated_at.isoformat(),
        age_minutes=age_minutes,
        generated_at_future_minutes=round(generated_at_future_minutes, 1),
        checked_count=checked_count,
        checked_alias=checked_alias,
        fail_count=fail_count,
        warn_count=warn_count,
        market_closed_ok_count=market_closed_ok_count,
        operable_checked_count=operable_checked_count,
        max_chart_age_minutes=max_chart_age_minutes,
        max_chart_age_alias=max_chart_age_alias,
        avg_chart_age_minutes=avg_chart_age_minutes,
        operable_max_chart_age_minutes=operable_max_chart_age_minutes,
        operable_max_chart_age_alias=operable_max_chart_age_alias,
        operable_avg_chart_age_minutes=operable_avg_chart_age_minutes,
        max_cadence_lag_minutes=max_cadence_lag_minutes,
        operable_max_cadence_lag_minutes=operable_max_cadence_lag_minutes,
        max_health_lag_minutes=max_health_lag_minutes,
        operable_max_health_lag_minutes=operable_max_health_lag_minutes,
        min_freshness_margin_minutes=min_freshness_margin_chart.get("margin_minutes"),
        min_freshness_margin_alias=min_freshness_margin_alias,
        min_freshness_margin_ratio=min_freshness_margin_chart.get("margin_ratio"),
        min_freshness_margin_ratio_alias=min_freshness_margin_ratio_alias,
        min_freshness_budget_minutes=min_freshness_margin_chart.get("freshness_budget_minutes"),
        min_freshness_budget_alias=min_freshness_budget_alias,
        min_freshness_margin_chart=min_freshness_margin_chart,
        min_freshness_margin_chart_alias=min_freshness_margin_chart_alias,
        operable_min_freshness_margin_minutes=operable_min_freshness_margin_minutes,
        operable_min_freshness_margin_alias=operable_min_freshness_margin_alias,
        operable_min_freshness_margin_ratio=operable_min_freshness_margin_chart.get("margin_ratio"),
        operable_min_freshness_margin_ratio_alias=operable_min_freshness_margin_ratio_alias,
        operable_min_freshness_budget_minutes=operable_min_freshness_budget_minutes,
        operable_min_freshness_budget_alias=operable_min_freshness_budget_alias,
        operable_freshness_margin_warn_threshold_minutes=operable_margin_warn_threshold_minutes,
        operable_freshness_margin_warn_threshold_alias=operable_freshness_margin_warn_threshold_alias,
        operable_freshness_margin_state=operable_margin_state,
        operable_freshness_margin_state_alias=operable_freshness_margin_state_alias,
        operable_min_freshness_margin_chart=operable_min_freshness_margin_chart,
        operable_min_freshness_margin_chart_alias=operable_min_freshness_margin_chart_alias,
        next_expected_update_in_minutes=next_expected_update_in_minutes,
        next_candle_alias=next_candle_alias,
        operable_next_expected_update_in_minutes=operable_next_expected_update_in_minutes,
        operable_next_candle_alias=operable_next_candle_alias,
        chart_health_contract_issues=contract_issues,
        stalest_chart=stalest_chart,
        operable_stalest_chart=operable_stalest_chart,
        most_overdue_chart=most_overdue_chart,
        operable_most_overdue_chart=operable_most_overdue_chart,
        required_chart_symbols=required_chart_symbols,
        covered_chart_symbols=covered_chart_symbols,
        missing_required_chart_symbols=missing_required_chart_symbols,
        missing_required_chart_symbol_count=len(missing_required_chart_symbols),
    )


def evaluate_realtime_health(
    *,
    base_dir: Path = BASE_DIR,
    max_age_minutes: float = 10.0,
    maintenance_max_age_hours: float = 36.0,
    required_timeframes: set[str] | None = None,
    app_url: str = "",
    chart_symbol: str | None = None,
    chart_timeframe: str = "1h",
    skip_chart_fetch: bool = False,
    skip_service_check: bool = False,
    warn_free_gb: float = 1.0,
    fail_free_gb: float = 0.25,
    running_warn_minutes: float = 15.0,
    running_fail_minutes: float = 30.0,
    external_disk_path: str | Path | None = None,
    external_warn_free_gb: float = 100.0,
    external_fail_free_gb: float = 20.0,
    storage_migration_source_path: str | Path | None = None,
    storage_migration_destination_path: str | Path | None = None,
    storage_migration_log_path: str | Path | None = None,
    runtime_cache_source_path: str | Path | None = None,
    runtime_cache_destination_path: str | Path | None = None,
    training_media_path: str | Path | None = None,
    training_media_warn_gb: float = DEFAULT_TRAINING_MEDIA_WARN_GB,
    training_media_fail_gb: float = DEFAULT_TRAINING_MEDIA_FAIL_GB,
    project_storage_warn_gb: float = DEFAULT_PROJECT_STORAGE_WARN_GB,
    project_storage_fail_gb: float = DEFAULT_PROJECT_STORAGE_FAIL_GB,
    health_history_path: str | Path | None = None,
    health_history_max_entries: int = DEFAULT_HEALTH_HISTORY_MAX_ENTRIES,
    health_history_max_bytes: int | None = DEFAULT_HEALTH_HISTORY_MAX_BYTES,
    health_history_max_age_minutes: float = 90.0,
    lock_status_path: str | Path | None = None,
    lock_status_max_acquired_minutes: float = 30.0,
    now: datetime | None = None,
) -> dict[str, Any]:
    required_timeframes = required_timeframes or {"15m", "1h", "2h", "4h"}
    custom_base_dir = Path(base_dir).resolve(strict=False) != BASE_DIR.resolve(strict=False)
    output_path, alerts_path = runtime_dirs(base_dir)
    isolated_runtime_dirs = custom_base_dir or (
        output_path.resolve(strict=False) != (BASE_DIR / "output").resolve(strict=False)
        or alerts_path.resolve(strict=False) != (BASE_DIR / "alerts").resolve(strict=False)
    )
    storage_scan_root = (
        Path(os.path.commonpath([str(output_path), str(alerts_path)]))
        if isolated_runtime_dirs
        else None
    )
    checks: list[dict[str, Any]] = []
    disk_check = validate_disk_space(base_dir, warn_free_gb=warn_free_gb, fail_free_gb=fail_free_gb)
    checks.append(disk_check)
    try:
        disk_free_pct = float(disk_check.get("free_pct"))
    except (TypeError, ValueError):
        disk_free_pct = None
    if disk_free_pct is not None and disk_free_pct <= DEFAULT_LOCAL_STORAGE_PRESSURE_SCAN_PCT:
        checks.append(
            validate_cached_local_storage_pressure_sources(
                cache_path=alerts_path / DEFAULT_LOCAL_STORAGE_PRESSURE_CACHE_PATH.name,
                maintenance_report_path=alerts_path / "output_maintenance.json",
                home_dir=storage_scan_root,
                free_pct=disk_free_pct,
                now=now,
            )
        )
    local_training_path = (
        Path(training_media_path)
        if training_media_path is not None
        else Path(base_dir) / DEFAULT_LOCAL_TRAINING_MEDIA_RELATIVE_PATH
    )
    checks.append(
        validate_local_training_media(
            local_training_path,
            external_disk_path=external_disk_path or DEFAULT_EXTERNAL_DISK_PATH,
            warn_size_gb=training_media_warn_gb,
            fail_size_gb=training_media_fail_gb,
        )
    )
    video_staging_path = Path(base_dir) / "data" / "video_ingest_staging"
    video_ingest_activity = detect_video_ingest_staging_activity(video_staging_path)
    checks.append(
        validate_video_learning_library(
            local_training_path,
            video_ingest_active=bool(video_ingest_activity.get("active")),
        )
    )
    checks.append(
        validate_project_storage_footprint(
            base_dir,
            warn_size_gb=project_storage_warn_gb,
            fail_size_gb=project_storage_fail_gb,
            video_ingest_active=bool(video_ingest_activity.get("active")),
            video_ingest_process_count=int(video_ingest_activity.get("process_count") or 0),
            video_ingest_archive_path=(Path(external_disk_path or DEFAULT_EXTERNAL_DISK_PATH) / "RoxyVideosAnalizados"),
        )
    )
    if external_disk_path:
        external_root = Path(external_disk_path)
        default_cache_source = (
            Path(base_dir) / "home" / ".cache" / "codex-runtimes"
            if custom_base_dir
            else DEFAULT_RUNTIME_CACHE_SOURCE_PATH
        )
        default_cache_destination = (
            external_root / "MacArchive" / Path.home().name / ".cache" / "codex-runtimes"
            if custom_base_dir
            else DEFAULT_RUNTIME_CACHE_DESTINATION_PATH
        )
        checks.append(
            validate_external_disk(
                external_disk_path,
                warn_free_gb=external_warn_free_gb,
                fail_free_gb=external_fail_free_gb,
                operational_report_path=alerts_path / "runtime_backup.json",
                now=now,
            )
        )
        checks.append(
            validate_storage_migration(
                source_path=storage_migration_source_path or DEFAULT_PARALLELS_SOURCE_PATH,
                destination_path=storage_migration_destination_path or DEFAULT_PARALLELS_DESTINATION_PATH,
                log_path=storage_migration_log_path or DEFAULT_PARALLELS_MIGRATION_LOG_PATH,
                external_disk_path=external_disk_path,
                now=now,
            )
        )
        checks.append(
            validate_runtime_cache_migration(
                source_path=runtime_cache_source_path or default_cache_source,
                destination_path=runtime_cache_destination_path or default_cache_destination,
                external_disk_path=external_disk_path,
            )
        )

    heartbeat_path = alerts_path / "ma_live_heartbeat.json"
    heartbeat, heartbeat_load_state = read_json_object_report(heartbeat_path)
    heartbeat_exists = bool(heartbeat_load_state.get("exists"))
    heartbeat_malformed = bool(heartbeat_load_state.get("malformed"))
    if heartbeat_malformed:
        hb_status = ""
        heartbeat_status = check(
            "heartbeat",
            "FAIL",
            f"Heartbeat malformed: {heartbeat_load_state.get('detail')}",
            path=str(heartbeat_path),
            exists=heartbeat_exists,
            malformed=True,
            payload_type=heartbeat_load_state.get("payload_type"),
            load_detail=heartbeat_load_state.get("detail"),
            heartbeat_status="",
        )
    else:
        heartbeat_status, hb_status = heartbeat_check(
            heartbeat_path,
            heartbeat,
            now=now,
            running_warn_minutes=running_warn_minutes,
            running_fail_minutes=running_fail_minutes,
        )
        heartbeat_status.setdefault("exists", heartbeat_exists)
        heartbeat_status.setdefault("malformed", False)
        heartbeat_status.setdefault("payload_type", heartbeat_load_state.get("payload_type"))
        heartbeat_status.setdefault("load_detail", heartbeat_load_state.get("detail"))
        heartbeat_status["heartbeat_status"] = hb_status
    checks.append(heartbeat_status)
    live_scan_timing_path = alerts_path / "ma_live_scan_timing.json"
    checks.append(
        validate_live_scan_efficiency_report(
            live_scan_timing_path,
            max_age_minutes=max_age_minutes,
            now=now,
        )
    )
    checks.append(validate_live_backend_process_guard())
    freshness_max_age_minutes = max_age_minutes
    if hb_status == "RUNNING" and heartbeat_status.get("status") == "OK":
        freshness_max_age_minutes += float(heartbeat_status.get("running_minutes") or 0.0)

    use_heartbeat_paths_only = bool(heartbeat) and hb_status in {"SUCCESS", "NO_SCAN"}
    scan_path = heartbeat_artifact_path(heartbeat, "scan_path")
    confluence_path = heartbeat_artifact_path(heartbeat, "confluence_path")
    options_path = heartbeat_artifact_path(heartbeat, "options_path")
    if not use_heartbeat_paths_only:
        scan_path = scan_path or latest_output_file("ma_live_strategy_*.csv", output_path=output_path)
        confluence_path = confluence_path or latest_output_file("ma_confluence_*.csv", output_path=output_path)
        options_path = options_path or latest_output_file("options_candidates_*.csv", output_path=output_path)
    checks.append(freshness_check("live_scan_freshness", scan_path, max_age_minutes=freshness_max_age_minutes, now=now))
    checks.append(
        freshness_check("confluence_freshness", confluence_path, max_age_minutes=freshness_max_age_minutes, now=now)
    )

    scan_df = read_csv(scan_path)
    if scan_df.empty:
        checks.append(check("live_scan_rows", "FAIL", "Live scan is empty or unreadable"))
    else:
        checks.append(check("live_scan_rows", "OK", f"{len(scan_df)} live scan rows", rows=len(scan_df)))
        if "tf" not in scan_df.columns:
            checks.append(check("timeframe_coverage", "FAIL", "Live scan has no tf column"))
        else:
            present = {normalize_tf(value) for value in scan_df["tf"].dropna().unique().tolist()}
            missing = sorted(required_timeframes - present)
            status = "OK" if not missing else "FAIL"
            detail = (
                "All required live timeframes present" if not missing else f"Missing timeframes: {', '.join(missing)}"
            )
            checks.append(check("timeframe_coverage", status, detail, present=sorted(present), missing=missing))

    confluence_df = read_csv(confluence_path)
    if confluence_df.empty:
        checks.append(check("confluence_rows", "FAIL", "Confluence file is empty or unreadable"))
    else:
        missing_cols = sorted(REQUIRED_CONFLUENCE_COLUMNS - set(confluence_df.columns))
        checks.append(check("confluence_rows", "OK", f"{len(confluence_df)} confluence rows", rows=len(confluence_df)))
        checks.append(
            check(
                "higher_timeframe_confluence",
                "OK" if not missing_cols else "FAIL",
                (
                    "2h/4h confluence columns present"
                    if not missing_cols
                    else f"Missing columns: {', '.join(missing_cols)}"
                ),
                missing_columns=missing_cols,
            )
        )

    brief_path = alerts_path / "roxy_ai_brief.json"
    alert_quality_payload = read_json(alerts_path / "alert_quality.json")
    status_snapshot_payload = read_json(alerts_path / "roxy_status.json")
    checks.append(validate_ai_brief_report(brief_path, source_paths=[scan_path, confluence_path], now=now))
    checks.append(validate_daily_opportunity_plan_report(alerts_path / "roxy_daily_opportunity_plan.json", now=now))
    checks.append(
        validate_status_snapshot_report(
            alerts_path / "roxy_status.json",
            now=now,
            alert_quality_report=alert_quality_payload if isinstance(alert_quality_payload, dict) else None,
        )
    )
    checks.append(validate_alert_quality_report(alerts_path / "alert_quality.json", now=now))

    checks.append(
        validate_options_candidates(
            options_path,
            alerts_path / "options_summary.json",
            route_context=option_route_context_from_reports(
                status_snapshot_payload if isinstance(status_snapshot_payload, dict) else None,
                alert_quality_payload if isinstance(alert_quality_payload, dict) else None,
            ),
            now=now,
        )
    )

    if skip_chart_fetch:
        checks.append(check("chart_indicators", "WARN", "Chart fetch skipped"))
        checks.append(check("chart_provider_effective", "WARN", "Chart provider/source check skipped"))
    else:
        operational_focus_symbol = ""
        operational_focus_market = ""
        if isinstance(status_snapshot_payload, dict):
            operational_focus_symbol = str(status_snapshot_payload.get("operational_focus_symbol") or "")
            operational_focus_market = str(status_snapshot_payload.get("operational_focus_market") or "")
        symbol, market = choose_chart_symbol(
            scan_df,
            chart_symbol,
            operational_focus_symbol=operational_focus_symbol,
            operational_focus_market=operational_focus_market,
        )
        checks.append(validate_chart(symbol, market, chart_timeframe))
    try:
        from chart_health import active_chart_symbols_from_alerts

        required_chart_symbols = active_chart_symbols_from_alerts(alerts_path)
    except Exception:
        required_chart_symbols = []
    if not skip_chart_fetch:
        provider_targets = [(symbol, market)]
        provider_targets.extend(
            (active_symbol, "crypto" if "/" in active_symbol else "stock") for active_symbol in required_chart_symbols
        )
        provider_targets = provider_effective_targets_with_market_baseline(provider_targets)
        provider_env, _provider_env_loaded_keys = effective_provider_env()
        checks.append(validate_chart_providers_effective(provider_targets, timeframe=chart_timeframe, env=provider_env))
    else:
        provider_env, _provider_env_loaded_keys = effective_provider_env()
    checks.append(validate_provider_env_parity())
    checks.append(validate_alpaca_account_probe(env=provider_env))
    checks.append(
        validate_chart_health_report(
            alerts_path / "chart_realtime_health.json",
            required_symbols=required_chart_symbols,
            now=now,
        )
    )

    checks.append(validate_salto_integration())
    checks.append(validate_smart_alert_contract(base_dir / "smart_alerts.py"))
    checks.append(validate_dashboard_realtime_contract(base_dir / "streamlit_app.py"))
    checks.append(validate_dashboard_history_hygiene(base_dir / "db" / "scan_history.csv", now=now))
    checks.append(validate_dashboard_render_probe_report(alerts_path / "dashboard_render_probe.json", now=now))
    checks.append(validate_dual_chart_crosshair_probe_report(alerts_path / "dual_chart_crosshair_probe.json", now=now))
    checks.append(
        validate_dashboard_render_probe_report(
            alerts_path / "dashboard_render_probe_search.json",
            now=now,
            check_name="dashboard_search_render_probe",
            label="Dashboard search render probe",
        )
    )

    if app_url:
        checks.append(validate_app_url(app_url))

    maintenance_report_path = alerts_path / "output_maintenance.json"
    checks.append(
        validate_output_maintenance_report(maintenance_report_path, max_age_hours=maintenance_max_age_hours, now=now)
    )
    runtime_backup_report_path = alerts_path / "runtime_backup.json"
    checks.append(validate_runtime_backup_report(runtime_backup_report_path, now=now))
    launchd_recovery_report_path = alerts_path / "launchd_recovery.json"
    checks.append(validate_launchd_recovery_report(launchd_recovery_report_path, now=now))
    price_alert_monitor_report_path = alerts_path / "price_alert_monitor.json"
    checks.append(validate_price_alert_monitor_report(price_alert_monitor_report_path, now=now))
    opportunity_sync_report_path = alerts_path / "opportunity_sync.json"
    checks.append(validate_opportunity_sync_report(opportunity_sync_report_path, now=now))
    opportunity_lifecycle_report_path = alerts_path / "opportunity_lifecycle.json"
    checks.append(
        validate_opportunity_lifecycle_report(
            opportunity_lifecycle_report_path,
            brief_path,
            now=now,
        )
    )
    checks.append(validate_notification_delivery(alerts_path))
    checks.append(
        validate_health_history_integrity(
            health_history_path or alerts_path / "roxy_realtime_history.jsonl",
            max_entries=health_history_max_entries,
            max_bytes=health_history_max_bytes,
            max_age_minutes=health_history_max_age_minutes,
            now=now,
        )
    )
    checks.append(
        validate_realtime_lock_status(
            lock_status_path or alerts_path / "roxy_realtime_lock.json",
            max_acquired_minutes=lock_status_max_acquired_minutes,
            now=now,
        )
    )
    checks.append(validate_operational_logs(base_dir=base_dir, now=now))

    if skip_service_check:
        checks.append(check("live_service_24h", "WARN", "LaunchAgent check skipped"))
        checks.append(check("streamlit_service_24h", "WARN", "LaunchAgent check skipped"))
        checks.append(check("daily_service", "WARN", "LaunchAgent check skipped"))
        checks.append(check("health_watchdog_service", "WARN", "LaunchAgent check skipped"))
        checks.append(check("price_alert_monitor_service", "WARN", "LaunchAgent check skipped"))
        checks.append(check("output_maintenance_service", "WARN", "LaunchAgent check skipped"))
        checks.append(check("runtime_backup_service", "WARN", "LaunchAgent check skipped"))
    else:
        checks.append(validate_launchagent_plist_integrity())
        checks.append(validate_live_service(required_timeframes))
        checks.append(validate_streamlit_service())
        checks.append(validate_daily_service())
        checks.append(validate_health_watchdog_service())
        checks.append(validate_price_alert_monitor_service())
        checks.append(validate_output_maintenance_service())
        checks.append(validate_runtime_backup_service())

    status = overall_status(checks)
    report = {
        "generated_at": (now or utc_now()).isoformat(),
        "status": status,
        "ok": status == "OK",
        "checks": checks,
        "paths": {
            "scan": str(scan_path) if scan_path else None,
            "confluence": str(confluence_path) if confluence_path else None,
            "options": str(options_path) if options_path else None,
            "heartbeat": str(heartbeat_path),
            "live_scan_timing": str(live_scan_timing_path),
            "brief": str(brief_path),
            "alert_quality": str(alerts_path / "alert_quality.json"),
            "output_maintenance": str(maintenance_report_path),
            "runtime_backup": str(runtime_backup_report_path),
            "launchd_recovery": str(launchd_recovery_report_path),
            "price_alert_monitor": str(price_alert_monitor_report_path),
            "opportunity_sync": str(opportunity_sync_report_path),
            "opportunity_lifecycle": str(opportunity_lifecycle_report_path),
        },
    }
    report["provider_recovery"] = provider_recovery_summary(checks)
    report["market_realtime"] = market_realtime_summary(checks, report["provider_recovery"])
    report["operational_summary"] = build_operational_summary(
        report,
        alert_quality_report=read_json(alerts_path / "alert_quality.json"),
    )
    report["checks"].append(validate_operational_summary_contract(report))
    report["checks"].append(validate_provider_recovery_contract(report))
    report["checks"].append(
        validate_health_stability_slo(
            health_history_path or alerts_path / "roxy_realtime_history.jsonl",
            sample_limit=min(100, int(health_history_max_entries)),
            current_entry=health_history_entry(report),
        )
    )
    refresh_report_metrics_contract(report)
    return report


def build_operational_summary(
    report: dict[str, Any],
    *,
    alert_quality_report: dict[str, Any] | None = None,
) -> dict[str, Any]:
    status = str(report.get("status") or "UNKNOWN").upper()
    issue = top_health_issue(report)
    quality = alert_quality_report or {}
    summary = quality.get("summary") if isinstance(quality.get("summary"), dict) else {}
    entry = quality.get("entry") if isinstance(quality.get("entry"), dict) else {}
    market_state = str(summary.get("state") or entry.get("state") or "UNKNOWN").upper()
    ready = int(summary.get("latest_notifications_ready") or entry.get("notifications_ready") or 0)
    total = int(summary.get("latest_total_opportunities") or entry.get("total_opportunities") or 0)
    diagnostic_label = str(summary.get("diagnostic_label") or "")
    diagnostic_detail = str(
        summary.get("diagnostic_detail") or summary.get("latest_top_blocker") or entry.get("top_blocker") or ""
    )
    diagnostic_severity = str(summary.get("diagnostic_severity") or "OK").upper()
    blocker_category = str(summary.get("blocker_category") or "")
    recommended_action = str(summary.get("recommended_action") or "")
    blocker_streak = int(summary.get("latest_top_blocker_streak") or 0)
    provider_recovery = report.get("provider_recovery") if isinstance(report.get("provider_recovery"), dict) else {}
    market_realtime = report.get("market_realtime") if isinstance(report.get("market_realtime"), dict) else {}
    active_route = str(market_realtime.get("active_route") or "")
    active_route_label = str(market_realtime.get("active_route_label") or "")
    active_route_detail = str(market_realtime.get("active_route_detail") or "")
    allowed_markets = (
        market_realtime.get("allowed_markets") if isinstance(market_realtime.get("allowed_markets"), list) else []
    )
    blocked_markets = (
        market_realtime.get("blocked_markets") if isinstance(market_realtime.get("blocked_markets"), list) else []
    )
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []

    def current_check_status(name: str) -> str:
        for item in checks:
            if str(item.get("name") or "") == name:
                return str(item.get("status") or "").upper()
        return ""

    def diagnostic_is_resolved_health_failure(detail: str) -> bool:
        match = re.search(r"Health fallo:\s*([a-zA-Z0-9_]+):", detail)
        if not match:
            return False
        return current_check_status(match.group(1)) == "OK"

    if diagnostic_detail and diagnostic_is_resolved_health_failure(diagnostic_detail):
        diagnostic_detail = ""
        if blocker_category == "SYSTEM_BLOCKED":
            blocker_category = (
                "MARKET_PARTIAL_BLOCK" if bool(provider_recovery.get("premium_blocked")) else blocker_category
            )

    status_snapshot = next((item for item in checks if str(item.get("name") or "") == "status_snapshot"), {})
    if isinstance(status_snapshot, dict):
        snapshot_allowed = (
            status_snapshot.get("allowed_markets") if isinstance(status_snapshot.get("allowed_markets"), list) else []
        )
        snapshot_blocked = (
            status_snapshot.get("blocked_markets") if isinstance(status_snapshot.get("blocked_markets"), list) else []
        )
        if str(status_snapshot.get("active_route_label") or "").strip():
            active_route = str(status_snapshot.get("active_route") or active_route)
            active_route_label = str(status_snapshot.get("active_route_label") or active_route_label)
            active_route_detail = str(status_snapshot.get("active_route_detail") or active_route_detail)
        if snapshot_allowed or snapshot_blocked:
            allowed_markets = snapshot_allowed
            blocked_markets = snapshot_blocked
    safe_mode = str(status_snapshot.get("safe_mode") or provider_recovery.get("safe_mode") or "")
    confirmation_gate = str(
        status_snapshot.get("confirmation_gate") or provider_recovery.get("confirmation_gate") or ""
    )
    premium_blocked_context = (
        bool(provider_recovery.get("premium_blocked"))
        or safe_mode == "NO_STOCK_OR_OPTIONS_ALERTS"
        or "stock" in {str(item).lower() for item in blocked_markets}
        or blocker_category == "MARKET_PARTIAL_BLOCK"
    )
    allowed_market_set = {str(item).lower() for item in allowed_markets}
    blocked_market_set = {str(item).lower() for item in blocked_markets}
    stock_route_allowed = "stock" in allowed_market_set and "stock" not in blocked_market_set
    crypto_route_allowed = ("crypto" in allowed_market_set and "crypto" not in blocked_market_set) or (
        not allowed_market_set and "crypto" not in blocked_market_set
    )
    options_route_allowed = "options" in allowed_market_set and "options" not in blocked_market_set
    if safe_mode == "NO_STOCK_OR_OPTIONS_ALERTS":
        stock_route_allowed = False
        options_route_allowed = False
    if status == "FAIL":
        return {
            "mode": "SYSTEM_FAIL",
            "label": "Sistema falla",
            "tone": "avoid",
            "detail": f"{issue.get('name')}: {issue.get('detail')}" if issue else "Health FAIL",
            "system_status": status,
            "market_state": market_state,
            "notifications_ready": ready,
            "total_opportunities": total,
            "diagnostic_severity": diagnostic_severity,
            "diagnostic_label": diagnostic_label,
            "diagnostic_detail": diagnostic_detail,
            "blocker_category": blocker_category,
            "recommended_action": recommended_action,
            "blocker_streak": blocker_streak,
            "stock_alerts_allowed": stock_route_allowed,
            "crypto_alerts_allowed": crypto_route_allowed,
            "options_alerts_allowed": options_route_allowed,
            "safe_mode": safe_mode,
            "confirmation_gate": confirmation_gate,
            "allowed_markets": allowed_markets,
            "blocked_markets": blocked_markets,
            "active_route": active_route,
            "active_route_label": active_route_label,
            "active_route_detail": active_route_detail,
        }
    if status == "WARN":
        if premium_blocked_context:
            provider_blocked = bool(provider_recovery.get("premium_blocked"))
            provider_detail = str(provider_recovery.get("detail") or "").strip() if provider_blocked else ""
            provider_action = str(provider_recovery.get("action") or "").strip()
            block_label = (
                str(provider_recovery.get("label") or "Premium bloqueado") if provider_blocked else "Premium bloqueado"
            )
            detail_parts = [
                provider_detail,
                provider_action,
            ]
            if diagnostic_detail and "Premium bloqueado" not in diagnostic_detail:
                detail_parts.append(diagnostic_detail)
            detail = " | ".join(part for part in detail_parts if part) or (
                f"{issue.get('name')}: {issue.get('detail')}" if issue else "Proveedor premium bloqueado"
            )
            return {
                "mode": "PREMIUM_BLOCKED",
                "label": block_label,
                "tone": "avoid",
                "detail": detail,
                "system_status": status,
                "market_state": market_state,
                "notifications_ready": ready,
                "total_opportunities": total,
                "diagnostic_severity": diagnostic_severity,
                "diagnostic_label": diagnostic_label or "Proveedor premium",
                "diagnostic_detail": diagnostic_detail,
                "blocker_category": blocker_category,
                "recommended_action": str(provider_recovery.get("action") or recommended_action),
                "blocker_streak": blocker_streak,
                "stock_alerts_allowed": stock_route_allowed,
                "crypto_alerts_allowed": crypto_route_allowed,
                "options_alerts_allowed": options_route_allowed,
                "impacted_markets": (
                    provider_recovery.get("impacted_markets")
                    if isinstance(provider_recovery.get("impacted_markets"), list)
                    else blocked_markets
                ),
                "safe_mode": safe_mode,
                "confirmation_gate": confirmation_gate,
                "allowed_markets": allowed_markets,
                "blocked_markets": blocked_markets,
                "active_route": active_route,
                "active_route_label": active_route_label,
                "active_route_detail": active_route_detail,
            }
        return {
            "mode": "SYSTEM_WARN",
            "label": "Sistema revisar",
            "tone": "watch",
            "detail": f"{issue.get('name')}: {issue.get('detail')}" if issue else "Health WARN",
            "system_status": status,
            "market_state": "UNKNOWN",
            "allowed_markets": allowed_markets,
            "blocked_markets": blocked_markets,
            "active_route": active_route,
            "active_route_label": active_route_label,
            "active_route_detail": active_route_detail,
        }

    if ready > 0 or market_state == "READY":
        mode = "READY_TO_REVIEW"
        label = "Alertas listas"
        tone = "buy"
        detail = f"{ready}/{total} listas"
    elif market_state in {"BLOCKED_DATA", "BLOCKED_REALTIME"}:
        mode = "DATA_BLOCKED"
        label = "Datos bloquean"
        tone = "avoid"
        detail = diagnostic_detail or market_state
    elif market_state == "NO_SETUPS":
        mode = "MARKET_NO_SETUPS"
        label = "Sin setups"
        tone = "neutral"
        detail = "Sistema OK; mercado sin setups"
    elif market_state == "WAITING":
        mode = "MARKET_WAITING"
        label = "Mercado espera"
        tone = "watch"
        detail = diagnostic_label or "Sistema OK; esperando entrada"
        if blocker_streak and f"x{blocker_streak}" not in detail:
            detail += f" | bloqueador x{blocker_streak}"
        if diagnostic_detail and diagnostic_detail not in detail:
            detail += f" | {diagnostic_detail}"
        if recommended_action and recommended_action not in detail:
            detail += f" | {recommended_action}"
    else:
        mode = "SYSTEM_OK"
        label = "Sistema OK"
        tone = "buy"
        detail = "Pipeline realtime operativo"

    return {
        "mode": mode,
        "label": label,
        "tone": tone,
        "detail": detail,
        "system_status": status,
        "market_state": market_state,
        "notifications_ready": ready,
        "total_opportunities": total,
        "diagnostic_severity": diagnostic_severity,
        "diagnostic_label": diagnostic_label,
        "diagnostic_detail": diagnostic_detail,
        "blocker_category": blocker_category,
        "recommended_action": recommended_action,
        "blocker_streak": blocker_streak,
        "allowed_markets": allowed_markets,
        "blocked_markets": blocked_markets,
        "active_route": active_route,
        "active_route_label": active_route_label,
        "active_route_detail": active_route_detail,
    }


def validate_operational_summary_contract(report: dict[str, Any]) -> dict[str, Any]:
    operational = report.get("operational_summary") if isinstance(report.get("operational_summary"), dict) else {}
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    status_snapshot = next((item for item in checks if str(item.get("name") or "") == "status_snapshot"), {})
    issues: list[str] = []
    if not operational:
        issues.append("missing operational_summary")
    if not isinstance(status_snapshot, dict) or not status_snapshot:
        return check(
            "operational_summary_contract",
            "INFO" if not issues else "WARN",
            "; ".join(issues) if issues else "No status_snapshot available for operational contract",
            issues=issues,
            snapshot_present=False,
        )

    snapshot_allowed = (
        status_snapshot.get("allowed_markets") if isinstance(status_snapshot.get("allowed_markets"), list) else []
    )
    snapshot_blocked = (
        status_snapshot.get("blocked_markets") if isinstance(status_snapshot.get("blocked_markets"), list) else []
    )
    operational_allowed = (
        operational.get("allowed_markets") if isinstance(operational.get("allowed_markets"), list) else []
    )
    operational_blocked = (
        operational.get("blocked_markets") if isinstance(operational.get("blocked_markets"), list) else []
    )

    def contract_value(value: Any) -> str:
        text = str(value or "").strip()
        return "" if text == "-" else text

    snapshot_route_label = contract_value(status_snapshot.get("active_route_label"))
    operational_route_label = contract_value(operational.get("active_route_label"))
    snapshot_safe_mode = contract_value(status_snapshot.get("safe_mode"))
    operational_safe_mode = contract_value(operational.get("safe_mode"))
    snapshot_gate = contract_value(status_snapshot.get("confirmation_gate"))
    operational_gate = contract_value(operational.get("confirmation_gate"))
    snapshot_allowed_set = {str(item).lower() for item in snapshot_allowed}
    snapshot_blocked_set = {str(item).lower() for item in snapshot_blocked}
    operational_allowed_set = {str(item).lower() for item in operational_allowed}
    operational_blocked_set = {str(item).lower() for item in operational_blocked}

    if snapshot_route_label and operational_route_label != snapshot_route_label:
        issues.append(f"route label mismatch {operational_route_label or '-'} != {snapshot_route_label}")
    if snapshot_allowed_set or snapshot_blocked_set:
        if operational_allowed_set != snapshot_allowed_set:
            issues.append(
                "allowed markets mismatch "
                + ",".join(sorted(operational_allowed_set or {"-"}))
                + " != "
                + ",".join(sorted(snapshot_allowed_set or {"-"}))
            )
        if operational_blocked_set != snapshot_blocked_set:
            issues.append(
                "blocked markets mismatch "
                + ",".join(sorted(operational_blocked_set or {"-"}))
                + " != "
                + ",".join(sorted(snapshot_blocked_set or {"-"}))
            )
    if snapshot_safe_mode and operational_safe_mode != snapshot_safe_mode:
        issues.append(f"safe mode mismatch {operational_safe_mode or '-'} != {snapshot_safe_mode}")
    if snapshot_gate and operational_gate and operational_gate != snapshot_gate:
        issues.append(f"confirmation gate mismatch {operational_gate} != {snapshot_gate}")
    if "stock" in snapshot_blocked_set and operational_route_label == "Operar mercados realtime":
        issues.append("stock blocked in snapshot but operational route allows all markets")
    if snapshot_safe_mode == "NO_STOCK_OR_OPTIONS_ALERTS" and str(operational.get("label") or "") == "Premium activo":
        issues.append("premium label active while stock/options are blocked")

    status = "FAIL" if issues else "OK"
    detail = (
        "; ".join(issues) if issues else f"Operational route synced with snapshot: {operational_route_label or '-'}"
    )
    return check(
        "operational_summary_contract",
        status,
        detail,
        issues=issues,
        snapshot_present=True,
        snapshot_active_route_label=snapshot_route_label,
        operational_active_route_label=operational_route_label,
        snapshot_allowed_markets=snapshot_allowed,
        operational_allowed_markets=operational_allowed,
        snapshot_blocked_markets=snapshot_blocked,
        operational_blocked_markets=operational_blocked,
        snapshot_safe_mode=snapshot_safe_mode,
        operational_safe_mode=operational_safe_mode,
        snapshot_confirmation_gate=snapshot_gate,
        operational_confirmation_gate=operational_gate,
    )


def validate_provider_recovery_contract(report: dict[str, Any]) -> dict[str, Any]:
    checks = report.get("checks") if isinstance(report.get("checks"), list) else []
    provider = report.get("provider_recovery") if isinstance(report.get("provider_recovery"), dict) else {}
    market = report.get("market_realtime") if isinstance(report.get("market_realtime"), dict) else {}
    operational = report.get("operational_summary") if isinstance(report.get("operational_summary"), dict) else {}
    alpaca_probe = next((item for item in checks if str(item.get("name") or "") == "alpaca_account_probe"), {})
    issues: list[str] = []

    def market_set(container: dict[str, Any], key: str) -> set[str]:
        values = container.get(key) if isinstance(container.get(key), list) else []
        return {str(item).strip().lower() for item in values if str(item).strip()}

    provider_blocked = bool(provider.get("premium_blocked"))
    provider_label = str(provider.get("label") or "")
    provider_safe_mode = str(provider.get("safe_mode") or "")
    provider_gate = str(provider.get("confirmation_gate") or "")
    provider_stock_allowed = provider.get("stock_alerts_allowed")
    market_allowed = market_set(market, "allowed_markets")
    market_blocked = market_set(market, "blocked_markets")
    operational_allowed = market_set(operational, "allowed_markets")
    operational_blocked = market_set(operational, "blocked_markets")
    market_route_label = str(market.get("active_route_label") or "")
    operational_route_label = str(operational.get("active_route_label") or "")
    operational_safe_mode = str(operational.get("safe_mode") or "")
    operational_gate = str(operational.get("confirmation_gate") or "")
    operational_safe_modes_blocking_premium = {"NO_STOCK_OR_OPTIONS_ALERTS", "NO_ALERTS_UNTIL_DATA_OK"}

    alpaca_auth_failed = (
        isinstance(alpaca_probe, dict)
        and alpaca_probe.get("auth_ok") is False
        and str(alpaca_probe.get("status") or "").upper() in {"WARN", "FAIL"}
        and (
            str(alpaca_probe.get("diagnosis") or "") == "alpaca_account_auth_failed"
            or str(alpaca_probe.get("error_category") or "") in {"AUTH_INVALID", "AUTH_FORBIDDEN", "ENDPOINT_OR_MODE"}
        )
    )

    if alpaca_auth_failed:
        if not provider_blocked:
            issues.append("alpaca auth failed but provider_recovery.premium_blocked is false")
        if provider_label == "Premium activo":
            issues.append("alpaca auth failed but provider label is Premium activo")
        if provider_stock_allowed is not False:
            issues.append("alpaca auth failed but provider allows stock alerts")
        if provider_safe_mode != "NO_STOCK_OR_OPTIONS_ALERTS":
            issues.append(f"alpaca auth failed but provider safe_mode is {provider_safe_mode or '-'}")
        if provider_gate != "NO_TRADE_FROM_FALLBACK":
            issues.append(f"alpaca auth failed but provider confirmation_gate is {provider_gate or '-'}")
        if not {"stock", "options"}.issubset(market_blocked):
            issues.append("alpaca auth failed but market route does not block stock/options")
        if "stock" in market_allowed or "options" in market_allowed:
            issues.append("alpaca auth failed but market route allows stock/options")
        if market_route_label == "Operar mercados realtime":
            issues.append("alpaca auth failed but market route is all realtime")
        if not {"stock", "options"}.issubset(operational_blocked):
            issues.append("alpaca auth failed but operational route does not block stock/options")
        if "stock" in operational_allowed or "options" in operational_allowed:
            issues.append("alpaca auth failed but operational route allows stock/options")
        if operational_safe_mode not in operational_safe_modes_blocking_premium:
            issues.append(f"alpaca auth failed but operational safe_mode is {operational_safe_mode or '-'}")
        if operational_gate != "NO_TRADE_FROM_FALLBACK":
            issues.append(f"alpaca auth failed but operational confirmation_gate is {operational_gate or '-'}")

    stock_or_options_blocked = bool({"stock", "options"} & (market_blocked | operational_blocked))
    stock_or_options_allowed_while_blocked = bool({"stock", "options"} & (market_allowed | operational_allowed))
    if stock_or_options_blocked and not provider_blocked:
        issues.append("stock/options blocked in route but provider_recovery.premium_blocked is false")
    if stock_or_options_blocked and provider_label == "Premium activo":
        issues.append("stock/options blocked in route but provider label is Premium activo")
    if provider_blocked:
        if not {"stock", "options"}.issubset(market_blocked | operational_blocked):
            issues.append("provider premium blocked but stock/options are not blocked in route")
        if market_route_label == "Operar mercados realtime" or operational_route_label == "Operar mercados realtime":
            issues.append("provider premium blocked but route label allows all markets")
    if stock_or_options_blocked and stock_or_options_allowed_while_blocked:
        issues.append("route both allows and blocks stock/options")

    status = "FAIL" if issues else "OK"
    detail = (
        "; ".join(issues)
        if issues
        else f"Provider recovery synced: {provider_label or '-'}; route {operational_route_label or market_route_label or '-'}"
    )
    return check(
        "provider_recovery_contract",
        status,
        detail,
        issues=issues,
        alpaca_auth_failed=alpaca_auth_failed,
        provider_label=provider_label,
        provider_premium_blocked=provider_blocked,
        provider_stock_alerts_allowed=provider_stock_allowed,
        provider_safe_mode=provider_safe_mode,
        provider_confirmation_gate=provider_gate,
        market_allowed_markets=sorted(market_allowed),
        market_blocked_markets=sorted(market_blocked),
        operational_allowed_markets=sorted(operational_allowed),
        operational_blocked_markets=sorted(operational_blocked),
        market_active_route_label=market_route_label,
        operational_active_route_label=operational_route_label,
        operational_safe_mode=operational_safe_mode,
        operational_confirmation_gate=operational_gate,
    )


def render_text_report(report: dict[str, Any]) -> str:
    lines = [
        f"Roxy realtime check: {report.get('status', '-')}",
        f"Generated: {report.get('generated_at', '-')}",
    ]
    operational = report.get("operational_summary") if isinstance(report.get("operational_summary"), dict) else {}
    if operational:
        route_detail = ""
        if operational.get("active_route_label"):
            route_detail = (
                f" | route {operational.get('active_route_label')}: " f"{operational.get('active_route_detail') or '-'}"
            )
        lines.append(
            "Operational: "
            f"{operational.get('label', '-')} | {operational.get('mode', '-')} | {operational.get('detail', '-')}"
            f"{route_detail}"
        )
    stability = report.get("stability_summary") if isinstance(report.get("stability_summary"), dict) else {}
    if stability:
        ok_rate = stability.get("ok_rate")
        ok_pct = f"{float(ok_rate) * 100:.1f}%" if ok_rate is not None else "-"
        core_ok_rate = stability.get("core_ok_rate")
        core_ok_pct = f"{float(core_ok_rate) * 100:.1f}%" if core_ok_rate is not None else ""
        recovery_detail = ""
        incident_free = stability.get("incident_free_minutes")
        if incident_free is not None:
            recovery_detail = f" | recovered {float(incident_free):.1f}m"
        dominant_issue = stability.get("dominant_issue") if isinstance(stability.get("dominant_issue"), dict) else {}
        issue_detail = ""
        if dominant_issue.get("name"):
            current_streak_status = str(stability.get("current_streak_status") or "").upper()
            issue_label = "hist issue" if current_streak_status == "OK" else "top issue"
            issue_detail = f" | {issue_label} {dominant_issue.get('name')} x{dominant_issue.get('count', 0)}"
        metric_deltas = stability.get("metric_deltas") if isinstance(stability.get("metric_deltas"), dict) else {}
        metric_detail = ""
        metric_parts: list[str] = []
        if metric_deltas.get("disk_free_gb") is not None:
            metric_parts.append(f"disk {float(metric_deltas['disk_free_gb']):+.2f} GiB")
        if metric_deltas.get("external_disk_free_gb") is not None:
            metric_parts.append(f"external {float(metric_deltas['external_disk_free_gb']):+.2f} GiB")
        if metric_deltas.get("training_media_gb") is not None:
            metric_parts.append(f"media {float(metric_deltas['training_media_gb']):+.2f} GiB")
        if metric_deltas.get("project_storage_gb") is not None:
            metric_parts.append(f"project {float(metric_deltas['project_storage_gb']):+.2f} GiB")
        if metric_parts:
            metric_detail = " | trend " + ", ".join(metric_parts)
        disk_free_drop_pressure = str(stability.get("disk_free_drop_pressure") or "CLEAR").upper()
        disk_free_drop_detail = ""
        if disk_free_drop_pressure in {"WATCH", "ATTENTION"}:
            try:
                disk_free_drop_gb = float(stability.get("disk_free_drop_gb") or 0.0)
            except (TypeError, ValueError):
                disk_free_drop_gb = 0.0
            disk_free_drop_source = str(stability.get("disk_free_drop_source") or "").lower()
            disk_free_drop_detail = (
                f" | disk pressure {disk_free_drop_pressure.lower()} drop {disk_free_drop_gb:.1f}GiB"
            )
            if disk_free_drop_source and disk_free_drop_source != "clear":
                disk_free_drop_detail += f" source {disk_free_drop_source}"
            try:
                latest_disk_free_gb = float(stability.get("latest_disk_free_gb"))
            except (TypeError, ValueError):
                latest_disk_free_gb = None
            try:
                latest_disk_free_pct = float(stability.get("latest_disk_free_pct"))
            except (TypeError, ValueError):
                latest_disk_free_pct = None
            if latest_disk_free_gb is not None:
                disk_free_drop_detail += f" free {latest_disk_free_gb:.1f}GiB"
                if latest_disk_free_pct is not None:
                    disk_free_drop_detail += f"/{latest_disk_free_pct:.1f}%"
            disk_free_drop_action = str(stability.get("disk_free_drop_recommended_action") or "")
            if disk_free_drop_action:
                disk_free_drop_detail += f" | action {disk_free_drop_action}"
        transient_locks = int(stability.get("transient_lock_contention_count") or 0)
        recent_transient_locks = int(stability.get("recent_transient_lock_contention_count") or 0)
        recent_lock_window = int(stability.get("recent_lock_window") or 0)
        try:
            recent_lock_rate = float(stability.get("recent_transient_lock_contention_rate") or 0.0)
        except (TypeError, ValueError):
            recent_lock_rate = 0.0
        lock_pressure = str(stability.get("lock_contention_pressure") or "").upper()
        lock_severity = str(stability.get("lock_contention_severity") or "").upper()
        lock_profile = str(stability.get("lock_contention_profile") or "").upper()
        try:
            recent_lock_max_age = float(stability.get("recent_transient_lock_contention_max_age_minutes"))
        except (TypeError, ValueError):
            recent_lock_max_age = None
        transient_lock_detail = ""
        if recent_transient_locks:
            recent_detail = f"recent {recent_transient_locks}"
            if recent_lock_window:
                recent_detail += f"/{recent_lock_window} {recent_lock_rate * 100:.0f}%"
            if lock_pressure and lock_pressure != "CLEAR":
                recent_detail += f" {lock_pressure.lower()}"
            if lock_severity and lock_severity not in {"CLEAR", lock_pressure}:
                recent_detail += f" {lock_severity.lower()}"
            if lock_profile and lock_profile != "CLEAR":
                recent_detail += f" profile {lock_profile.lower()}"
            if recent_lock_max_age is not None:
                recent_detail += f" max {recent_lock_max_age:.1f}m"
            if transient_locks > recent_transient_locks:
                transient_lock_detail = f" | lock overlaps {recent_detail}/hist {transient_locks}"
            else:
                transient_lock_detail = f" | lock overlaps {recent_detail}"
        elif transient_locks:
            transient_lock_detail = f" | lock overlaps resolved hist {transient_locks}"
        known_issue_detail = ""
        known_issue_label = str(stability.get("known_issue_label") or "")
        known_issue_action = str(stability.get("known_issue_action") or "")
        premium_streak = int(stability.get("current_premium_blocked_streak") or 0)
        if known_issue_label:
            known_issue_detail = f" | known {known_issue_label}"
            if premium_streak:
                known_issue_detail += f" x{premium_streak}"
            if known_issue_action:
                known_issue_detail += f" | action {known_issue_action}"
        sync_issue_detail = ""
        sync_issues = int(stability.get("status_alert_quality_sync_issue_count") or 0)
        recent_sync_issues = int(stability.get("recent_status_alert_quality_sync_issue_count") or 0)
        latest_sync_issue_count = int(stability.get("latest_status_alert_quality_issue_count") or 0)
        if "unresolved_status_alert_quality_sync_issue_count" in stability:
            unresolved_sync_issues = int(stability.get("unresolved_status_alert_quality_sync_issue_count") or 0)
        else:
            unresolved_sync_issues = recent_sync_issues if latest_sync_issue_count else 0
        latest_sync_checked = stability.get("latest_status_alert_quality_sync_checked")
        if unresolved_sync_issues:
            if sync_issues > unresolved_sync_issues:
                sync_issue_detail = f" | status/quality sync issues active {unresolved_sync_issues}/hist {sync_issues}"
            else:
                sync_issue_detail = f" | status/quality sync issues active {unresolved_sync_issues}"
        elif recent_sync_issues:
            if sync_issues > recent_sync_issues:
                sync_issue_detail = f" | status/quality sync resolved recent {recent_sync_issues}/hist {sync_issues}"
            else:
                sync_issue_detail = f" | status/quality sync resolved recent {recent_sync_issues}"
        elif sync_issues and latest_sync_issue_count:
            sync_issue_detail = f" | status/quality sync issues hist {sync_issues}"
        elif sync_issues:
            sync_issue_detail = f" | status/quality sync resolved hist {sync_issues}"
        elif latest_sync_checked is False:
            sync_issue_detail = " | status/quality sync unchecked"
        rotation_handoff_detail = ""
        handoff_issues = int(stability.get("status_snapshot_rotation_handoff_issue_count") or 0)
        recent_handoff_issues = int(stability.get("recent_status_snapshot_rotation_handoff_issue_count") or 0)
        latest_handoff_status = str(stability.get("latest_status_snapshot_rotation_handoff_status") or "").upper()
        latest_handoff_symbol = str(stability.get("latest_status_snapshot_rotation_handoff_focus_symbol") or "")
