            skipped_count = optional_float(local_cache_cleanup_skipped_count)
            skipped_positive = (skipped_mb is not None and skipped_mb > 0) or (
                skipped_count is not None and skipped_count > 0
            )
            skip_ratio = 0.0
            skip_state = "CLEAR"
            if eligible_mb is not None and eligible_mb > 0:
                effective_skipped_mb = max(skipped_mb or 0.0, 0.0)
                skip_ratio = round(effective_skipped_mb / eligible_mb, 4)
                if skipped_positive and effective_skipped_mb + 0.0005 >= eligible_mb:
                    skip_state = "ALL_ELIGIBLE_SKIPPED"
                elif skipped_positive:
                    skip_state = "PARTIAL_SKIPPED"
            elif skipped_positive:
                skip_state = "SKIPPED_UNKNOWN_ELIGIBLE"
            metrics["output_maintenance_local_cache_cleanup_skipped_ratio"] = skip_ratio
            metrics["output_maintenance_local_cache_cleanup_skip_state"] = skip_state
