    def dashboard_actionable_warning_count(metrics: dict[str, Any], prefix: str) -> int:
        explicit_key = f"{prefix}_actionable_soft_console_warning_count"
        if explicit_key in metrics:
            return row_metric_int(metrics, explicit_key)
        raw_family_counts = normalized_count_dict(metrics.get(f"{prefix}_soft_console_warning_family_counts"))
        if raw_family_counts:
            return dashboard_soft_warning_count_from_family_counts(raw_family_counts)
        return row_metric_int(metrics, f"{prefix}_soft_console_warning_count")

