    def dashboard_benign_warning_family_counts(metrics: dict[str, Any], prefix: str) -> dict[str, int]:
        raw_counts = normalized_count_dict(metrics.get(f"{prefix}_soft_console_warning_family_counts"))
        explicit_actionable = actionable_dashboard_soft_warning_family_counts(
            metrics.get(f"{prefix}_actionable_soft_console_warning_family_counts")
        )
        actionable_counts = explicit_actionable or actionable_dashboard_soft_warning_family_counts(raw_counts)
        return {
            family: max(0, count - actionable_counts.get(family, 0))
            for family, count in raw_counts.items()
            if max(0, count - actionable_counts.get(family, 0)) > 0
        }

